// Fertility-related RAG entries for CycleMind Luna AI companion
// These entries provide evidence-based information on fertility, infertility evaluation, causes, and treatments

export const fertilityRagEntries = [
  // === Evaluation of Female Infertility RAG Entries (IDs 3306–3315) ===
  { id: 3306, category: 'fertility', keywords: ['when to start infertility evaluation age thresholds'], question: "When should an infertility evaluation be initiated?", response: "Standard timing is after 12 months of regular unprotected intercourse for women under 35 years and after 6 months for women 35 years and older. Earlier or immediate evaluation is appropriate for women ≥40 years, those with irregular cycles, known risk factors (endometriosis, prior PID, pelvic surgery, reproductive tract anomalies), or known/suspected male factor infertility. Both partners should be evaluated concurrently." },
  { id: 3307, category: 'fertility', keywords: ['initial infertility evaluation components history physical'], question: "What are the key components of the initial infertility evaluation?", response: "A focused history (duration of infertility, menstrual pattern, medical/surgical/gynecologic history, sexual history, family history, lifestyle factors) and physical examination (BMI, signs of endocrinopathy, pelvic findings) should be performed on the female partner. Semen analysis, documentation of ovulation, assessment of tubal patency/uterine cavity, and ovarian reserve testing form the core diagnostic workup. Multiple factors may coexist." },
  { id: 3308, category: 'fertility', keywords: ['ovarian reserve testing AMH day 3 FSH estradiol'], question: "How is ovarian reserve assessed in the infertility evaluation?", response: "Common tests include anti-müllerian hormone (AMH, can be drawn any cycle day), day 3 FSH + estradiol, antral follicle count, and the clomiphene citrate challenge test. AMH and antral follicle count are particularly useful for predicting ovarian response to stimulation. No single test perfectly predicts live birth. Markedly abnormal results (e.g., very low AMH or high day 3 FSH) suggest diminished reserve and warrant referral to a reproductive endocrinologist." },
  { id: 3309, category: 'fertility', keywords: ['tubal patency testing HSG HyCoSy laparoscopy'], question: "How is tubal patency evaluated?", response: "Hysterosalpingogram (HSG) or hysterosalpingo-contrast sonography (HyCoSy) are first-line tests to assess tubal patency and the uterine cavity. HyCoSy is often better tolerated. Laparoscopy with chromotubation (plus hysteroscopy) is preferred when endometriosis, pelvic adhesions, or other pelvic pathology is suspected based on history or exam, as it allows diagnosis and potential treatment in one procedure." },
  { id: 3310, category: 'fertility', keywords: ['ovulation assessment progesterone LH kit'], question: "How is ovulatory function assessed?", response: "Women with regular ~28-day cycles and molimina symptoms are usually ovulatory. In others, a mid-luteal progesterone level (>3 ng/mL) or urinary LH ovulation predictor kits can document ovulation. If anovulation is confirmed, further evaluation for causes (e.g., PCOS, thyroid dysfunction, hyperprolactinemia) is indicated." },
  { id: 3311, category: 'fertility', keywords: ['limited utility tests postcoital endometrial biopsy'], question: "Which tests have limited utility in the basic infertility evaluation?", response: "The postcoital test, routine endometrial biopsy for luteal phase dating, basal body temperature charting, routine mycoplasma cultures, and broad antibody testing have limited or no proven value in guiding treatment or improving outcomes for most couples. Karyotyping is reserved for specific indications (e.g., severe male factor, premature ovarian insufficiency, recurrent pregnancy loss)." },
  { id: 3312, category: 'fertility', keywords: ['CycleMind fertility tracking preconception support'], question: "How can CycleMind support users exploring fertility or undergoing evaluation?", response: "CycleMind can help users track cycle length and regularity, ovulation symptoms or LH surge data (if using kits), menstrual symptoms, mood, sleep, and other factors relevant to fertility awareness. It can provide general education on the basic components of an infertility workup and the importance of preconception health optimization. All specific testing decisions, result interpretation, and treatment planning must be handled by qualified clinicians." },
  { id: 3313, category: 'fertility', keywords: ['CycleMind Luna infertility evaluation boundaries'], question: "What boundaries should Luna maintain when discussing infertility evaluation?", response: "Luna must clearly state she is not a reproductive endocrinologist or fertility specialist and cannot order tests, interpret results, diagnose causes of infertility, or recommend specific treatments. Provide general information about standard evaluation components and timing while strongly redirecting users to their obstetrician-gynecologist or a reproductive endocrinologist for personalized assessment and care." },
  { id: 3314, category: 'fertility', keywords: ['preconception counseling infertility risk factors'], question: "What preconception factors should be addressed in patients concerned about fertility?", response: "Key areas include optimizing BMI, reviewing medications, screening for thyroid dysfunction or other endocrinopathies, addressing lifestyle factors (smoking, alcohol, substance use, exercise), offering genetic carrier screening based on ethnicity/family history, and ensuring up-to-date vaccinations and routine health maintenance. Early identification of risk factors (e.g., endometriosis symptoms, irregular cycles) allows timely referral." },
  { id: 3315, category: 'fertility', keywords: ['CycleMind pregnancy mode fertility transition support'], question: "How does CycleMind's Pregnancy mode relate to fertility evaluation support?", response: "CycleMind's Pregnancy mode can help users who are actively trying to conceive or who have recently started fertility evaluation by tracking relevant symptoms, cycle data, and emotional well-being. It should reinforce that fertility evaluation and treatment decisions belong with medical professionals while offering supportive, non-medical tracking and general education. Clear pathways to professional care and safety netting for concerning symptoms remain essential." },

  // === Overview of Infertility RAG Entries (IDs 3316–3325) ===
  { id: 3316, category: 'fertility', keywords: ['infertility definition ASRM timing evaluation'], question: "How is infertility defined and when should evaluation begin?", response: "ASRM defines infertility as a disease/condition characterized by inability to achieve a successful pregnancy based on medical/sexual/reproductive history, age, physical findings, or diagnostic testing; or the need for medical intervention (including donor gametes) to achieve pregnancy. Standard timing: initiate evaluation after 12 months of regular unprotected intercourse if the female partner is under 35, and after 6 months if she is 35 or older. Earlier evaluation is warranted for women ≥40, irregular cycles, known risk factors (endometriosis, prior PID, pelvic surgery, reproductive tract anomalies), or known/suspected male factor." },
  { id: 3317, category: 'fertility', keywords: ['fecundability fecundity fertility sterility definitions'], question: "What do fecundability, fecundity, fertility, and sterility mean?", response: "Fecundability is the probability of achieving a pregnancy that results in a live birth in a single menstrual cycle with adequate sperm exposure and no contraception. Fecundity is the capacity to have a live birth. Fertility is the ability to have a clinical pregnancy. Sterility is a permanent state of infertility. Time to pregnancy (usually in months) is often used in studies as a measure of subfecundity." },
  { id: 3318, category: 'fertility', keywords: ['infertility prevalence age parity access'], question: "What factors influence infertility prevalence?", response: "Global prevalence is roughly 1 in 6 adults. Prevalence rises with female age (lowest ~3% at ages 20–24; highest ~5.5% at 35–39). Nulliparous individuals have roughly double the prevalence of parous individuals, with even larger differences after age 35. Better access to reproductive health services is associated with lower prevalence, likely through earlier detection and treatment of gynecologic disease and infection. Race/ethnicity associations are likely confounded by socioeconomic factors." },
  { id: 3319, category: 'fertility', keywords: ['causes of infertility distribution male female unexplained'], question: "What are the common causes of infertility and their approximate distribution?", response: "Rough distribution in developed countries: male factor ~26%, ovulatory dysfunction ~21%, tubal damage ~14%, endometriosis ~6%, coital problems ~6%, cervical factor ~3%, and unexplained ~28% (totals exceed 100% because some couples have multiple factors). Both male and female factors are present in a substantial portion of couples. A complete evaluation of both partners is essential." },
  { id: 3320, category: 'fertility', keywords: ['who should perform infertility evaluation referral'], question: "Who should perform the infertility evaluation?", response: "Infertility evaluations are best directed by fertility specialists or physicians experienced in diagnosis and treatment of infertility. Primary care physicians or general obstetrician-gynecologists can often initiate portions of the basic workup, but couples with abnormal results or complex situations should be referred to a reproductive endocrinologist or specialist for comprehensive management and counseling." },
  { id: 3321, category: 'fertility', keywords: ['basic infertility evaluation components tests'], question: "What are the core components of the basic infertility evaluation?", response: "Core components include: detailed history and physical examination of both partners; semen analysis; assessment of ovulatory function (menstrual history ± mid-luteal progesterone or urinary LH kits); evaluation of tubal patency and uterine cavity (HSG or HyCoSy); ovarian reserve testing (AMH, day 3 FSH/estradiol, antral follicle count); and basic labs such as TSH and prolactin. Additional testing (pelvic ultrasound, laparoscopy) is selected based on history and initial findings." },
  { id: 3322, category: 'fertility', keywords: ['infertility treatment principles reversible irreversible'], question: "What are the general principles of infertility treatment?", response: "Once causes are identified, treatment focuses on correcting reversible factors and overcoming irreversible ones. This may involve lifestyle optimization, medications, surgery, intrauterine insemination, or assisted reproductive technologies such as IVF. Counseling should also address emotional stress, which is common. Absolute contraindications are limited to situations where pregnancy itself or specific treatments are medically unsafe. Marital status, sexual orientation, and HIV status should not be used to deny care." },
  { id: 3323, category: 'fertility', keywords: ['CycleMind fertility preconception support tracking'], question: "How can CycleMind support users concerned about fertility or trying to conceive?", response: "CycleMind can help users track cycle length/regularity, ovulation symptoms or LH surge timing, menstrual patterns, mood, sleep, and other factors relevant to fertility awareness and preconception health. It can provide balanced general education on the timing of evaluation and basic workup components while strongly encouraging users to discuss concerns with their obstetrician-gynecologist or a reproductive specialist. All testing decisions, result interpretation, and treatment planning belong with qualified clinicians." },
  { id: 3324, category: 'fertility', keywords: ['CycleMind Luna infertility boundaries referral'], question: "What boundaries should Luna maintain when discussing infertility?", response: "Luna must clearly state she is not a reproductive endocrinologist or fertility specialist and cannot order tests, interpret results, diagnose causes of infertility, or recommend specific treatments or timelines. Provide general educational information about definitions, common causes, and when evaluation is typically initiated, while strongly redirecting users to their obstetrician-gynecologist or a reproductive endocrinologist for personalized assessment, testing, and care." },
  { id: 3325, category: 'fertility', keywords: ['infertility pregnancy outcomes risks treatment'], question: "Do infertility treatments affect pregnancy outcomes?", response: "Women who conceive after infertility treatment (IVF or non-IVF) have a modestly increased risk of some complications such as preterm birth, low birth weight, and severe maternal morbidity compared with the general population. However, subfertile women who conceive naturally without treatment also show elevated risks of preterm birth and low birth weight. The relationship between specific causes of infertility, treatment type, and outcomes requires individualized counseling by the care team." },

  // === Female Infertility: Causes RAG Entries (IDs 3326–3335) ===
  { id: 3326, category: 'fertility', keywords: ['female infertility causes distribution ovulatory tubal endometriosis'], question: "What are the most common identifiable causes of female infertility?", response: "In resource-abundant countries, the most common identifiable female factors (accounting for ~81% of female infertility) are: ovulatory disorders (~25%), endometriosis (~15%), pelvic adhesions (~12%), tubal blockage (~11%), other tubal abnormalities (~11%), and hyperprolactinemia (~7%). Many couples have multiple contributing factors. With advancing female age, age-related oocyte decline and accumulated gynecologic disease become increasingly important." },
  { id: 3327, category: 'fertility', keywords: ['ovulatory disorders causes PCOS hypothalamic pituitary'], question: "What are the main causes of ovulatory disorders leading to infertility?", response: "Ovulatory disorders (oligoovulation or anovulation) prevent regular release of an oocyte. Common categories include hypothalamic causes (e.g., functional hypothalamic amenorrhea, stress, weight loss), pituitary causes (e.g., hyperprolactinemia, hypopituitarism), ovarian causes (e.g., premature ovarian insufficiency), and polycystic ovary syndrome (PCOS). Women with regular menses and molimina are usually ovulatory; irregular or absent menses warrant evaluation." },
  { id: 3328, category: 'fertility', keywords: ['oocyte aging ovarian reserve decline female age'], question: "How does female age affect oocyte quantity and quality?", response: "Female fertility declines with age primarily due to progressive loss of oocyte quantity and quality. The ovarian follicle pool peaks in fetal life and declines steadily, with accelerated loss after the mid-30s. Oocyte quality declines due to increased meiotic nondisjunction and other age-related changes. This leads to lower fecundability, higher miscarriage rates, and poorer response to ovarian stimulation, even in women who continue to ovulate regularly." },
  { id: 3329, category: 'fertility', keywords: ['tubal factor infertility pelvic adhesions PID hydrosalpinx'], question: "What causes tubal factor infertility and how do hydrosalpinges affect outcomes?", response: "Tubal factor infertility results from damage that impairs oocyte/sperm transport, most commonly from pelvic inflammatory disease (chlamydia, gonorrhea). Other causes include severe endometriosis, prior surgery, nontubal infection, pelvic tuberculosis, and salpingitis isthmica nodosa. Hydrosalpinges reduce IVF success rates, likely via retrograde flow of toxic fluid into the endometrial cavity; surgical removal or occlusion of hydrosalpinges improves IVF outcomes." },
  { id: 3330, category: 'fertility', keywords: ['uterine causes infertility fibroids anomalies adhesions'], question: "How do uterine abnormalities contribute to infertility?", response: "Uterine factors impair implantation through mechanical distortion or reduced endometrial receptivity. Submucosal or intracavitary fibroids appear to reduce implantation and pregnancy rates (with variable data on live birth). Congenital uterine anomalies (especially septate uterus) and acquired conditions (polyps, intrauterine adhesions/synechiae) can also interfere with implantation. Cervical stenosis or mucus abnormalities may impair sperm transport." },
  { id: 3331, category: 'fertility', keywords: ['endometriosis infertility mechanisms pelvic adhesions'], question: "How does endometriosis cause infertility?", response: "Endometriosis reduces fertility through multiple mechanisms: anatomic distortion from pelvic adhesions, direct damage to ovarian tissue (endometriomas and surgical resection), and production of inflammatory cytokines/growth factors that impair ovulation, fertilization, and implantation. Severity and location matter; even minimal/mild disease can affect fertility in some patients." },
  { id: 3332, category: 'fertility', keywords: ['immune factors celiac autoantibodies infertility'], question: "Do immune factors or celiac disease contribute to infertility?", response: "Abnormal immune test results are sometimes found in women with reproductive failure, but rigorous evidence for a direct causal role in infertility is lacking, and routine immune testing/treatment solely for infertility is not supported. Untreated celiac disease is associated with higher rates of infertility, miscarriage, and other adverse outcomes; treatment may improve fertility in affected women." },
  { id: 3333, category: 'fertility', keywords: ['genetic causes female infertility FMR1 Turner'], question: "What genetic conditions are associated with female infertility?", response: "Infertile couples have a higher prevalence of karyotypic abnormalities than the general population. Key conditions include Turner syndrome (45,X) and fragile X premutation (FMR1), which can cause premature ovarian insufficiency. Other single-gene disorders affecting the hypothalamic-pituitary-ovarian axis (e.g., GnRH receptor, FSH/LH receptor mutations) are rare but important when suspected. TUBB8 mutations specifically impair oocyte maturation." },
  { id: 3334, category: 'fertility', keywords: ['luteal phase defect unexplained infertility'], question: "What is the status of luteal phase defect as a cause of infertility?", response: "Luteal phase defect (inadequate progesterone production or endometrial response) has historically been proposed as a cause of infertility, but current evidence does not support it as a distinct, treatable entity. There is no consensus on diagnostic criteria or effective treatment, and endometrial dating is not recommended for evaluating or managing infertility." },
  { id: 3335, category: 'fertility', keywords: ['CycleMind Luna female infertility causes support boundaries'], question: "How should CycleMind and Luna support users exploring causes of infertility?", response: "CycleMind can help users notice patterns in cycle regularity, ovulatory symptoms, pelvic pain, or other factors that may relate to common causes (ovulatory dysfunction, endometriosis, etc.) while providing balanced, non-alarmist education. Luna must clearly state she is not a fertility specialist and cannot diagnose causes or order testing. All specific evaluation, interpretation of results, and treatment decisions must be directed to the user's obstetrician-gynecologist or reproductive endocrinologist. Include clear pathways to professional care." },

  // === Natural Fertility & Lifestyle Factors RAG Entries (IDs 3336–3345) ===
  { id: 3336, category: 'fertility', keywords: ['natural fertility rates time to pregnancy'], question: "What are typical natural fertility rates and time to pregnancy?", response: "Most pregnancies occur in the first six menstrual cycles of trying. Approximately 80% of couples conceive within 6 months and 85% within 12 months of regular unprotected intercourse. Fecundability is highest (~30% per cycle) in the first 1–2 cycles and declines over time. After 48 months without conception, spontaneous pregnancy becomes uncommon. Evaluation timing should be individualized based on age and risk factors." },
  { id: 3337, category: 'fertility', keywords: ['fertile window ovulation timing intercourse'], question: "When is the fertile window and how often should couples have intercourse?", response: "The fertile window is approximately 6 days: the 5 days before ovulation plus the day of ovulation. Highest conception probability occurs with intercourse 1–2 days before ovulation and on the day of ovulation. For most couples, having vaginal intercourse every 1–2 days during the follicular phase (or 2–3 times per week starting after menses) optimizes chances while maintaining good semen quality." },
  { id: 3338, category: 'fertility', keywords: ['ovulation tracking methods calendar mucus LH kits apps'], question: "What methods can be used to track the fertile window?", response: "Options include menstrual calendar tracking, observing cervical mucus changes (most fertile on peak slippery clear mucus day), basal body temperature monitoring, urinary LH ovulation predictor kits, and fertility tracking apps. LH kits can be particularly helpful for women with irregular cycles. No single method is dramatically superior for most people, but consistent tracking helps identify the fertile window." },
  { id: 3339, category: 'fertility', keywords: ['BMI obesity overweight fertility weight loss'], question: "How does body weight affect fertility?", response: "Both underweight (BMI <17–18.5) and overweight/obese (BMI ≥25–27) status are associated with reduced fertility, largely through ovulatory dysfunction (especially in PCOS for higher BMI). Weight gain in adulthood can also prolong time to conception even in regularly cycling women. Modest weight loss in overweight/obese individuals can improve ovulation and spontaneous conception rates in some studies, though effects on live birth rates with fertility treatment are mixed. A BMI of 18.5–25 kg/m² is generally optimal for fertility and overall health." },
  { id: 3340, category: 'fertility', keywords: ['exercise fertility female vigorous activity'], question: "How does exercise affect female fertility?", response: "Vigorous or intense exercise (especially >4–5 hours/week) can reduce fertility in women with normal BMI, possibly via effects on GnRH, LH/FSH, progesterone, and leptin. In overweight/obese women, moderate exercise is generally beneficial. We suggest women with BMI <25 who are trying to conceive limit vigorous exercise to fewer than 5 hours per week while maintaining overall activity. Male fertility does not appear significantly affected by exercise." },
  { id: 3341, category: 'fertility', keywords: ['caffeine alcohol fertility pregnancy'], question: "What are the effects of caffeine and alcohol on fertility?", response: "Caffeine intake under ~200 mg/day (roughly 1–2 cups of coffee) does not appear to impair female fertility and may even be associated with slightly better outcomes in some studies. Moderate alcohol use (<2 drinks/day) probably has minimal effect, but heavier use is linked to longer time to pregnancy. We suggest women trying to conceive limit or avoid alcohol, as no safe level is established for the developing fetus. Male moderate alcohol use does not clearly impair fertility." },
  { id: 3342, category: 'fertility', keywords: ['smoking tobacco fertility male female'], question: "How does smoking affect fertility?", response: "Cigarette smoking by the female partner is clearly associated with reduced fertility, earlier menopause, and lower success rates with IVF. Effects appear dose-dependent. Male smoking is linked to reduced semen quality, though the impact on fertility is less definitive. Smoking cessation improves fertility outcomes in many observational studies and should be strongly encouraged for both partners for fertility and overall health." },
  { id: 3343, category: 'fertility', keywords: ['lubricants fertility intercourse position orgasm'], question: "Do lubricants, coital position, or female orgasm affect conception chances?", response: "Some lubricants can impair sperm motility in vitro, but real-world data on fecundability are limited and mixed. When lubricants are needed, mineral oil, canola oil, or hydroxyethylcellulose-based products (e.g., Pre-Seed) are preferable. Coital position, presence/absence of female orgasm, and remaining supine after ejaculation do not appear to meaningfully affect conception rates." },
  { id: 3344, category: 'fertility', keywords: ['CycleMind fertility lifestyle tracking ovulation'], question: "How can CycleMind support users trying to conceive or optimize fertility?", response: "CycleMind can help users track cycle length, ovulation symptoms or LH surge timing, cervical mucus observations (if desired), intercourse frequency, mood, sleep, and lifestyle factors (exercise, caffeine, smoking, alcohol) alongside their cycle data. It can provide balanced education on the fertile window, normal fertility timelines, and evidence-based lifestyle factors while strongly encouraging users to discuss personalized plans with their clinician, especially if conception is delayed or they have risk factors." },
  { id: 3345, category: 'fertility', keywords: ['CycleMind Luna fertility lifestyle boundaries'], question: "What boundaries should Luna maintain regarding fertility and lifestyle advice?", response: "Luna must clearly state she is not a fertility specialist or physician and cannot diagnose infertility, interpret test results, recommend specific treatments, or create personalized conception plans. Provide general, evidence-based information on normal fertility timelines, the fertile window, and lifestyle factors while strongly redirecting all medical evaluation, testing, and treatment decisions to the user's obstetrician-gynecologist or reproductive endocrinologist. Include clear pathways to professional care." },

  // === Endometriosis & Infertility Treatment RAG Entries (IDs 3346–3355) ===
  { id: 3346, category: 'fertility', keywords: ['endometriosis infertility prevalence mechanisms'], question: "How common is endometriosis in infertile women and how does it impair fertility?", response: "Endometriosis affects 10–15% of reproductive-age women; 30–50% of women with endometriosis have infertility, and 25–50% of infertile women have endometriosis. Mechanisms vary by stage: mild disease triggers inflammation (cytokines, prostaglandins, immune changes) that can impair folliculogenesis, fertilization, and implantation; advanced disease adds anatomic distortion from adhesions and endometriomas that impair ovum pickup, tubal transport, and implantation. Both pathways often coexist." },
  { id: 3347, category: 'fertility', keywords: ['endometriosis infertility evaluation surgery indications'], question: "What is the recommended approach when endometriosis and infertility coexist?", response: "Perform a full infertility evaluation first (semen analysis, ovulation assessment, tubal/uterine evaluation, ovarian reserve). Then assess whether primary surgery for endometriosis is indicated. Primary operative laparoscopy (excision/ablation) is reasonable for symptomatic patients (pain, dysmenorrhea, dyspareunia) or when high-stage disease is suspected. Asymptomatic patients generally proceed directly to infertility treatment. Repeat surgery is mainly for severe recurrent pain, not to improve fertility." },
  { id: 3348, category: 'fertility', keywords: ['endometrioma infertility management ART vs surgery'], question: "How should endometriomas be managed in infertile patients?", response: "For most infertile patients with an asymptomatic endometrioma, proceed with ART (IVF) rather than routine surgical removal, as surgery can further reduce ovarian reserve. Exceptions include endometriomas that limit oocyte retrieval, are symptomatic, or raise concern for malignancy. Decisions should be individualized with a reproductive endocrinologist and consider ovarian reserve, patient age, and prior surgeries." },
  { id: 3349, category: 'fertility', keywords: ['minimal mild endometriosis infertility treatment superovulation IUI'], question: "How is infertility treated in minimal or mild endometriosis (stage I/II)?", response: "For women <35 years with stage I/II endometriosis and no or reversible infertility factors, start with mild superovulation (clomiphene or letrozole) plus IUI for up to 3 cycles. This approach is low-cost, lower risk of multiples than gonadotropins, and improves fecundability. For women ≥35 years, many proceed directly to ART (IVF) to shorten time to pregnancy and allow embryo freezing. Patient age, preferences, cost, and access to care guide the choice between sequential superovulation/IUI versus direct ART." },
  { id: 3350, category: 'fertility', keywords: ['severe endometriosis infertility treatment ART'], question: "How is infertility treated in moderate to severe endometriosis (stage III/IV)?", response: "Women with stage III/IV endometriosis and infertility generally proceed directly to ART (typically IVF), especially if there are nonreversible factors (male factor, diminished ovarian reserve, tubal disease). Superovulation with IUI has limited benefit in advanced disease. Repeat surgery does not improve fertility outcomes and is reserved for severe pain or specific indications (e.g., symptomatic endometrioma). ART success is reduced compared with milder disease, largely due to lower ovarian reserve." },
  { id: 3351, category: 'fertility', keywords: ['endometriosis ART outcomes live birth rates by stage'], question: "How does endometriosis affect ART/IVF outcomes?", response: "Mild (stage I/II) endometriosis has minimal or controversial impact on IVF live birth rates after controlling for age. Severe (stage III/IV) disease is associated with lower ovarian reserve, fewer oocytes retrieved, lower implantation rates, and modestly reduced cumulative live birth rates. Despite this, many women with advanced endometriosis still achieve live births with IVF. Donor oocyte IVF can be considered for those with significantly diminished reserve." },
  { id: 3352, category: 'fertility', keywords: ['endometriosis ineffective treatments hormonal suppression'], question: "Which treatments do not improve fertility in endometriosis?", response: "Hormonal suppression (GnRH agonists, danazol, progestins, etc.), Chinese herbal medicine, nutritional supplements, and most complementary/alternative therapies have not been shown to improve pregnancy rates in endometriosis-related infertility. These may help pain but do not enhance fecundability. Surgery followed by immediate fertility treatment (rather than prolonged postoperative suppression) is preferred when fertility is the goal." },
  { id: 3353, category: 'fertility', keywords: ['endometriosis fertility preservation considerations'], question: "When should fertility preservation be considered in endometriosis?", response: "Fertility preservation (oocyte or embryo freezing) may be reasonable for select patients at high risk of diminished ovarian reserve, such as those with bilateral endometriomas, prior ovarian surgery, or young age at diagnosis with extensive disease. It is not routinely recommended for all patients with endometriosis, as many conceive without it. Decisions should be individualized with a reproductive endocrinologist." },
  { id: 3354, category: 'fertility', keywords: ['CycleMind endometriosis infertility pain tracking support'], question: "How can CycleMind support users with endometriosis and fertility concerns?", response: "CycleMind can help users track pelvic pain patterns, menstrual symptoms, cycle regularity, ovulation data, mood, and energy alongside fertility-related tracking. Provide balanced education that endometriosis can affect fertility through inflammation and anatomic changes, but many treatments (surgery when indicated, superovulation/IUI, or ART) are available. Strongly encourage multidisciplinary care (gynecology, reproductive endocrinology, pain management) and include clear pathways to professional evaluation for new or worsening symptoms or fertility questions." },
  { id: 3355, category: 'fertility', keywords: ['CycleMind Luna endometriosis infertility boundaries'], question: "What boundaries should Luna maintain regarding endometriosis and infertility?", response: "Luna must clearly state she is not a gynecologist or reproductive endocrinologist and cannot diagnose endometriosis, stage disease, recommend surgery, interpret imaging, or create personalized fertility treatment plans. Provide general evidence-based information on how endometriosis can affect fertility and common management approaches while strongly redirecting all medical decisions, surgical planning, and fertility treatment to the user's qualified care team. Include prominent safety netting for severe pain or concerning symptoms." },

  // === Unexplained Infertility (IDs 3356–3365) ===
  { id: 3356, category: 'fertility', keywords: ['unexplained infertility definition thorough evaluation'], question: "What is unexplained infertility and how is it diagnosed?", response: "Unexplained infertility means no identifiable cause is found after a thorough evaluation despite 12 months of trying (or 6 months if the woman is ≥35). A complete workup typically includes confirmation of ovulation, tubal patency, normal uterine cavity, normal semen analysis, and adequate ovarian reserve. Many cases likely result from subtle or combined minor factors rather than a single clear problem." },

  { id: 3357, category: 'fertility', keywords: ['unexplained infertility subtle causes oocyte sperm endometrial'], question: "What are possible reasons for unexplained infertility?", response: "Possible contributing factors include subtle abnormalities in oocyte or sperm function, reduced endometrial receptivity, minor issues with gamete transport or interaction, or the combined effect of several borderline factors (e.g., slightly diminished ovarian reserve plus low-normal semen parameters). Some cases may also involve undetected genetic variants or untreated conditions such as celiac disease. IVF itself can sometimes reveal fertilization or embryo cleavage issues." },

  { id: 3358, category: 'fertility', keywords: ['unexplained infertility stepwise treatment approach'], question: "What is the general treatment approach for unexplained infertility?", response: "Management is stepwise and individualized, starting with low-resource, lower-risk options and progressing as needed. Typical sequence: address lifestyle factors → clomiphene or letrozole plus IUI (first-line for most) → IVF for those who do not conceive after 3–4 cycles. For patients who cannot or choose not to pursue IVF, options may include gonadotropin/IUI or laparoscopy. Patient age, prognosis, cost, insurance, values, and tolerance for multiples strongly influence choices." },

  { id: 3359, category: 'fertility', keywords: ['expectant management unexplained infertility age'], question: "When is expectant management reasonable for unexplained infertility?", response: "Expectant management (no active treatment) yields roughly 1–3% pregnancy chance per month. It may be reasonable for young women (<32–35) with good prognosis and no urgent concerns about ovarian reserve. It is generally not appropriate for women >37 because ovarian aging accelerates and the chance of spontaneous conception drops sharply. Most couples prefer active treatment even when expectant management is an option." },

  { id: 3360, category: 'fertility', keywords: ['lifestyle changes smoking BMI caffeine unexplained infertility'], question: "What lifestyle changes are recommended for couples with unexplained infertility?", response: "Couples should be encouraged to stop smoking, achieve a healthy BMI (18.5–25 kg/m²), limit caffeine to ~200–250 mg/day, and limit alcohol. These changes support overall fertility and health. Coordinated lifestyle efforts by both partners can also provide mutual support during the fertility journey." },

  { id: 3361, category: 'fertility', keywords: ['clomiphene letrozole IUI first line unexplained infertility'], question: "Why is clomiphene or letrozole plus IUI often used first for unexplained infertility?", response: "Clomiphene or letrozole plus IUI is commonly used first because it is oral, relatively low-cost, requires little monitoring, has a reasonable pregnancy rate, and carries a lower risk of high-order multiples than gonadotropins. It aims to produce mild superovulation (often double ovulation) while placing concentrated motile sperm higher in the reproductive tract. Most couples try 3–4 cycles before moving to the next step." },

  { id: 3362, category: 'fertility', keywords: ['IVF unexplained infertility when to proceed'], question: "When should couples with unexplained infertility move to IVF?", response: "IVF is generally recommended after 3–4 unsuccessful cycles of clomiphene or letrozole plus IUI, as it offers the highest per-cycle pregnancy and live birth rates in the shortest time. It is especially valuable for older women or those with any hint of diminished ovarian reserve. IVF also allows embryo freezing for future use and single-embryo transfer to minimize multiples." },

  { id: 3363, category: 'fertility', keywords: ['gonadotropin IUI multiples risk unexplained infertility'], question: "What are the considerations with gonadotropin injections plus IUI?", response: "Gonadotropin/IUI can increase pregnancy rates compared with oral agents but carries a substantially higher risk of multiple gestations (including triplets and higher). Because of this risk and the superior efficacy and control of IVF, many specialists prefer moving directly to IVF rather than gonadotropins after oral agent + IUI failure. Decisions depend on patient values, access, and risk tolerance." },

  { id: 3364, category: 'fertility', keywords: ['laparoscopy unexplained infertility endometriosis'], question: "What is the role of laparoscopy in unexplained infertility?", response: "Laparoscopy can diagnose and treat conditions such as endometriosis or adhesions that may have been missed on non-invasive testing. It is sometimes offered after oral agent + IUI failure for symptomatic patients or when IVF is not an option. Surgical treatment of endometriosis found at laparoscopy has been associated with improved fertility in some studies. It is not routine for every patient with unexplained infertility." },

  { id: 3365, category: 'fertility', keywords: ['CycleMind Luna unexplained infertility tracking boundaries'], question: "How should CycleMind and Luna support users with unexplained infertility or fertility concerns?", response: "CycleMind can help users track cycle characteristics, ovulation signs, intercourse timing, symptoms, mood, and lifestyle factors while providing balanced education about normal fertility timelines and common next steps in evaluation. Luna must clearly state she is not a reproductive endocrinologist and cannot diagnose unexplained infertility, interpret test results, recommend specific treatments, or create personalized plans. All medical evaluation, testing decisions, and treatment choices must be directed by the user's obstetrician-gynecologist or reproductive endocrinologist. Include clear pathways to professional care." },

  // === Alcohol Use in Pregnancy (IDs 3386–3395) ===
  { id: 3386, category: 'pregnancy', keywords: ['alcohol use pregnancy prevalence no safe level'], question: "How common is alcohol use in pregnancy and is there a safe level?", response: "Alcohol use during pregnancy is common and appears to be rising in the US. No safe level of alcohol consumption during pregnancy has been established. Alcohol is a known teratogen that can affect fetal development at any stage. Major medical societies recommend complete abstinence from conception through pregnancy to eliminate the risk of alcohol-related birth defects and neurodevelopmental issues (FASD). Even low-level exposure may influence craniofacial development and increase risks such as pregnancy loss." },

  { id: 3387, category: 'pregnancy', keywords: ['fetal alcohol spectrum disorder FASD effects pregnancy'], question: "What are the effects of prenatal alcohol exposure?", response: "Prenatal alcohol exposure can cause a spectrum of adverse outcomes known as fetal alcohol spectrum disorder (FASD), including growth restriction, facial dysmorphology, central nervous system abnormalities, and lifelong neurodevelopmental, behavioral, and cognitive impairments. There is no clear dose-response relationship; outcomes vary based on timing, quantity, pattern (e.g., binge drinking), genetics, maternal factors, and other exposures. Stillbirth risk also increases with alcohol consumption." },

  { id: 3388, category: 'pregnancy', keywords: ['alcohol screening pregnancy T-ACE TWEAK AUDIT-C'], question: "What screening tools are used for alcohol use in pregnancy?", response: "Recommended brief screening tools for pregnant individuals include T-ACE (Tolerance, Annoyed, Cut down, Eye-opener), TWEAK, and AUDIT-C. These tools are more appropriate for prenatal use than general population screens. A positive screen should trigger further assessment and brief intervention. Universal screening at the first prenatal visit and periodically thereafter is recommended, as self-report alone can underestimate use due to stigma." },

  { id: 3389, category: 'pregnancy', keywords: ['brief intervention alcohol pregnancy efficacy'], question: "How effective are brief interventions for alcohol use in pregnancy?", response: "Brief psychosocial interventions (educational sessions, motivational enhancement, cognitive behavioral approaches) increase continuous abstinence rates compared with usual care. Even brief clinician counseling is more effective than no intervention. Involving a supportive partner can further improve outcomes, especially for heavier drinkers. Pregnancy-specific reporting policies have not been shown to reduce infant harm and may delay care." },

  { id: 3390, category: 'pregnancy', keywords: ['management alcohol use pregnancy prenatal care'], question: "What are key principles of prenatal care when alcohol use is identified?", response: "Core elements include: universal screening, nonjudgmental counseling on risks, early ultrasound for accurate dating, monitoring for growth restriction, multidisciplinary team involvement (obstetrics, addiction medicine, social work, pediatrics), preparation for possible neonatal effects, discussion of breastfeeding (discouraged if ongoing use), and postpartum support. For heavy drinkers or alcohol use disorder, refer to specialized treatment. Medication for alcohol use disorder may be considered in select cases with specialist input." },

  { id: 3391, category: 'pregnancy', keywords: ['alcohol cessation benefits any time pregnancy'], question: "Is it beneficial to stop drinking at any point in pregnancy?", response: "Yes. Cessation at any point during pregnancy improves outcomes compared with continued drinking. Children born to individuals who stop drinking even late in gestation have better outcomes than those whose mothers continue throughout pregnancy. This supports ongoing screening and intervention at every prenatal visit." },

  { id: 3392, category: 'pregnancy', keywords: ['CycleMind alcohol pregnancy tracking mood support'], question: "How can CycleMind support users regarding alcohol use during pregnancy or preconception?", response: "CycleMind can help users track alcohol intake patterns, cravings, mood, sleep, stress, and pregnancy symptoms in one private place. It can provide balanced, nonjudgmental education on why abstinence is recommended, the benefits of quitting at any stage, and the value of discussing use openly with the prenatal care team. Include clear, low-barrier pathways to clinical resources and support services." },

  { id: 3393, category: 'pregnancy', keywords: ['CycleMind Luna alcohol pregnancy boundaries nonjudgmental'], question: "What boundaries should Luna maintain when discussing alcohol use in pregnancy?", response: "Luna must clearly state she is not a physician or addiction specialist and cannot diagnose alcohol use disorder, assess fetal risk, recommend specific treatments, or create cessation plans. All conversations must remain strictly nonjudgmental and supportive. Any screening results, counseling, medication decisions, or referrals must be directed by the user's obstetrician or qualified care team. Provide general education and strong redirection to professional care." },

  { id: 3394, category: 'pregnancy', keywords: ['alcohol pregnancy mental health intersection PMDD'], question: "How might alcohol use intersect with mental health and PMDD tracking in pregnancy?", response: "Some individuals use alcohol to cope with mood symptoms, anxiety, or sleep difficulties, which can overlap with PMDD or perinatal mood concerns. In CycleMind's pregnancy mode, tracking alcohol alongside mood, sleep, and symptoms can help users and clinicians identify patterns. However, Luna should never suggest alcohol as a coping strategy and must redirect any concerns about use, dependence, or mental health to the user's clinical team for integrated support." },

  { id: 3395, category: 'pregnancy', keywords: ['alcohol pregnancy partner involvement support'], question: "How can partners support alcohol cessation in pregnancy?", response: "Partner involvement in brief interventions is associated with greater reductions in alcohol use. Partners can help by maintaining a supportive, nonjudgmental environment, participating in discussions about risks, and reducing their own alcohol use if applicable. CycleMind can gently encourage users to involve supportive partners while emphasizing that final decisions and clinical care remain with the pregnant person and their healthcare team." },

  // === Psychiatric Medications During Breastfeeding (IDs 3396–3405) ===
  { id: 3396, category: 'postpartum', keywords: ['psychiatric medication breastfeeding safety determination RID M/P ratio'], question: "How is the safety of psychiatric medications during breastfeeding determined?", response: "Safety is assessed using multiple factors: measured drug levels in maternal plasma, breast milk, and infant plasma; milk-to-plasma (M/P) ratio (lower is better; <1 favorable); relative infant dose (RID; generally <10% of maternal weight-adjusted dose is acceptable); published case series and adverse event reports; and expert consensus/guidelines (ACOG, AAFP, LactMed). Uguz's safety scoring system rates medications on sample size, RID data, infant levels, and adverse events (higher score = more reassuring). Low or undetectable infant plasma levels despite measurable milk levels provide strong reassurance." },

  { id: 3397, category: 'postpartum', keywords: ['general principles psychiatric meds breastfeeding premature infants'], question: "What are the general principles for psychiatric medication use while breastfeeding?", response: "All psychiatric medications are excreted into breast milk to varying degrees. Premature or medically vulnerable infants (e.g., hepatic impairment) have reduced ability to metabolize drugs and may be at higher risk. Routine infant drug-level monitoring is not required for healthy full-term infants but should be considered if symptoms of toxicity appear or with higher maternal doses. Long-term developmental outcome data remain limited. Collaboration with the infant's pediatrician is essential. Decisions must balance maternal mental health benefits against potential (often theoretical) infant risks." },

  { id: 3398, category: 'postpartum', keywords: ['antidepressants breastfeeding SSRIs TCAs safety'], question: "Are antidepressants safe during breastfeeding?", response: "SSRIs (especially sertraline and paroxetine) and tricyclic antidepressants are among the best-studied and most reassuring options, with low breast milk concentrations and typically undetectable or very low infant serum levels. Adverse events are rare. Other antidepressants (venlafaxine, duloxetine, mirtazapine, trazodone) have less data but may be considered when clinically indicated with monitoring. Recent guidelines state there is little evidence of significant harm from antidepressant exposure via breast milk. The risks of untreated maternal depression far outweigh theoretical risks of medication." },

  { id: 3399, category: 'postpartum', keywords: ['benzodiazepines breastfeeding safety lorazepam clonazepam'], question: "How are benzodiazepines managed during breastfeeding?", response: "Commonly used benzodiazepines (lorazepam, clonazepam) appear at low levels in breast milk. Adverse effects are rarely reported but may include infant sedation or feeding difficulties, especially with higher doses or longer-acting agents. Shortest-acting agents at the lowest effective dose for the shortest duration are preferred. Routine monitoring for sedation and feeding issues is recommended. Guidelines support short-term use and indicate little evidence of significant harm." },

  { id: 3400, category: 'postpartum', keywords: ['mood stabilizers breastfeeding lithium lamotrigine valproate'], question: "What are the considerations for mood stabilizers during breastfeeding?", response: "Lithium transfers significantly into milk (infant levels can reach 1/3–1/2 of maternal levels); close monitoring of infant lithium, renal, and thyroid function is required. Lamotrigine shows variable infant levels (20–50% of maternal); no serious adverse events (including SJS) reported, but pediatrician consultation and monitoring are advised. Carbamazepine and valproic acid require caution with recommended infant liver function monitoring due to rare hepatotoxicity reports." },

  { id: 3401, category: 'postpartum', keywords: ['antipsychotics breastfeeding olanzapine quetiapine aripiprazole clozapine'], question: "What is known about antipsychotic use during breastfeeding?", response: "Olanzapine is the best-studied atypical antipsychotic (nearly 40 exposures); low milk/serum levels and rare mild sedation at doses up to 20 mg/day. Quetiapine (up to 400 mg) yields low RID (<1%). Risperidone has some reports of sedation, jitteriness, or movement issues (causality unclear). Aripiprazole can significantly reduce prolactin and has been associated with lactation failure/insufficient milk supply in many users — monitor feeding and weight gain closely. Clozapine is contraindicated (agranulocytosis risk). First-generation antipsychotics are generally compatible at moderate doses." },

  { id: 3402, category: 'postpartum', keywords: ['ADHD medications breastfeeding methylphenidate amphetamines'], question: "Are ADHD medications compatible with breastfeeding?", response: "Methylphenidate and amphetamines generally appear at very low levels in milk with relative infant doses typically <1%. Most reports show no adverse events or developmental concerns in exposed infants. Use lowest effective dose and immediate-release formulations when possible; time doses to minimize infant exposure. Monitor for irritability, poor feeding, sleep changes, or growth concerns, especially postpartum or with dose increases. Non-stimulants (atomoxetine, guanfacine, clonidine) have limited data; guanfacine/clonidine may affect milk supply — monitor closely or consider alternatives." },

  { id: 3403, category: 'postpartum', keywords: ['clinical decision making psychiatric meds breastfeeding guidelines'], question: "What principles guide clinical decision-making for psychiatric medications while breastfeeding?", response: "Prioritize continuation of effective pregnancy medications postpartum to minimize relapse risk. Individualize based on severity of maternal illness, prior response, desire/ability to breastfeed, and medication-specific data. Weigh benefits of maternal stability and breastfeeding against potential infant exposure. Continue standard infant monitoring with attention to feeding, sedation, irritability, and growth. Consult LactMed for latest data. For severe illness, reducing or supplementing breastfeeding may be appropriate to protect maternal health. Shared decision-making with perinatal psychiatry and pediatrics is ideal." },

  { id: 3404, category: 'postpartum', keywords: ['CycleMind Luna breastfeeding psychiatric medication support'], question: "How can CycleMind support users taking psychiatric medications while breastfeeding?", response: "CycleMind's postpartum mode can help users track mood, sleep, energy, medication adherence (if desired), breastfeeding patterns, infant feeding cues, and any noted infant symptoms in one integrated place. It can provide balanced education that many psychiatric medications are compatible with breastfeeding, that untreated maternal illness carries real risks, and that decisions should be made collaboratively with the care team. Include prominent, easy pathways to LactMed, perinatal psychiatry resources, and pediatric consultation." },

  { id: 3405, category: 'postpartum', keywords: ['CycleMind Luna breastfeeding psychiatric meds boundaries'], question: "What boundaries should Luna maintain regarding psychiatric medications and breastfeeding?", response: "Luna must clearly state she is not a physician, perinatal psychiatrist, or lactation consultant and cannot recommend specific medications, assess safety for an individual case, interpret infant symptoms, or create treatment plans. Provide general, evidence-based information that many medications have reassuring data and that individualized decisions with the care team (including pediatrician) are essential. Strongly redirect all medication questions, changes, or concerns to the user's perinatal psychiatrist, obstetrician, or pediatrician. Include clear safety netting and referral pathways to professional resources such as LactMed and Postpartum Support International." },

  // === Perinatal Substance Use (IDs 3406–3415) ===
  { id: 3406, category: 'pregnancy', keywords: ['substance use pregnancy prevalence trends screening'], question: "How common is substance use during pregnancy and why is universal screening important?", response: "Substance use disorders are increasingly prevalent among women of childbearing age. While many women reduce or stop use upon learning they are pregnant, those who continue are more likely to have a substance use disorder requiring specialized care. Universal screening at the first prenatal visit (and periodically thereafter) is recommended by ACOG regardless of race, ethnicity, or socioeconomic status. Validated tools include NIDA Quick Screen/ASSIST, 4P's Plus, and SURP-P. Screening must be non-judgmental and person-centered to build trust and encourage honest disclosure. Punitive policies are associated with delayed prenatal care and do not improve outcomes." },

  { id: 3407, category: 'pregnancy', keywords: ['alcohol pregnancy FASD no safe level interventions'], question: "What are the risks of alcohol use in pregnancy and how should it be addressed?", response: "There is no known safe level of alcohol during pregnancy. Alcohol is a teratogen that can cause fetal alcohol spectrum disorders (FASDs) with lifelong physical, behavioral, and neurodevelopmental effects. Even light or moderate use carries potential risk. Women should be encouraged to stop at any point — cessation at any stage benefits the baby. Brief interventions and counseling are effective for many; those with alcohol use disorder may need referral to specialized treatment or, in some cases, medically supervised withdrawal management." },

  { id: 3408, category: 'pregnancy', keywords: ['cannabis pregnancy risks prevalence counseling'], question: "What are the concerns with cannabis use during pregnancy?", response: "Cannabis use has increased among women of reproductive age, including during pregnancy (especially first trimester), often for nausea or anxiety. THC crosses the placenta and is associated with lower birth weight, increased preterm birth, higher NICU admission rates, and potential long-term effects on child behavior and cognition. Healthcare providers should counsel pregnant patients about these risks and support cessation. For those using cannabis for medical reasons, alternative treatments should be explored under medical supervision." },

  { id: 3409, category: 'pregnancy', keywords: ['opioids pregnancy MAT methadone buprenorphine NAS'], question: "How should opioid use disorder be managed during pregnancy?", response: "Untreated opioid use disorder in pregnancy is associated with poor fetal growth, preterm birth, stillbirth, and neonatal abstinence syndrome (NAS). Medication-assisted treatment (MAT) with methadone or buprenorphine is the standard of care. These medications improve prenatal care adherence, stabilize opioid levels, reduce withdrawal and relapse risk, and improve pregnancy outcomes. Abrupt discontinuation is not recommended and can harm the fetus. NAS is treatable, and long-term outcomes for infants can be positive with appropriate care. MAT should be continued throughout pregnancy and postpartum." },

  { id: 3410, category: 'pregnancy', keywords: ['stimulants pregnancy cocaine methamphetamine treatment'], question: "How are stimulant use disorders managed during pregnancy?", response: "Stimulants (cocaine, methamphetamine) cross the placenta and are associated with placental abruption, preterm labor, and intrauterine growth restriction. There are no approved medication-assisted treatments for stimulant use disorders in pregnancy. Treatment relies on behavioral interventions such as cognitive-behavioral therapy and contingency management. A non-judgmental, supportive approach is essential, as fear of legal consequences can deter women from seeking prenatal care." },

  { id: 3411, category: 'postpartum', keywords: ['postpartum substance use relapse overdose risk'], question: "What are the postpartum risks for women with substance use disorders?", response: "The postpartum period carries high risk for relapse due to sleep deprivation, postpartum depression/anxiety, pain, decreased monitoring, and newborn care stress. Drug-related deaths (including overdose) have become a leading cause of postpartum maternal mortality, especially 6–12 months after birth. Continued support and treatment into the postpartum period are critical. Breastfeeding decisions should be individualized, weighing benefits against potential infant exposure and the mother's ability to safely care for the infant." },

  { id: 3412, category: 'postpartum', keywords: ['support perinatal substance use nonjudgmental integrated care'], question: "What principles guide effective support for pregnant and postpartum women with substance use disorders?", response: "Effective support requires a compassionate, non-judgmental, person-centered approach that treats substance use disorder as a medical condition. Key elements include: universal screening, integrated care models (substance use treatment + prenatal/mental health/parenting support), peer support and recovery coaches, trauma-informed care, addressing social determinants of health (housing, transportation, childcare), continued postpartum support to prevent relapse, family involvement when possible, ready access to MAT for opioid use disorder, and breastfeeding support when appropriate. Legal advocacy and avoidance of punitive approaches improve engagement and outcomes." },

  { id: 3413, category: 'postpartum', keywords: ['CycleMind substance use pregnancy postpartum tracking support'], question: "How can CycleMind support users navigating substance use during pregnancy or postpartum?", response: "CycleMind can help users privately track mood, sleep, cravings, triggers, substance use patterns (if they choose to log), pregnancy/postpartum symptoms, and infant feeding/ well-being cues in one place. It can provide balanced, non-alarmist education that many women successfully reduce or stop use with support, that early help improves outcomes for both mother and baby, and that recovery is possible. Include prominent, low-barrier pathways to clinical resources, peer support, and helplines while emphasizing that CycleMind is not a substitute for professional care." },

  { id: 3414, category: 'postpartum', keywords: ['CycleMind Luna substance use pregnancy boundaries nonjudgmental'], question: "What boundaries should Luna maintain when discussing substance use in pregnancy or postpartum?", response: "Luna must clearly state she is not a physician, addiction specialist, or counselor and cannot diagnose substance use disorders, provide medical advice on treatment or detoxification, interpret toxicology results, or create recovery plans. All conversations must remain strictly non-judgmental and supportive. Any screening concerns, treatment decisions, medication questions (including MAT), or safety issues must be directed to the user's obstetric, addiction medicine, or perinatal mental health team. Provide general education on the value of early support and include clear referral pathways to qualified care." },

  { id: 3415, category: 'postpartum', keywords: ['perinatal substance use mental health intersection CycleMind'], question: "How does perinatal substance use intersect with mental health tracking in CycleMind?", response: "Substance use and mental health concerns (depression, anxiety, trauma) frequently co-occur in the perinatal period. CycleMind's integrated tracking of mood, sleep, anxiety, and substance-related patterns (when disclosed) can help users and clinicians notice connections and support holistic care. Luna should never suggest substances as coping tools and must consistently redirect users experiencing cravings, relapse concerns, or co-occurring mental health symptoms to their clinical team for integrated, evidence-based support that addresses both recovery and mental health." },

  // === Introduction: Women's Reproductive Mental Health Textbook (IDs 3466–3495) ===
  { id: 3466, category: 'introduction', keywords: ['womens reproductive mental health name purpose'], question: "What is the purpose of the Introduction section titled 'What's in a Name?'", response: "The introduction explains the deliberate choice of the term 'Women's Reproductive Mental Health' while acknowledging evolving language around gender and identity. It frames the textbook as a comprehensive resource focused on mental health across female reproductive transitions (menarche, menstrual cycle, pregnancy, postpartum, perimenopause, menopause) and sets the stage for inclusive, evidence-based care." },

  { id: 3467, category: 'introduction', keywords: ['reproductive psychiatry terminology evolution'], question: "Why does the textbook use the term 'Women's Reproductive Mental Health'?", response: "The term centers the book on mental illness associated with female reproductive biology and life stages. It prioritizes clinical and scientific clarity while recognizing that definitions of 'woman' are evolving. Future editions will expand language and coverage for gender-diverse populations as data and terminology mature." },

  { id: 3468, category: 'introduction', keywords: ['gender identity reproductive mental health'], question: "How does the textbook address gender identity and sexual orientation in reproductive mental health?", response: "Gender identity and sexual orientation are fluid and not determinative of reproductive health needs. The book primarily addresses cisgender women due to available data but explicitly calls for inclusive, non-assumptive, trauma-informed care. Providers should avoid assumptions about contraception, pregnancy, or family-building desires." },

  { id: 3469, category: 'introduction', keywords: ['LGBTQ+ reproductive psychiatry'], question: "What considerations are highlighted for LGBTQ+ individuals?", response: "LGBTQ+ people face higher rates of discrimination, stigma, trauma, and barriers to care. The textbook advocates for culturally competent, affirming care that does not conflate gender identity with reproductive capacity or risk. Inclusive language is used where evidence allows." },

  { id: 3470, category: 'introduction', keywords: ['CycleMind Luna introduction implications'], question: "How should CycleMind and Luna use the Introduction content?", response: "CycleMind can help users track symptoms across reproductive stages with inclusive language. Luna should provide general education on reproductive transitions, emphasize professional care, and use affirming, non-assumptive phrasing while always redirecting diagnosis/treatment to qualified clinicians." },

  { id: 3471, category: 'introduction', keywords: ['Luna boundaries reproductive terminology'], question: "What boundaries does the Introduction reinforce for Luna?", response: "Luna must clearly state she is not a psychiatrist and cannot diagnose or treat. She can share general educational information from the textbook and support symptom tracking but must redirect all clinical questions to the user's perinatal psychiatrist or OB/GYN." },

  { id: 3472, category: 'introduction', keywords: ['National Curriculum in Reproductive Psychiatry NCRP'], question: "What is the National Curriculum in Reproductive Psychiatry (NCRP) and its relation to the textbook?", response: "The textbook was inspired by and builds upon the National Curriculum in Reproductive Psychiatry (NCRP). It aims to fill the widespread training gap in psychiatry residencies regarding reproductive mental health." },

  { id: 3473, category: 'introduction', keywords: ['reproductive psychiatry training gaps'], question: "What training gaps in reproductive psychiatry does the textbook address?", response: "Most psychiatry residency programs provide little to no formal training in reproductive mental health despite women comprising over 50% of psychiatric patients and experiencing unique risks during reproductive transitions. The textbook serves as a core educational resource for clinicians, educators, and trainees." },

  { id: 3474, category: 'introduction', keywords: ['future editions gender diverse populations'], question: "What does the textbook say about future editions and gender-diverse populations?", response: "The editors anticipate that future editions will incorporate more comprehensive data and language for gender-diverse populations as the field advances. The current edition focuses on the best available evidence while committing to ongoing evolution of the field." },

  { id: 3475, category: 'introduction', keywords: ['foreword reproductive psychiatry importance'], question: "How does the foreword (Katherine L. Wisner and Samantha Meltzer-Brody) connect to the Introduction?", response: "The foreword highlights the high prevalence of mental illness in women during reproductive transitions and the critical need for specialized training, directly supporting the Introduction's emphasis on the textbook as a foundational resource." },

  { id: 3476, category: 'introduction', keywords: ['preface textbook purpose'], question: "How does the preface reinforce the Introduction's themes?", response: "The preface underscores the textbook's role as the first comprehensive resource in reproductive psychiatry, aligning with the Introduction's explanation of the book's title and scope." },

  { id: 3477, category: 'introduction', keywords: ['inclusive language reproductive mental health'], question: "What guidance does the Introduction provide on inclusive language?", response: "The book uses inclusive language where evidence allows and explicitly avoids assumptions based on gender identity or sexual orientation. It emphasizes trauma-informed, patient-centered care." },

  { id: 3478, category: 'introduction', keywords: ['CycleMind symptom tracking reproductive stages'], question: "How can CycleMind support users based on the Introduction?", response: "CycleMind can provide unified tracking of mood, sleep, and symptoms across all reproductive stages while surfacing general educational content from the textbook. Luna will always pair tracking tools with strong clinician redirection." },

  { id: 3479, category: 'introduction', keywords: ['Luna safe response reproductive topics'], question: "What is Luna's required response structure for reproductive mental health topics per the Introduction?", response: "Every Luna response must begin with a clear disclaimer (not a clinician, general education only), provide accurate textbook-derived information, and end with a strong redirect to the user's psychiatrist or OB/GYN." },

  { id: 3480, category: 'introduction', keywords: ['reproductive transitions textbook focus'], question: "Which reproductive transitions does the Introduction emphasize?", response: "Menarche, menstrual cycle (including PMDD), pregnancy, postpartum period, perimenopause, and menopause. The textbook provides comprehensive coverage of mental health across these stages." },

  { id: 3481, category: 'introduction', keywords: ['textbook editors Introduction'], question: "Who authored the Introduction?", response: "Lucy A. Hutner, M.D., Lisa A. Catapano, M.D., Ph.D., Erika Kelley, Ph.D., Sheryl A. Kingsberg, Ph.D., Sarah M. Nagle-Yang, M.D., Katherine E. Williams, M.D., and Lauren M. Osborne, M.D." },

  { id: 3482, category: 'introduction', keywords: ['CycleMind Luna professional boundaries'], question: "What professional boundaries does the Introduction reinforce for the app?", response: "The app must never diagnose, interpret symptoms clinically, or recommend treatment. It exists to support tracking and general education while directing users to qualified mental health professionals." },

  { id: 3483, category: 'introduction', keywords: ['evolving definitions woman reproductive health'], question: "How does the Introduction discuss evolving definitions of 'woman'?", response: "It acknowledges that societal and scientific definitions are changing and that future editions will reflect broader data on gender-diverse individuals while maintaining clinical precision in the current volume." },

  { id: 3484, category: 'introduction', keywords: ['trauma-informed care reproductive psychiatry'], question: "What does the Introduction say about trauma-informed care?", response: "Trauma-informed, culturally competent, and affirming care is essential, particularly for LGBTQ+ individuals who experience higher rates of trauma and barriers to reproductive mental health services." },

  { id: 3485, category: 'introduction', keywords: ['Luna response template reproductive health'], question: "What template should Luna follow when discussing reproductive mental health?", response: "1. Clear disclaimer. 2. General education only. 3. Accurate, citable textbook information. 4. Strong redirect to professional care. 5. Offer to help with symptom tracking in CycleMind." },

  { id: 3486, category: 'introduction', keywords: ['textbook first comprehensive reproductive psychiatry'], question: "Is this the first comprehensive textbook in the field?", response: "Yes. The Introduction and preface emphasize that this is the first comprehensive textbook dedicated to women's reproductive mental health and reproductive psychiatry." },

  { id: 3487, category: 'introduction', keywords: ['CycleMind education library Introduction'], question: "How should CycleMind incorporate Introduction content into its education library?", response: "Create dedicated onboarding/education screens that explain the textbook's scope, terminology rationale, and inclusive care principles, with direct links to symptom trackers." },

  { id: 3488, category: 'introduction', keywords: ['Luna disclaimers required'], question: "What disclaimers are mandatory for Luna per the Introduction?", response: "Luna must always state she is not a physician, psychiatrist, or reproductive mental health specialist and cannot provide medical advice, diagnosis, or treatment recommendations." },

  { id: 3489, category: 'introduction', keywords: ['reproductive psychiatry future directions'], question: "What future directions for the field are implied in the Introduction?", response: "Continued expansion of data on gender-diverse populations, updated terminology, and broader integration of reproductive mental health into standard psychiatric training and practice." },

  { id: 3490, category: 'introduction', keywords: ['CycleMind Luna alignment textbook vision'], question: "How does CycleMind/Luna align with the textbook's vision?", response: "By providing practical symptom tracking tools across reproductive stages, general education grounded in the textbook, and consistent redirection to professional care — supporting the book's goal of improving reproductive mental health outcomes." },

  { id: 3491, category: 'introduction', keywords: ['editors Introduction authorship'], question: "Who are the authors of the Introduction?", response: "Lucy A. Hutner, M.D., Lisa A. Catapano, M.D., Ph.D., Erika Kelley, Ph.D., Sheryl A. Kingsberg, Ph.D., Sarah M. Nagle-Yang, M.D., Katherine E. Williams, M.D., and Lauren M. Osborne, M.D." },

  { id: 3492, category: 'introduction', keywords: ['Luna response safety netting'], question: "What safety netting language should Luna include?", response: "Luna should include phrases such as: 'For personalized assessment and treatment, please consult your psychiatrist or obstetrician. If you are experiencing a mental health emergency, contact your provider or emergency services immediately.'" },

  { id: 3493, category: 'introduction', keywords: ['textbook scope reproductive lifespan'], question: "What is the overall scope of the textbook as described in the Introduction?", response: "Comprehensive coverage of mental health across the entire female reproductive lifespan, with dedicated sections on each major transition and an emphasis on evidence-based clinical approaches." },

  { id: 3494, category: 'introduction', keywords: ['CycleMind feature ideas Introduction'], question: "What CycleMind features are directly inspired by the Introduction?", response: "Inclusive language toggle, stage-specific dashboards (menstrual, pregnancy, perimenopause), educational onboarding module explaining terminology, and seamless clinician-export functionality." },

  { id: 3495, category: 'introduction', keywords: ['textbook future editions gender inclusive'], question: "What does the Introduction say about future editions and gender-diverse populations?", response: "The editors anticipate that future editions will incorporate more comprehensive data and language for gender-diverse populations as the field advances. The current edition focuses on the best available evidence while committing to ongoing evolution of the field." },

  // === Chapter 1: Reproductive Life Cycle Overview (IDs 3496–3525) ===
  { id: 3496, category: 'chapter1', keywords: ['reproductive life cycle overview'], question: "What does Chapter 1 of the Textbook of Women's Reproductive Mental Health cover?", response: "Chapter 1 provides a comprehensive overview of the female reproductive life cycle, including menarche, menstrual cycle physiology, pregnancy, postpartum period, perimenopause, and menopause, with emphasis on hormonal changes and their intersections with mental health." },

  { id: 3497, category: 'chapter1', keywords: ['menstrual cycle physiology'], question: "What are the key physiologic stages of the menstrual cycle described in Chapter 1?", response: "The menstrual cycle includes the follicular phase (estrogen rise), ovulation, and luteal phase (progesterone dominance). These hormonal fluctuations are linked to mood, sleep, and cognitive changes that can influence mental health vulnerability." },

  { id: 3498, category: 'chapter1', keywords: ['CycleMind menstrual cycle tracking'], question: "How can CycleMind support users based on Chapter 1 menstrual cycle physiology?", response: "CycleMind can implement phase-aware tracking (follicular, ovulatory, luteal) with symptom logging to help users identify patterns in mood, sleep, and energy across the cycle." },

  { id: 3499, category: 'chapter1', keywords: ['Luna boundaries reproductive physiology'], question: "What boundaries should Luna observe when discussing reproductive physiology from Chapter 1?", response: "Luna must state she is not a medical provider and cannot interpret individual hormonal or cycle data clinically. She can share general educational information and support tracking but must redirect users to their clinician for personalized advice." },

  { id: 3500, category: 'chapter1', keywords: ['pregnancy physiologic changes'], question: "What major physiologic changes during pregnancy are highlighted in Chapter 1?", response: "Pregnancy involves dramatic increases in estrogen, progesterone, and other hormones, along with cardiovascular, immune, and neuroendocrine adaptations that can influence mental health risk." },

  { id: 3501, category: 'chapter1', keywords: ['CycleMind pregnancy mode'], question: "How should CycleMind handle pregnancy tracking per Chapter 1?", response: "CycleMind can switch to a pregnancy-specific mode that logs mood, sleep, and anxiety symptoms while providing general education on common perinatal physiologic changes and strongly encouraging professional monitoring." },

  { id: 3502, category: 'chapter1', keywords: ['postpartum reproductive changes'], question: "What postpartum physiologic changes are covered in Chapter 1?", response: "The postpartum period features rapid hormone withdrawal, lactation-related changes, and recovery of the hypothalamic-pituitary-ovarian axis, creating a window of heightened mental health vulnerability." },

  { id: 3503, category: 'chapter1', keywords: ['perimenopause physiology'], question: "How does Chapter 1 describe perimenopause?", response: "Perimenopause is characterized by irregular cycles, fluctuating estrogen and progesterone, and eventual decline leading to menopause. These changes are associated with increased risk of mood symptoms, sleep disruption, and vasomotor symptoms." },

  { id: 3504, category: 'chapter1', keywords: ['CycleMind perimenopause tracking'], question: "What perimenopause features should CycleMind include?", response: "CycleMind should offer irregular-cycle detection, VMS/sleep/mood logging, and educational content on perimenopausal hormonal transitions while always directing users to clinical evaluation." },

  { id: 3505, category: 'chapter1', keywords: ['menopause transition mental health'], question: "What mental health implications of the reproductive life cycle does Chapter 1 emphasize?", response: "Hormonal transitions across the lifespan (menstrual cycle, pregnancy, postpartum, perimenopause) are periods of increased vulnerability to mood, anxiety, and other psychiatric symptoms." },

  { id: 3506, category: 'chapter1', keywords: ['Luna response reproductive life cycle'], question: "How should Luna respond to questions about the reproductive life cycle?", response: "Luna should provide general educational summaries from Chapter 1, support CycleMind tracking tools, and always include a clear disclaimer and clinician redirect." },

  { id: 3507, category: 'chapter1', keywords: ['hormonal fluctuations mental health'], question: "What is the relationship between hormonal fluctuations and mental health per Chapter 1?", response: "Estrogen and progesterone fluctuations can modulate neurotransmitter systems (serotonin, GABA) and HPA-axis function, contributing to mood and anxiety symptom variability across reproductive stages." },

  { id: 3508, category: 'chapter1', keywords: ['CycleMind symptom correlation'], question: "How can CycleMind help users correlate symptoms with reproductive phases?", response: "CycleMind can generate visualizations and reports showing symptom patterns relative to cycle phase, pregnancy trimester, or perimenopausal stage to support user awareness and clinician discussions." },

  { id: 3509, category: 'chapter1', keywords: ['menarche reproductive life cycle'], question: "What does Chapter 1 say about menarche?", response: "Menarche marks the beginning of the reproductive lifespan with establishment of menstrual cycles and associated hormonal changes that may influence early mental health experiences." },

  { id: 3510, category: 'chapter1', keywords: ['Luna boundaries hormonal changes'], question: "What boundaries apply when Luna discusses hormonal changes from Chapter 1?", response: "Luna cannot provide individualized hormonal interpretations or medical advice. She must limit responses to general physiology education and redirect users to qualified healthcare providers." },

  { id: 3511, category: 'chapter1', keywords: ['postpartum hormone withdrawal'], question: "What postpartum changes are emphasized in Chapter 1?", response: "Rapid postpartum hormone withdrawal, especially of estrogen and progesterone, is a key physiologic event that can contribute to mood vulnerability in the perinatal period." },

  { id: 3512, category: 'chapter1', keywords: ['CycleMind life stage dashboards'], question: "What life-stage dashboards should CycleMind offer based on Chapter 1?", response: "Dedicated dashboards for menstrual cycle, pregnancy/postpartum, and perimenopause/menopause with tailored symptom trackers and educational summaries from the chapter." },

  { id: 3513, category: 'chapter1', keywords: ['reproductive lifespan overview'], question: "What is the overall structure of the reproductive life cycle in Chapter 1?", response: "The chapter traces the female reproductive lifespan from menarche through menopause, detailing endocrine physiology and its relevance to psychiatric symptoms at each transition." },

  { id: 3514, category: 'chapter1', keywords: ['Luna educational content Chapter 1'], question: "How should Luna present Chapter 1 educational content?", response: "Luna should deliver concise, accurate summaries of reproductive physiology while always pairing them with CycleMind tracking encouragement and a strong clinician redirect." },

  { id: 3515, category: 'chapter1', keywords: ['estrogen progesterone mental health'], question: "How do estrogen and progesterone influence mental health according to Chapter 1?", response: "Estrogen and progesterone modulate serotonin, GABA, and other neurotransmitter systems and influence HPA-axis reactivity, creating windows of vulnerability during hormonal shifts." },

  { id: 3516, category: 'chapter1', keywords: ['CycleMind data export Chapter 1'], question: "How can CycleMind data support clinical discussions based on Chapter 1?", response: "Users can export phase-tagged symptom data and charts to share with their psychiatrist, helping correlate symptoms with reproductive physiology as described in the chapter." },

  { id: 3517, category: 'chapter1', keywords: ['menopause physiology'], question: "What does Chapter 1 describe about menopause?", response: "Menopause is the permanent cessation of menstruation following 12 months of amenorrhea, preceded by perimenopause with fluctuating hormones and associated mental health risks." },

  { id: 3518, category: 'chapter1', keywords: ['Luna disclaimer reproductive physiology'], question: "What disclaimer must Luna include when discussing Chapter 1 content?", response: "Luna must always state: 'I am not a physician. This is general educational information from the textbook. Please consult your psychiatrist or OB/GYN for personalized medical advice.'" },

  { id: 3519, category: 'chapter1', keywords: ['reproductive transitions vulnerability'], question: "Why are reproductive transitions periods of mental health vulnerability per Chapter 1?", response: "Hormonal fluctuations, physical changes, and psychosocial stressors during reproductive transitions increase risk for mood, anxiety, and other psychiatric symptoms." },

  { id: 3520, category: 'chapter1', keywords: ['CycleMind tracking features Chapter 1'], question: "Which tracking features does Chapter 1 inspire for CycleMind?", response: "Phase-specific symptom logging, cycle irregularity detection, pregnancy/postpartum mode, perimenopause tracking, and symptom–hormone phase correlation visualizations." },

  { id: 3521, category: 'chapter1', keywords: ['Chapter 1 authors'], question: "Who authored Chapter 1 of the textbook?", response: "Alexis Lighten Wesley, M.D., Mira Zein, M.D., Melisa Olgun, B.A., and Lisa A. Catapano, M.D., Ph.D." },

  { id: 3522, category: 'chapter1', keywords: ['Luna response template Chapter 1'], question: "What is Luna's recommended response template for Chapter 1 topics?", response: "1. Disclaimer. 2. Brief accurate summary from Chapter 1. 3. Offer to log symptoms in CycleMind. 4. Strong redirect to clinician." },

  { id: 3523, category: 'chapter1', keywords: ['ovarian cycle vs uterine cycle'], question: "Does Chapter 1 distinguish ovarian and uterine cycle phases?", response: "Yes. Chapter 1 describes both the ovarian cycle (follicular, ovulatory, luteal) and corresponding uterine/endometrial changes to provide a complete physiologic picture." },

  { id: 3524, category: 'chapter1', keywords: ['CycleMind inclusive language Chapter 1'], question: "How should CycleMind apply inclusive language from the Introduction when using Chapter 1 content?", response: "All cycle and reproductive tracking features and education should use affirming, non-assumptive language that acknowledges diverse gender identities and reproductive experiences." },

  { id: 3525, category: 'chapter1', keywords: ['Chapter 1 key takeaway for app'], question: "What is the primary takeaway from Chapter 1 for CycleMind development?", response: "The reproductive life cycle provides the physiologic framework for understanding mental health vulnerabilities across stages; CycleMind should make these stages trackable and understandable while always connecting users to professional care." },

  // === Chapter 2: Gynecological Conditions and Mental Health (IDs 3526–3555) ===
  { id: 3526, category: 'chapter2', keywords: ['gynecological conditions mental health overview'], question: "What does Chapter 2 of the Textbook of Women's Reproductive Mental Health cover?", response: "Chapter 2 examines common gynecological conditions (endometriosis, PCOS, chronic pelvic pain, fibroids, genito-pelvic pain/penetration disorder) and their bidirectional relationships with mental health disorders including depression, anxiety, trauma, and substance use." },

  { id: 3527, category: 'chapter2', keywords: ['endometriosis mental health'], question: "What is the relationship between endometriosis and mental health per Chapter 2?", response: "Endometriosis is associated with higher rates of depression, anxiety, and chronic pain syndromes. Pain, infertility, and hormonal treatments contribute to psychosocial burden." },

  { id: 3528, category: 'chapter2', keywords: ['PCOS mental health'], question: "What mental health associations are discussed for polycystic ovary syndrome (PCOS)?", response: "PCOS is linked to increased risk of depression, anxiety, eating disorders, and body image distress due to androgen excess, metabolic issues, and infertility concerns." },

  { id: 3529, category: 'chapter2', keywords: ['chronic pelvic pain mental health'], question: "How does chronic pelvic pain intersect with mental health according to Chapter 2?", response: "Chronic pelvic pain frequently co-occurs with depression, anxiety, PTSD, and somatic symptom disorders. Bidirectional relationships exist between pain and psychiatric symptoms." },

  { id: 3530, category: 'chapter2', keywords: ['CycleMind gynecological comorbidity tracking'], question: "How can CycleMind support users with gynecological conditions and mental health?", response: "CycleMind can include comorbidity trackers that log pelvic pain, PCOS symptoms, or endometriosis flares alongside mood, sleep, and anxiety to help users identify patterns and share data with clinicians." },

  { id: 3531, category: 'chapter2', keywords: ['Luna boundaries gynecological conditions'], question: "What boundaries should Luna observe when discussing gynecological conditions from Chapter 2?", response: "Luna must emphasize she is not a medical provider and cannot diagnose or treat gynecological or psychiatric conditions. She can share general education and support symptom tracking but must always redirect to the user's gynecologist and psychiatrist." },

  { id: 3532, category: 'chapter2', keywords: ['fibroids mental health'], question: "What mental health considerations are noted for uterine fibroids?", response: "Uterine fibroids can cause heavy bleeding, pain, and infertility stress that contribute to depression, anxiety, and reduced quality of life." },

  { id: 3533, category: 'chapter2', keywords: ['GPPPD genito-pelvic pain penetration disorder'], question: "What is GPPPD and its mental health links per Chapter 2?", response: "Genito-pelvic pain/penetration disorder (GPPPD) involves pain with penetration and is often associated with anxiety, trauma history, and sexual dysfunction that require integrated mental health care." },

  { id: 3534, category: 'chapter2', keywords: ['CycleMind pain mood correlation'], question: "How should CycleMind handle pain-mood correlations from gynecological conditions?", response: "CycleMind can generate reports showing temporal relationships between pelvic pain flares and mood/anxiety symptoms to support clinical discussions." },

  { id: 3535, category: 'chapter2', keywords: ['hormonal treatments gynecological conditions mental health'], question: "What impact do hormonal treatments for gynecological conditions have on mental health?", response: "Hormonal therapies (e.g., GnRH agonists, progestins, combined contraceptives) used for endometriosis, PCOS, or fibroids can affect mood and require monitoring for psychiatric side effects." },

  { id: 3536, category: 'chapter2', keywords: ['Luna response template Chapter 2'], question: "What template should Luna use for Chapter 2 topics?", response: "1. Disclaimer (not a clinician). 2. General educational summary. 3. Offer CycleMind tracking for symptoms. 4. Strong redirect to gynecologist and psychiatrist." },

  { id: 3537, category: 'chapter2', keywords: ['infertility gynecological conditions'], question: "How does infertility related to gynecological conditions affect mental health?", response: "Infertility from endometriosis, PCOS, or fibroids is associated with grief, depression, anxiety, and relationship strain that warrant mental health support." },

  { id: 3538, category: 'chapter2', keywords: ['CycleMind PCOS symptom tracker'], question: "What PCOS-specific tracking should CycleMind include?", response: "CycleMind can track irregular cycles, hirsutism, acne, weight, mood, and metabolic symptoms together with menstrual mental health markers." },

  { id: 3539, category: 'chapter2', keywords: ['trauma gynecological pain'], question: "What role does trauma play in gynecological conditions per Chapter 2?", response: "History of trauma (including sexual trauma) is common in women with chronic pelvic pain and GPPPD and can exacerbate pain perception and psychiatric comorbidity." },

  { id: 3540, category: 'chapter2', keywords: ['Luna boundaries pain conditions'], question: "What boundaries apply when Luna discusses chronic pelvic pain or endometriosis?", response: "Luna cannot assess or advise on pain management. She must limit responses to general information and strongly recommend evaluation by a gynecologist and mental health professional." },

  { id: 3541, category: 'chapter2', keywords: ['Chapter 2 authors'], question: "Who authored Chapter 2?", response: "Brittney Bastow, M.D., M.Sc. and Pooja Lakshmin, M.D." },

  { id: 3542, category: 'chapter2', keywords: ['mental health screening gynecological care'], question: "What screening recommendations are implied for gynecological conditions?", response: "Routine mental health screening is recommended in women with endometriosis, PCOS, chronic pelvic pain, and other gynecological disorders due to high psychiatric comorbidity." },

  { id: 3543, category: 'chapter2', keywords: ['CycleMind comorbidity dashboard'], question: "What comorbidity dashboard feature should CycleMind include based on Chapter 2?", response: "A dedicated section showing overlapping gynecological and psychiatric symptoms with visualizations and exportable reports for shared care with providers." },

  { id: 3544, category: 'chapter2', keywords: ['sexual dysfunction gynecological conditions'], question: "How are sexual dysfunctions addressed in Chapter 2?", response: "Sexual dysfunction (including dyspareunia and GPPPD) frequently co-occurs with gynecological conditions and mental health disorders and benefits from integrated treatment." },

  { id: 3545, category: 'chapter2', keywords: ['Luna educational content Chapter 2'], question: "How should Luna present Chapter 2 educational content?", response: "Luna should deliver concise summaries of gynecological–mental health links while always encouraging professional evaluation and offering CycleMind symptom logging tools." },

  { id: 3546, category: 'chapter2', keywords: ['endometriosis depression anxiety'], question: "What specific psychiatric risks are noted for endometriosis?", response: "Women with endometriosis have elevated rates of depression and anxiety, partly mediated by chronic pain, inflammation, and infertility stress." },

  { id: 3547, category: 'chapter2', keywords: ['PCOS body image mental health'], question: "What body image and mental health issues are linked to PCOS in Chapter 2?", response: "Androgen excess symptoms (hirsutism, acne, alopecia) and metabolic changes in PCOS often lead to body image distress, disordered eating, and depression." },

  { id: 3548, category: 'chapter2', keywords: ['CycleMind export for gynecologist'], question: "How can CycleMind data support gynecological care?", response: "Users can export symptom timelines that correlate gynecological symptoms (pain, bleeding, cycle irregularity) with mood and anxiety for discussion with their gynecologist or psychiatrist." },

  { id: 3549, category: 'chapter2', keywords: ['Luna disclaimer Chapter 2'], question: "What disclaimer is mandatory for Chapter 2 topics?", response: "Luna must state: 'I am not a doctor. This is general information from the textbook. Please consult your gynecologist and psychiatrist for individualized care.'" },

  { id: 3550, category: 'chapter2', keywords: ['fibroids depression'], question: "What mental health impacts of fibroids are discussed?", response: "Heavy bleeding, pain, and pressure symptoms from fibroids can contribute to anemia-related fatigue, depression, and anxiety." },

  { id: 3551, category: 'chapter2', keywords: ['GPPPD anxiety trauma'], question: "What psychological factors are associated with GPPPD?", response: "GPPPD is frequently linked to anxiety disorders, history of sexual trauma, and hypervigilance that require trauma-informed mental health care." },

  { id: 3552, category: 'chapter2', keywords: ['CycleMind feature ideas Chapter 2'], question: "What CycleMind features are inspired by Chapter 2?", response: "Comorbidity symptom trackers for endometriosis/PCOS/pelvic pain, pain-mood correlation charts, and educational cards linking gynecological conditions with mental health." },

  { id: 3553, category: 'chapter2', keywords: ['integrated care gynecological mental health'], question: "What does Chapter 2 emphasize about integrated care?", response: "Integrated gynecological and psychiatric care is essential for women with chronic gynecological conditions due to high rates of psychiatric comorbidity and bidirectional influences." },

  { id: 3554, category: 'chapter2', keywords: ['Luna response safety netting Chapter 2'], question: "What safety netting should Luna include for Chapter 2 topics?", response: "Luna should recommend prompt evaluation for severe pain, mood changes, or suicidal thoughts and direct users to their healthcare team or emergency services when appropriate." },

  { id: 3555, category: 'chapter2', keywords: ['Chapter 2 key takeaway for app'], question: "What is the primary takeaway from Chapter 2 for CycleMind?", response: "Gynecological conditions and mental health are deeply intertwined; the app should support tracking of both domains to empower users and facilitate better interdisciplinary care." },

  // === Chapter 3: Female Sexual Dysfunctions and Reproductive Psychiatry (IDs 3556–3585) ===
  { id: 3556, category: 'chapter3', keywords: ['female sexual dysfunctions reproductive psychiatry overview'], question: "What does Chapter 3 of the Textbook of Women's Reproductive Mental Health cover?", response: "Chapter 3 explores female sexual dysfunctions (hypoactive sexual desire disorder, female sexual arousal disorder, genito-pelvic pain/penetration disorder, etc.) and their complex intersections with reproductive psychiatry, hormonal transitions, and mental health." },

  { id: 3557, category: 'chapter3', keywords: ['hypoactive sexual desire disorder HSDD'], question: "What is hypoactive sexual desire disorder (HSDD) and its reproductive psychiatry links?", response: "HSDD involves persistently low sexual desire causing distress. It is common across reproductive transitions (postpartum, perimenopause) and frequently co-occurs with depression, anxiety, and relationship strain." },

  { id: 3558, category: 'chapter3', keywords: ['female sexual arousal disorder'], question: "What is female sexual arousal disorder and its mental health associations?", response: "Female sexual arousal disorder involves difficulty with physiological or subjective arousal. It is linked to hormonal changes, medications, depression, anxiety, and trauma history." },

  { id: 3559, category: 'chapter3', keywords: ['GPPPD genito-pelvic pain penetration disorder'], question: "How does Chapter 3 discuss genito-pelvic pain/penetration disorder (GPPPD)?", response: "GPPPD encompasses dyspareunia and vaginismus. It is often intertwined with anxiety, PTSD, and gynecological conditions and benefits from integrated psychiatric and gynecologic care." },

  { id: 3560, category: 'chapter3', keywords: ['CycleMind sexual health tracking'], question: "How can CycleMind support users with sexual dysfunction concerns from Chapter 3?", response: "CycleMind can include optional, private sexual function tracking tied to cycle phase, pregnancy, or perimenopause to help users identify patterns and share anonymized data with clinicians." },

  { id: 3561, category: 'chapter3', keywords: ['Luna boundaries sexual dysfunction'], question: "What boundaries should Luna observe when discussing sexual dysfunctions from Chapter 3?", response: "Luna must clearly state she is not a clinician and cannot diagnose or treat sexual dysfunctions. She can provide general education from the textbook and support private tracking but must redirect to a qualified psychiatrist, gynecologist, or sexual medicine specialist." },

  { id: 3562, category: 'chapter3', keywords: ['hormonal factors sexual function'], question: "What hormonal factors affecting sexual function are covered in Chapter 3?", response: "Estrogen, progesterone, testosterone, and oxytocin fluctuations across reproductive stages (postpartum, perimenopause, contraceptive use) significantly influence sexual desire, arousal, and pain." },

  { id: 3563, category: 'chapter3', keywords: ['postpartum sexual dysfunction'], question: "What postpartum sexual changes are highlighted?", response: "Postpartum period commonly involves decreased desire, arousal difficulties, and pain due to hormonal withdrawal, fatigue, breastfeeding, and body image changes." },

  { id: 3564, category: 'chapter3', keywords: ['perimenopause sexual function'], question: "How does perimenopause affect sexual function per Chapter 3?", response: "Perimenopause is associated with declining estrogen leading to vaginal dryness, dyspareunia, and reduced desire. These changes often interact with mood symptoms and relationship factors." },

  { id: 3565, category: 'chapter3', keywords: ['CycleMind reproductive stage sexual health'], question: "What stage-specific sexual health tracking should CycleMind offer?", response: "Optional modules for menstrual cycle, pregnancy/postpartum, and perimenopause that allow users to log desire, arousal, pain, and satisfaction alongside mood and sleep." },

  { id: 3566, category: 'chapter3', keywords: ['trauma sexual dysfunction'], question: "What role does trauma play in female sexual dysfunctions?", response: "History of sexual trauma is a major risk factor for GPPPD, low desire, and arousal disorders and requires trauma-informed, sensitive care." },

  { id: 3567, category: 'chapter3', keywords: ['Luna response template Chapter 3'], question: "What template should Luna follow for Chapter 3 topics?", response: "1. Clear disclaimer. 2. General educational summary. 3. Offer private CycleMind tracking option. 4. Strong redirect to appropriate specialists." },

  { id: 3568, category: 'chapter3', keywords: ['medications sexual side effects'], question: "How do psychiatric medications affect sexual function per Chapter 3?", response: "Antidepressants (especially SSRIs), antipsychotics, and other psychotropics can cause sexual side effects including decreased desire, arousal difficulties, and orgasm problems." },

  { id: 3569, category: 'chapter3', keywords: ['CycleMind medication sexual health log'], question: "Should CycleMind include medication-related sexual health tracking?", response: "Optional, private logging of sexual function changes in relation to psychotropic medications can help users prepare informed discussions with their psychiatrist." },

  { id: 3570, category: 'chapter3', keywords: ['Chapter 3 authors'], question: "Who authored Chapter 3?", response: "Erika Kelley, Ph.D., Brittney Bastow, M.D., M.Sc., Pooja Lakshmin, M.D., and Sheryl A. Kingsberg, Ph.D." },

  { id: 3571, category: 'chapter3', keywords: ['integrated treatment sexual dysfunction'], question: "What does Chapter 3 recommend for treatment of sexual dysfunctions?", response: "Integrated biopsychosocial approaches combining gynecologic, psychiatric, and sex therapy interventions are most effective, especially when reproductive transitions are involved." },

  { id: 3572, category: 'chapter3', keywords: ['Luna disclaimer sexual health'], question: "What disclaimer is required for sexual health topics from Chapter 3?", response: "Luna must state she is not a sexual medicine specialist or therapist and cannot provide treatment recommendations. Users should consult qualified professionals." },

  { id: 3573, category: 'chapter3', keywords: ['contraception sexual function'], question: "How does contraception affect sexual function per Chapter 3?", response: "Hormonal contraceptives can have variable effects on desire and arousal; some women experience improvement while others report worsening, requiring individualized discussion." },

  { id: 3574, category: 'chapter3', keywords: ['CycleMind privacy sexual tracking'], question: "How does CycleMind ensure privacy for sexual health tracking?", response: "Sexual function logs are optional, password-protected, and never shared without explicit user consent. Data can be exported privately for clinician discussions." },

  { id: 3575, category: 'chapter3', keywords: ['body image sexual dysfunction'], question: "What role does body image play in reproductive psychiatry sexual dysfunctions?", response: "Body image concerns during pregnancy, postpartum, and perimenopause frequently contribute to sexual avoidance, low desire, and distress." },

  { id: 3576, category: 'chapter3', keywords: ['Luna educational content Chapter 3'], question: "How should Luna present Chapter 3 content?", response: "Luna should deliver concise, destigmatizing education on sexual function across reproductive stages while always emphasizing professional evaluation and offering CycleMind tracking tools." },

  { id: 3577, category: 'chapter3', keywords: ['relationship factors sexual function'], question: "How do relationship factors intersect with sexual dysfunctions?", response: "Partner dynamics, communication, and relationship satisfaction significantly influence sexual function and are important targets in reproductive psychiatry." },

  { id: 3578, category: 'chapter3', keywords: ['CycleMind feature ideas Chapter 3'], question: "What CycleMind features are inspired by Chapter 3?", response: "Private sexual wellness tracker (optional), reproductive-stage-specific sexual health education cards, and symptom correlation between sexual function, mood, and cycle phase." },

  { id: 3579, category: 'chapter3', keywords: ['postpartum sexual recovery'], question: "What does Chapter 3 say about postpartum sexual recovery?", response: "Postpartum sexual recovery is highly variable and influenced by hormonal changes, fatigue, body image, breastfeeding, and relationship factors; open discussion with providers is encouraged." },

  { id: 3580, category: 'chapter3', keywords: ['perimenopause sexual dysfunction'], question: "How does Chapter 3 address sexual dysfunction in perimenopause?", response: "Declining estrogen often leads to vaginal atrophy, dryness, and dyspareunia; these physical changes frequently interact with mood symptoms and require holistic care." },

  { id: 3581, category: 'chapter3', keywords: ['Luna safety netting sexual health'], question: "What safety netting should Luna include for Chapter 3 topics?", response: "Luna should recommend prompt professional evaluation for persistent distress, pain, or sudden changes in sexual function or mood." },

  { id: 3582, category: 'chapter3', keywords: ['integrated reproductive psychiatry sexual health'], question: "What is the core message of Chapter 3?", response: "Sexual health is an integral part of reproductive psychiatry; dysfunctions must be assessed and addressed within the context of hormonal transitions and mental health." },

  { id: 3583, category: 'chapter3', keywords: ['CycleMind education library Chapter 3'], question: "How should CycleMind incorporate Chapter 3 into its education library?", response: "Create destigmatizing, evidence-based cards on common sexual dysfunctions across reproductive stages, with clear statements that professional care is essential." },

  { id: 3584, category: 'chapter3', keywords: ['Chapter 3 key takeaway for app'], question: "What is the primary takeaway from Chapter 3 for CycleMind development?", response: "Sexual function is deeply connected to reproductive transitions and mental health; the app should offer optional, private, respectful tracking tools while maintaining strict clinical boundaries." },

  { id: 3585, category: 'chapter3', keywords: ['Luna response boundaries Chapter 3'], question: "What overarching boundaries apply to Luna for Chapter 3 content?", response: "Luna must never provide sexual therapy, diagnose dysfunctions, or recommend treatments. All responses must remain educational and include a clear redirect to qualified specialists." },

  // === Chapter 4: Contraception and Mental Health (IDs 3586–3615) ===
  { id: 3586, category: 'chapter4', keywords: ['contraception mental health overview'], question: "What does Chapter 4 of the Textbook of Women's Reproductive Mental Health cover?", response: "Chapter 4 reviews all major contraceptive methods (combined hormonal, progestin-only, intrauterine devices, implants, barriers, sterilization) and their potential psychiatric effects, with special attention to mood, PMDD, and decision-making in women with mental health conditions." },

  { id: 3587, category: 'chapter4', keywords: ['combined hormonal contraception mood effects'], question: "What are the mental health implications of combined hormonal contraceptives?", response: "Combined estrogen-progestin contraceptives can have variable mood effects. Some women experience improvement in PMDD symptoms while others report mood worsening, depression, or anxiety. Individual response is highly variable." },

  { id: 3588, category: 'chapter4', keywords: ['progestin-only contraception mental health'], question: "What psychiatric considerations exist for progestin-only methods?", response: "Progestin-only pills, implants, injections, and hormonal IUDs may be associated with mood changes in some women, though evidence is mixed. They are often considered when estrogen is contraindicated." },

  { id: 3589, category: 'chapter4', keywords: ['contraception PMDD'], question: "How does Chapter 4 address contraception in women with PMDD?", response: "Continuous combined hormonal contraception with drospirenone is often beneficial for PMDD. Luteal-phase symptom tracking helps guide contraceptive choice in women with premenstrual mood syndromes." },

  { id: 3590, category: 'chapter4', keywords: ['CycleMind contraception mood tracking'], question: "How can CycleMind support users starting or changing contraception?", response: "CycleMind can include optional mood and symptom tracking before and after starting contraception to help users identify personal response patterns and share data with their psychiatrist." },

  { id: 3591, category: 'chapter4', keywords: ['Luna boundaries contraception'], question: "What boundaries should Luna observe when discussing contraception from Chapter 4?", response: "Luna must state she is not a prescribing clinician and cannot recommend contraceptive methods. She can provide general educational information from the textbook and support symptom tracking but must redirect all decisions to the user's psychiatrist and gynecologist." },

  { id: 3592, category: 'chapter4', keywords: ['copper IUD mental health'], question: "What mental health considerations apply to the copper IUD?", response: "The non-hormonal copper IUD has no systemic hormonal effects and is often preferred when hormonal methods exacerbate mood symptoms." },

  { id: 3593, category: 'chapter4', keywords: ['levonorgestrel IUD mood effects'], question: "What psychiatric effects are associated with the levonorgestrel IUD?", response: "The hormonal IUD releases progestin locally with minimal systemic absorption; mood effects are generally lower than oral methods but should still be monitored in sensitive individuals." },

  { id: 3594, category: 'chapter4', keywords: ['contraception bipolar disorder'], question: "What contraception guidance is given for women with bipolar disorder?", response: "Mood-stabilizing effects of certain contraceptives may be beneficial, but enzyme-inducing medications can reduce contraceptive efficacy. Close collaboration between psychiatry and gynecology is essential." },

  { id: 3595, category: 'chapter4', keywords: ['CycleMind contraceptive log'], question: "What contraceptive tracking feature should CycleMind include?", response: "An optional, private contraceptive method log that correlates start dates, method type, and daily mood/sleep symptoms to support informed discussions with providers." },

  { id: 3596, category: 'chapter4', keywords: ['emergency contraception mental health'], question: "Does Chapter 4 discuss emergency contraception?", response: "Emergency contraception (levonorgestrel or ulipristal) has minimal psychiatric impact due to short-term use, but follow-up contraceptive counseling is important." },

  { id: 3597, category: 'chapter4', keywords: ['Luna response template Chapter 4'], question: "What template should Luna use for contraception questions?", response: "1. Clear disclaimer. 2. General educational summary from Chapter 4. 3. Offer CycleMind tracking. 4. Strong redirect to psychiatrist and gynecologist for personalized contraceptive decisions." },

  { id: 3598, category: 'chapter4', keywords: ['sterilization mental health'], question: "What mental health considerations apply to permanent sterilization?", response: "Decision-making for tubal ligation or vasectomy should include thorough discussion of regret risk, especially in women with mood disorders or history of trauma." },

  { id: 3599, category: 'chapter4', keywords: ['barrier methods mental health'], question: "How do barrier methods relate to mental health in Chapter 4?", response: "Barrier methods (condoms, diaphragms) have no hormonal effects and can be preferred when psychiatric stability is the priority or hormonal methods are contraindicated." },

  { id: 3600, category: 'chapter4', keywords: ['Chapter 4 author'], question: "Who authored Chapter 4?", response: "Lulu Zhao, M.D." },

  { id: 3601, category: 'chapter4', keywords: ['contraception depression risk'], question: "What does Chapter 4 say about contraception and depression risk?", response: "Large population studies show small increased risk of depression with hormonal contraception in some subgroups, but many women experience mood stability or improvement. Individual monitoring is recommended." },

  { id: 3602, category: 'chapter4', keywords: ['CycleMind PMDD contraception tracking'], question: "How can CycleMind help women with PMDD choose contraception?", response: "CycleMind can track luteal-phase symptoms before and after starting a contraceptive method to provide objective data for shared decision-making with the treatment team." },

  { id: 3603, category: 'chapter4', keywords: ['Luna disclaimer contraception'], question: "What disclaimer is mandatory for Chapter 4 topics?", response: "Luna must state she is not a physician and cannot prescribe or recommend contraception. All contraceptive decisions require discussion with a qualified medical provider." },

  { id: 3604, category: 'chapter4', keywords: ['contraceptive counseling reproductive psychiatry'], question: "What is the role of reproductive psychiatrists in contraceptive counseling?", response: "Reproductive psychiatrists help weigh psychiatric risks and benefits of contraceptive methods and coordinate care with gynecologists." },

  { id: 3605, category: 'chapter4', keywords: ['CycleMind feature ideas Chapter 4'], question: "What CycleMind features are inspired by Chapter 4?", response: "Contraceptive method log with mood correlation charts, PMDD-specific tracking around contraceptive changes, and educational cards on hormonal vs. non-hormonal options." },

  { id: 3606, category: 'chapter4', keywords: ['progestin implant mental health'], question: "What mental health considerations apply to the etonogestrel implant?", response: "The subdermal progestin implant may cause irregular bleeding and mood changes in some users; monitoring and early removal options should be discussed." },

  { id: 3607, category: 'chapter4', keywords: ['Luna educational content Chapter 4'], question: "How should Luna present Chapter 4 content?", response: "Luna should provide neutral, evidence-based summaries of contraceptive-mental health interactions while always directing users to their treatment team for individualized decisions." },

  { id: 3608, category: 'chapter4', keywords: ['contraception schizophrenia'], question: "What contraception considerations exist for women with schizophrenia?", response: "Antipsychotic medications may interact with hormonal contraceptives; long-acting reversible methods are often preferred due to adherence challenges and medication interactions." },

  { id: 3609, category: 'chapter4', keywords: ['CycleMind data export contraception'], question: "How can CycleMind data support contraceptive decision-making?", response: "Users can export mood and symptom timelines before and after contraceptive initiation to facilitate evidence-based discussions with their psychiatrist and gynecologist." },

  { id: 3610, category: 'chapter4', keywords: ['non-hormonal contraception benefits'], question: "What benefits of non-hormonal contraception are highlighted?", response: "Non-hormonal methods eliminate systemic hormonal exposure and are preferred by many women with mood disorders or hormone sensitivity." },

  { id: 3611, category: 'chapter4', keywords: ['Luna safety netting contraception'], question: "What safety netting should Luna include?", response: "Luna should advise users to contact their provider immediately for severe mood changes, breakthrough bleeding concerns, or questions about contraceptive efficacy with psychiatric medications." },

  { id: 3612, category: 'chapter4', keywords: ['integrated contraceptive psychiatric care'], question: "What is the core message of Chapter 4?", response: "Contraceptive choice in women with psychiatric illness requires individualized, collaborative care between reproductive psychiatrists and gynecologists." },

  { id: 3613, category: 'chapter4', keywords: ['Chapter 4 key takeaway for app'], question: "What is the primary takeaway from Chapter 4 for CycleMind?", response: "Contraception can significantly affect mental health; the app should support objective tracking of symptoms around contraceptive changes while maintaining strict clinical boundaries." },

  { id: 3614, category: 'chapter4', keywords: ['Luna response boundaries Chapter 4'], question: "What overarching boundaries apply to Luna for Chapter 4 content?", response: "Luna must never advise on contraceptive selection or discontinuation. All responses remain educational and end with a redirect to qualified medical providers." },

  { id: 3615, category: 'chapter4', keywords: ['CycleMind contraception education'], question: "How should CycleMind incorporate Chapter 4 into its education library?", response: "Create clear, non-directive educational modules on contraception-mental health interactions with emphasis on shared decision-making and professional guidance." },

  // === Chapter 5: Infertility and Perinatal Loss (IDs 3616–3645) ===
  { id: 3616, category: 'chapter5', keywords: ['infertility perinatal loss overview'], question: "What does Chapter 5 of the Textbook of Women's Reproductive Mental Health cover?", response: "Chapter 5 addresses the psychiatric impact of infertility, pregnancy loss (miscarriage, stillbirth, ectopic pregnancy, termination), and perinatal bereavement, including grief reactions, depression, anxiety, PTSD, and treatment considerations across the reproductive lifespan." },

  { id: 3617, category: 'chapter5', keywords: ['infertility mental health'], question: "What mental health risks are associated with infertility?", response: "Infertility is linked to elevated rates of depression, anxiety, grief, and relationship strain. The chronic stress of treatment and uncertainty can exacerbate preexisting psychiatric conditions." },

  { id: 3618, category: 'chapter5', keywords: ['perinatal loss grief'], question: "How does Chapter 5 describe grief after perinatal loss?", response: "Perinatal loss triggers intense grief that may include complicated grief, depression, anxiety, and PTSD symptoms. The grief is often disenfranchised and requires validation and support." },

  { id: 3619, category: 'chapter5', keywords: ['miscarriage mental health'], question: "What psychiatric sequelae follow miscarriage?", response: "Miscarriage is associated with increased risk of depression, anxiety, and PTSD. Risk is higher with recurrent losses or history of mood disorders." },

  { id: 3620, category: 'chapter5', keywords: ['CycleMind infertility tracking'], question: "How can CycleMind support users experiencing infertility?", response: "CycleMind can offer optional mood, grief, and treatment-cycle tracking to help users monitor emotional patterns during fertility treatments and share data with their reproductive psychiatrist." },

  { id: 3621, category: 'chapter5', keywords: ['Luna boundaries perinatal loss'], question: "What boundaries should Luna observe when discussing infertility or perinatal loss?", response: "Luna must clearly state she is not a grief counselor or psychiatrist and cannot provide therapy. She can share general educational information and support tracking but must strongly redirect users to qualified mental health professionals and support groups." },

  { id: 3622, category: 'chapter5', keywords: ['stillbirth mental health'], question: "What mental health impact does stillbirth have?", response: "Stillbirth carries particularly high risk of complicated grief, depression, anxiety, and PTSD. Subsequent pregnancies often involve intense anxiety and hypervigilance." },

  { id: 3623, category: 'chapter5', keywords: ['termination of pregnancy mental health'], question: "How does Chapter 5 address mental health after pregnancy termination?", response: "Mental health outcomes after termination are highly individual. Risk factors include preexisting psychiatric illness, coercion, or lack of social support. Most women do not experience long-term regret." },

  { id: 3624, category: 'chapter5', keywords: ['CycleMind perinatal loss tracker'], question: "What tracking features should CycleMind include for perinatal loss?", response: "Optional, sensitive grief and mood tracking modules with gentle prompts and resources, allowing users to log emotions over time and generate reports for their clinician." },

  { id: 3625, category: 'chapter5', keywords: ['infertility treatment psychiatric effects'], question: "What psychiatric effects are associated with infertility treatments?", response: "Hormonal stimulation (e.g., gonadotropins) can cause mood lability, anxiety, and depression. The emotional rollercoaster of IVF cycles increases stress and requires psychiatric support." },

  { id: 3626, category: 'chapter5', keywords: ['Luna response template Chapter 5'], question: "What template should Luna use for Chapter 5 topics?", response: "1. Clear disclaimer. 2. General educational summary. 3. Offer CycleMind tracking option. 4. Strong redirect to perinatal psychiatrist, grief counselor, or support organizations." },

  { id: 3627, category: 'chapter5', keywords: ['complicated grief perinatal loss'], question: "What is complicated grief after perinatal loss?", response: "Complicated grief involves prolonged, intense yearning, disbelief, bitterness, or functional impairment beyond expected bereavement and may require specific therapeutic intervention." },

  { id: 3628, category: 'chapter5', keywords: ['CycleMind support resources Chapter 5'], question: "How should CycleMind incorporate support resources from Chapter 5?", response: "Include curated, vetted links to perinatal loss support organizations, grief resources, and professional referral pathways alongside tracking tools." },

  { id: 3629, category: 'chapter5', keywords: ['PTSD after perinatal loss'], question: "Is PTSD discussed in relation to perinatal loss?", response: "Yes. Traumatic perinatal loss (stillbirth, emergency procedures) can trigger PTSD symptoms including intrusive memories, avoidance, hyperarousal, and negative alterations in cognition and mood." },

  { id: 3630, category: 'chapter5', keywords: ['Luna disclaimer perinatal loss'], question: "What disclaimer is required for Chapter 5 topics?", response: "Luna must state she is not a therapist or grief counselor and cannot provide counseling or treatment. Users should seek professional mental health support." },

  { id: 3631, category: 'chapter5', keywords: ['subsequent pregnancy after loss'], question: "What mental health challenges occur in pregnancies after loss?", response: "Subsequent pregnancies after perinatal loss are often marked by heightened anxiety, hypervigilance, and fear of recurrence that benefit from specialized perinatal psychiatric care." },

  { id: 3632, category: 'chapter5', keywords: ['Chapter 5 authors'], question: "Who authored Chapter 5?", response: "Neha S. Hudepohl, M.D., Jessica L. Coker, M.D., Sharvari P. Shivanekar, M.D., Madhavi-Latha Nagalla, M.D., Soudabeh Givrad, M.D., Lindsay R. Standeven, M.D., Courtney Erdly, B.A., Premala Jones, Ph.D., and Katherine E. Williams, M.D." },

  { id: 3633, category: 'chapter5', keywords: ['infertility depression anxiety'], question: "What is the prevalence of depression and anxiety in infertility?", response: "Rates of depression and anxiety are significantly elevated in individuals undergoing infertility treatment compared with the general population." },

  { id: 3634, category: 'chapter5', keywords: ['CycleMind grief mood correlation'], question: "How can CycleMind help with grief and mood correlation?", response: "CycleMind can visualize mood and grief intensity over time during infertility treatment or after loss to help users recognize patterns and prepare for clinical appointments." },

  { id: 3635, category: 'chapter5', keywords: ['Luna educational content Chapter 5'], question: "How should Luna present Chapter 5 content?", response: "Luna should deliver compassionate, destigmatizing education on infertility and perinatal loss while always pairing it with offers to track symptoms and strong clinician referrals." },

  { id: 3636, category: 'chapter5', keywords: ['partner support perinatal loss'], question: "Does Chapter 5 address partner experiences?", response: "Yes. Partners also experience grief, depression, and anxiety after perinatal loss and may have different coping styles that require acknowledgment in couple-based care." },

  { id: 3637, category: 'chapter5', keywords: ['CycleMind feature ideas Chapter 5'], question: "What CycleMind features are inspired by Chapter 5?", response: "Gentle grief tracking, infertility treatment cycle logging, mood/grief correlation charts, and resource links—all optional and privacy-protected." },

  { id: 3638, category: 'chapter5', keywords: ['ectopic pregnancy mental health'], question: "What psychiatric impact is associated with ectopic pregnancy?", response: "Ectopic pregnancy involves both medical emergency and pregnancy loss, often triggering acute stress, grief, and anxiety about future fertility." },

  { id: 3639, category: 'chapter5', keywords: ['Luna safety netting Chapter 5'], question: "What safety netting should Luna include for Chapter 5 topics?", response: "Luna should recommend immediate professional support for severe grief, suicidal thoughts, or functional impairment and provide crisis resource information." },

  { id: 3640, category: 'chapter5', keywords: ['integrated care infertility loss'], question: "What does Chapter 5 emphasize about care?", response: "Integrated psychiatric and reproductive care is essential for individuals and couples experiencing infertility and perinatal loss." },

  { id: 3641, category: 'chapter5', keywords: ['Chapter 5 key takeaway for app'], question: "What is the primary takeaway from Chapter 5 for CycleMind?", response: "Infertility and perinatal loss are profound psychological experiences; the app should offer respectful, optional tracking and education while always directing users to professional support." },

  { id: 3642, category: 'chapter5', keywords: ['Luna response boundaries Chapter 5'], question: "What overarching boundaries apply to Luna for Chapter 5 content?", response: "Luna must never provide grief counseling or interpret loss experiences clinically. All responses remain general education and end with a clear redirect to qualified mental health professionals." },

  { id: 3643, category: 'chapter5', keywords: ['recurrent pregnancy loss mental health'], question: "What mental health risks are associated with recurrent pregnancy loss?", response: "Recurrent losses compound grief and increase risk of depression, anxiety, and PTSD; specialized support is often needed." },

  { id: 3644, category: 'chapter5', keywords: ['CycleMind data export Chapter 5'], question: "How can CycleMind data support clinical care for infertility or loss?", response: "Users can export mood, grief, and treatment timelines to share with their reproductive psychiatrist or perinatal mental health specialist." },

  { id: 3645, category: 'chapter5', keywords: ['perinatal loss stigma'], question: "Does Chapter 5 address stigma around perinatal loss?", response: "Yes. Societal and cultural stigma often leads to disenfranchised grief; validation and open discussion are important components of recovery." },

  // === Chapter 6: Premenstrual Mood Syndromes and PMDD (IDs 3646–3675) ===
  { id: 3646, category: 'chapter6', keywords: ['PMDD premenstrual mood syndromes overview'], question: "What does Chapter 6 of the Textbook of Women's Reproductive Mental Health cover?", response: "Chapter 6 provides a comprehensive review of premenstrual mood syndromes with a primary focus on Premenstrual Dysphoric Disorder (PMDD), including DSM-5 criteria, epidemiology, pathophysiology, screening, diagnosis, differential diagnosis, and evidence-based treatments." },

  { id: 3647, category: 'chapter6', keywords: ['DSM-5 PMDD criteria'], question: "What are the DSM-5 diagnostic criteria for PMDD as described in Chapter 6?", response: "PMDD requires at least five symptoms (including at least one core mood symptom) in the final week before menses, improving within days after menses onset, and minimal or absent in the week post-menses, confirmed by prospective charting over at least two cycles." },

  { id: 3648, category: 'chapter6', keywords: ['DRSP Daily Record of Severity of Problems'], question: "What is the DRSP and how is it used for PMDD diagnosis?", response: "The Daily Record of Severity of Problems (DRSP) is the gold-standard 21-item prospective daily rating scale. Chapter 6 emphasizes that prospective charting with the DRSP for at least one (ideally two) menstrual cycles is required to confirm the diagnosis." },

  { id: 3649, category: 'chapter6', keywords: ['CycleMind digital DRSP'], question: "How can CycleMind implement the DRSP from Chapter 6?", response: "CycleMind can include a full digital DRSP form with daily ratings, automatic luteal-phase highlighting, severity scoring, and exportable charts that meet the prospective charting requirement for clinical diagnosis." },

  { id: 3650, category: 'chapter6', keywords: ['PMDD prevalence'], question: "What is the prevalence of PMDD per Chapter 6?", response: "PMDD affects approximately 5–8% of menstruating individuals. Prevalence is consistent across cultures but underdiagnosed due to the requirement for prospective charting." },

  { id: 3651, category: 'chapter6', keywords: ['PMDD pathophysiology'], question: "What is the pathophysiology of PMDD discussed in Chapter 6?", response: "PMDD involves abnormal sensitivity to normal luteal-phase fluctuations in estrogen and progesterone, particularly allopregnanolone effects on GABA-A receptors, along with serotonin dysregulation." },

  { id: 3652, category: 'chapter6', keywords: ['Luna boundaries PMDD diagnosis'], question: "What boundaries should Luna observe regarding PMDD diagnosis from Chapter 6?", response: "Luna must never diagnose PMDD. She can explain the diagnostic process (prospective DRSP charting) and support tracking but must always state that only a qualified clinician can make the diagnosis." },

  { id: 3653, category: 'chapter6', keywords: ['luteal phase SSRI PMDD'], question: "What is the first-line pharmacologic treatment for PMDD?", response: "Luteal-phase dosing of SSRIs (e.g., sertraline, fluoxetine) is first-line and highly effective for core mood symptoms. Continuous dosing is also an option for some patients." },

  { id: 3654, category: 'chapter6', keywords: ['drospirenone OCP PMDD'], question: "What hormonal contraceptive is recommended for PMDD?", response: "Combined oral contraceptives containing drospirenone (especially continuous or extended-cycle regimens) are effective for many women with PMDD and are supported by strong evidence." },

  { id: 3655, category: 'chapter6', keywords: ['CycleMind luteal phase alerts'], question: "How should CycleMind support PMDD management?", response: "CycleMind can provide luteal-phase alerts, automated DRSP prompts, symptom pattern visualizations, and educational cards on evidence-based treatments (SSRIs, drospirenone OCPs, CBT) while always redirecting treatment decisions to clinicians." },

  { id: 3656, category: 'chapter6', keywords: ['PMDD vs PME'], question: "How does Chapter 6 differentiate PMDD from premenstrual exacerbation (PME)?", response: "PMDD requires symptoms to be absent or minimal in the follicular phase. PME involves worsening of an underlying mood disorder premenstrually but with symptoms present throughout the cycle." },

  { id: 3657, category: 'chapter6', keywords: ['CBT PMDD'], question: "What non-pharmacologic treatments are discussed for PMDD?", response: "Cognitive-behavioral therapy (CBT) has promising evidence for PMDD. Lifestyle interventions, calcium, vitamin B6, and exercise are also reviewed as adjunctive options." },

  { id: 3658, category: 'chapter6', keywords: ['PMDD screening tools'], question: "What screening tools are recommended in Chapter 6?", response: "The DRSP is the gold standard. Other tools include the Premenstrual Symptoms Screening Tool (PSST) and Calendar of Premenstrual Experiences (COPE) for initial screening before prospective charting." },

  { id: 3659, category: 'chapter6', keywords: ['Luna response template PMDD'], question: "What template should Luna use for PMDD questions?", response: "1. Disclaimer (not a clinician). 2. Explain diagnostic process and general education. 3. Offer digital DRSP tracking in CycleMind. 4. Strongly redirect to psychiatrist for diagnosis and treatment." },

  { id: 3660, category: 'chapter6', keywords: ['PMDD perimenopause'], question: "Does PMDD persist into perimenopause per Chapter 6?", response: "Yes. PMDD symptoms can continue or worsen during the perimenopausal transition due to increasingly erratic hormonal fluctuations." },

  { id: 3661, category: 'chapter6', keywords: ['Chapter 6 authors'], question: "Who authored Chapter 6?", response: "Erin Murphy Barzilay, M.D., Katherine Unverferth, M.D., and Laura Obler, M.D." },

  { id: 3662, category: 'chapter6', keywords: ['PMDD risk factors'], question: "What risk factors for PMDD are covered?", response: "Genetic vulnerability, history of trauma, prior mood disorders, and sensitivity to neuroactive steroids (allopregnanolone) are key risk factors." },

  { id: 3663, category: 'chapter6', keywords: ['CycleMind PMDD education'], question: "How should CycleMind incorporate Chapter 6 education?", response: "Create clear, evidence-based education cards on PMDD diagnosis (DRSP requirement), treatments, and differentiation from PME, with direct links to the digital DRSP tracker." },

  { id: 3664, category: 'chapter6', keywords: ['PMDD comorbidities'], question: "What comorbidities are common with PMDD?", response: "PMDD frequently co-occurs with major depression, bipolar disorder, anxiety disorders, and PTSD. Prospective charting is essential to distinguish primary PMDD from exacerbation of these conditions." },

  { id: 3665, category: 'chapter6', keywords: ['Luna disclaimer PMDD'], question: "What disclaimer is required for PMDD topics?", response: "Luna must state: 'I am not a psychiatrist and cannot diagnose or treat PMDD. This is general information. Please consult your clinician for prospective charting and treatment planning.'" },

  { id: 3666, category: 'chapter6', keywords: ['GnRH agonists PMDD'], question: "Are GnRH agonists discussed for PMDD?", response: "GnRH agonists can be used in severe, refractory PMDD to suppress ovulation but require add-back hormone therapy and are not first-line due to side effects." },

  { id: 3667, category: 'chapter6', keywords: ['CycleMind PMDD diagnostic support'], question: "How does CycleMind support PMDD diagnosis per Chapter 6?", response: "CycleMind can automate the prospective DRSP process, calculate luteal vs. follicular symptom ratios, and generate clinician-ready reports to meet DSM-5 diagnostic standards." },

  { id: 3668, category: 'chapter6', keywords: ['PMDD treatment resistance'], question: "What is discussed for treatment-resistant PMDD?", response: "For treatment-resistant cases, options include switching SSRIs, adding CBT, hormonal suppression, or referral to a reproductive psychiatrist. Surgical options (oophorectomy) are last resort." },

  { id: 3669, category: 'chapter6', keywords: ['Luna safety netting PMDD'], question: "What safety netting should Luna include for PMDD?", response: "Luna should advise users experiencing severe premenstrual suicidality, functional impairment, or worsening symptoms to contact their psychiatrist or seek emergency care immediately." },

  { id: 3670, category: 'chapter6', keywords: ['PMDD adolescents'], question: "Does Chapter 6 address PMDD in adolescents?", response: "Yes. PMDD can begin after menarche. Diagnosis requires the same prospective charting standards, and treatment must consider developmental stage and contraceptive needs." },

  { id: 3671, category: 'chapter6', keywords: ['CycleMind feature ideas Chapter 6'], question: "What CycleMind features are directly inspired by Chapter 6?", response: "Full digital DRSP implementation, luteal-phase symptom alerts, PMDD education library, treatment response tracking, and clinician-export reports." },

  { id: 3672, category: 'chapter6', keywords: ['serotonin allopregnanolone PMDD'], question: "What neurotransmitter and neurosteroid mechanisms are discussed?", response: "Dysregulated serotonin transmission and abnormal sensitivity to allopregnanolone (a progesterone metabolite) in the luteal phase are central to PMDD pathophysiology." },

  { id: 3673, category: 'chapter6', keywords: ['Chapter 6 key takeaway for app'], question: "What is the primary takeaway from Chapter 6 for CycleMind?", response: "Accurate PMDD diagnosis requires prospective daily charting with the DRSP; CycleMind should make this process easy, accurate, and clinically useful while maintaining strict boundaries." },

  { id: 3674, category: 'chapter6', keywords: ['Luna response boundaries Chapter 6'], question: "What overarching boundaries apply to Luna for PMDD content?", response: "Luna must never diagnose PMDD, interpret DRSP scores clinically, or recommend specific treatments. All responses must remain educational and end with a clinician redirect." },

  { id: 3675, category: 'chapter6', keywords: ['PMDD lifetime course'], question: "What is the lifetime course of PMDD per Chapter 6?", response: "PMDD typically begins in the early 20s, persists until menopause, and may worsen during perimenopause. Symptoms remit after menopause or with ovulation suppression." },

  // === Chapter 7: Perimenopause and Mental Health (IDs 3676–3705) ===
  { id: 3676, category: 'chapter7', keywords: ['perimenopause overview'], question: "What does Chapter 7 of the Textbook of Women's Reproductive Mental Health cover?", response: "Chapter 7 reviews the physiology of perimenopause, increased risk of new-onset and recurrent depression/anxiety, vasomotor symptoms (VMS), sleep disruption, cognitive changes, sexual dysfunction, and evidence-based treatments." },

  { id: 3677, category: 'chapter7', keywords: ['perimenopausal depression risk'], question: "What is the risk of depression during perimenopause?", response: "Women in perimenopause have a 2–4-fold increased risk of new-onset major depressive episodes compared with premenopause, even after adjusting for other risk factors." },

  { id: 3678, category: 'chapter7', keywords: ['vasomotor symptoms VMS perimenopause'], question: "What are vasomotor symptoms and their mental health impact?", response: "Hot flashes and night sweats (VMS) affect up to 80% of women and contribute to sleep disruption, fatigue, mood instability, and reduced quality of life." },

  { id: 3679, category: 'chapter7', keywords: ['perimenopause sleep disturbance'], question: "How does perimenopause affect sleep?", response: "Sleep fragmentation due to night sweats, hormonal changes, and mood symptoms is common and can exacerbate or trigger depressive episodes." },

  { id: 3680, category: 'chapter7', keywords: ['CycleMind perimenopause tracker'], question: "How can CycleMind support perimenopausal users?", response: "CycleMind can offer a perimenopause mode with irregular-cycle detection, VMS/sleep/mood/cognitive symptom logging, and correlation charts to help users track the menopausal transition." },

  { id: 3681, category: 'chapter7', keywords: ['Luna boundaries perimenopause'], question: "What boundaries should Luna observe for perimenopause topics?", response: "Luna must state she is not a clinician and cannot diagnose depression or recommend hormone therapy. She can share general education from Chapter 7 and support symptom tracking but must redirect all treatment decisions to a qualified provider." },

  { id: 3682, category: 'chapter7', keywords: ['MHT menopausal hormone therapy'], question: "What does Chapter 7 say about menopausal hormone therapy (MHT)?", response: "MHT (estrogen ± progestin) is highly effective for VMS and can improve sleep and quality of life. It may also have mood benefits in some perimenopausal women but requires individualized risk-benefit assessment." },

  { id: 3683, category: 'chapter7', keywords: ['SSRIs SNRIs perimenopause'], question: "What role do SSRIs/SNRIs play in perimenopausal depression?", response: "SSRIs and SNRIs are first-line pharmacologic treatments for perimenopausal depression and can also reduce VMS and improve sleep." },

  { id: 3684, category: 'chapter7', keywords: ['cognitive changes perimenopause'], question: "What cognitive symptoms occur during perimenopause?", response: "Subjective memory complaints and difficulty with word-finding are common but usually mild and transient; objective testing often shows minimal change." },

  { id: 3685, category: 'chapter7', keywords: ['CycleMind VMS sleep tracking'], question: "What perimenopause-specific tracking should CycleMind include?", response: "VMS frequency/severity logging, sleep quality tracker, mood correlation charts, and cognitive symptom notes to help users identify patterns and prepare for clinician visits." },

  { id: 3686, category: 'chapter7', keywords: ['perimenopause vs depression overlap'], question: "How does Chapter 7 differentiate perimenopausal symptoms from depression?", response: "Many symptoms (sleep disturbance, fatigue, irritability) overlap. Chapter 7 provides tables and guidance for distinguishing hormonally driven symptoms from a primary depressive disorder." },

  { id: 3687, category: 'chapter7', keywords: ['CBT perimenopause'], question: "Is CBT recommended for perimenopausal symptoms?", response: "Yes. CBT is effective for both depression and vasomotor symptoms during the menopausal transition and is a non-hormonal treatment option." },

  { id: 3688, category: 'chapter7', keywords: ['Luna response template Chapter 7'], question: "What template should Luna use for perimenopause questions?", response: "1. Disclaimer. 2. General educational summary from Chapter 7. 3. Offer CycleMind perimenopause tracking. 4. Strong redirect to psychiatrist or gynecologist." },

  { id: 3689, category: 'chapter7', keywords: ['sexual dysfunction perimenopause'], question: "What sexual changes occur in perimenopause?", response: "Declining estrogen leads to vaginal dryness, dyspareunia, and reduced desire. These changes often interact with mood symptoms and relationship factors." },

  { id: 3690, category: 'chapter7', keywords: ['Chapter 7 authors'], question: "Who authored Chapter 7?", response: "Nicole Leistikow, M.D., Milena H. Smith, M.D., Ph.D., Katherine E. Williams, M.D., and C. Neill Epperson, M.D." },

  { id: 3691, category: 'chapter7', keywords: ['hormonal fluctuations perimenopause mood'], question: "What hormonal mechanism links perimenopause to mood symptoms?", response: "Erratic fluctuations and eventual decline in estradiol and progesterone, along with changes in allopregnanolone and serotonin sensitivity, contribute to mood vulnerability." },

  { id: 3692, category: 'chapter7', keywords: ['CycleMind perimenopause education'], question: "How should CycleMind incorporate Chapter 7 education?", response: "Create clear educational cards on VMS, sleep, mood, cognitive, and sexual changes with emphasis on evidence-based treatments and the importance of professional evaluation." },

  { id: 3693, category: 'chapter7', keywords: ['perimenopause bipolar disorder'], question: "What is discussed regarding bipolar disorder in perimenopause?", response: "Women with bipolar disorder may experience increased depressive episodes or mood instability during the menopausal transition." },

  { id: 3694, category: 'chapter7', keywords: ['Luna disclaimer perimenopause'], question: "What disclaimer is required for Chapter 7 topics?", response: "Luna must state she is not a physician and cannot recommend hormone therapy or diagnose depression. This is general information only." },

  { id: 3695, category: 'chapter7', keywords: ['non-hormonal treatments VMS'], question: "What non-hormonal treatments for VMS are reviewed?", response: "SSRIs/SNRIs, gabapentin, cognitive-behavioral therapy, and lifestyle modifications are effective non-hormonal options for vasomotor symptoms." },

  { id: 3696, category: 'chapter7', keywords: ['CycleMind feature ideas Chapter 7'], question: "What CycleMind features are inspired by Chapter 7?", response: "Perimenopause-specific dashboard, VMS/sleep/mood/cognitive symptom tracker, hormone-transition correlation charts, and treatment education library." },

  { id: 3697, category: 'chapter7', keywords: ['perimenopause anxiety'], question: "Is anxiety increased during perimenopause?", response: "Yes. New-onset and recurrent anxiety disorders are more common during the menopausal transition, often co-occurring with depressive symptoms." },

  { id: 3698, category: 'chapter7', keywords: ['Luna safety netting perimenopause'], question: "What safety netting should Luna include?", response: "Luna should advise users experiencing severe mood changes, suicidal thoughts, or debilitating VMS/sleep disruption to contact their psychiatrist or gynecologist promptly." },

  { id: 3699, category: 'chapter7', keywords: ['integrated care perimenopause'], question: "What does Chapter 7 emphasize about care?", response: "Collaborative care between reproductive psychiatrists, gynecologists, and primary providers is essential for optimal management of perimenopausal mental health symptoms." },

  { id: 3700, category: 'chapter7', keywords: ['Chapter 7 key takeaway for app'], question: "What is the primary takeaway from Chapter 7 for CycleMind?", response: "Perimenopause is a high-risk window for mood, sleep, and cognitive symptoms; CycleMind should provide dedicated tracking tools and education while maintaining strict clinical boundaries." },

  { id: 3701, category: 'chapter7', keywords: ['Luna response boundaries Chapter 7'], question: "What overarching boundaries apply to Luna for Chapter 7 content?", response: "Luna must never diagnose perimenopausal depression or recommend MHT/SSRIs. All responses remain general education and end with a clinician redirect." },

  { id: 3702, category: 'chapter7', keywords: ['perimenopause cognitive complaints'], question: "How are cognitive complaints characterized?", response: "Subjective 'brain fog' and word-finding difficulty are common but usually mild and transient; objective deficits are minimal when controlled for age and mood." },

  { id: 3703, category: 'chapter7', keywords: ['CycleMind data export perimenopause'], question: "How can CycleMind data support perimenopausal care?", response: "Users can export VMS, sleep, mood, and cognitive symptom timelines to share with their psychiatrist or gynecologist for personalized treatment planning." },

  { id: 3704, category: 'chapter7', keywords: ['perimenopause LGBTQ+ considerations'], question: "Does Chapter 7 address diverse populations?", response: "The chapter notes the need for inclusive care and acknowledges that data on gender-diverse individuals in perimenopause are limited but growing." },

  { id: 3705, category: 'chapter7', keywords: ['perimenopause lifetime course'], question: "What is the typical course of perimenopause?", response: "Perimenopause lasts 4–8 years on average, beginning around age 47. Symptoms peak during the late transition and generally improve after menopause." },

  // === Chapter 8: Psychiatric Diagnosis and Treatment During Pregnancy (IDs 3706–3735) ===
  { id: 3706, category: 'chapter8', keywords: ['psychiatric diagnosis treatment pregnancy overview'], question: "What does Chapter 8 of the Textbook of Women's Reproductive Mental Health cover?", response: "Chapter 8 presents a practical clinical framework for diagnosing and treating psychiatric disorders during pregnancy, including risk-benefit analysis, medication safety, non-pharmacologic options, and collaborative care with obstetrics." },

  { id: 3707, category: 'chapter8', keywords: ['risk benefit analysis pregnancy psychotropics'], question: "What is the core approach to treatment decisions in pregnancy?", response: "Chapter 8 emphasizes individualized risk-benefit analysis weighing untreated psychiatric illness risks against medication exposure risks, using the most up-to-date safety data." },

  { id: 3708, category: 'chapter8', keywords: ['untreated psychiatric illness pregnancy risks'], question: "What risks are associated with untreated psychiatric illness in pregnancy?", response: "Untreated depression, anxiety, bipolar disorder, or psychosis increase risks of preterm birth, low birth weight, preeclampsia, poor prenatal care, substance use, and postpartum worsening." },

  { id: 3709, category: 'chapter8', keywords: ['CycleMind pregnancy mode'], question: "How can CycleMind support pregnant users per Chapter 8?", response: "CycleMind can switch to a pregnancy-specific mode with mood, sleep, anxiety, and functioning trackers to help users monitor symptoms and generate reports for their perinatal psychiatrist." },

  { id: 3710, category: 'chapter8', keywords: ['Luna boundaries pregnancy psychiatry'], question: "What boundaries should Luna observe for pregnancy mental health topics?", response: "Luna must state she is not a perinatal psychiatrist and cannot make treatment recommendations. She can share general educational information from Chapter 8 and support symptom tracking but must always redirect to the user's psychiatrist and OB/GYN." },

  { id: 3711, category: 'chapter8', keywords: ['psychotropic medication pregnancy'], question: "How does Chapter 8 address psychotropic medications in pregnancy?", response: "Chapter 8 reviews safety data for antidepressants, mood stabilizers, antipsychotics, and anxiolytics, emphasizing that decisions must balance maternal illness severity with fetal risks and include shared decision-making." },

  { id: 3712, category: 'chapter8', keywords: ['non-pharmacologic treatments pregnancy'], question: "What non-pharmacologic options are recommended?", response: "Psychotherapy (CBT, IPT), bright light therapy, exercise, and supportive care are first-line or adjunctive options for mild-to-moderate symptoms during pregnancy." },

  { id: 3713, category: 'chapter8', keywords: ['collaborative care pregnancy'], question: "What model of care is advocated in Chapter 8?", response: "Close collaboration between reproductive psychiatrists, obstetricians, and other specialists is essential for optimal outcomes in pregnant women with psychiatric illness." },

  { id: 3714, category: 'chapter8', keywords: ['CycleMind symptom tracking pregnancy'], question: "What pregnancy-specific tracking should CycleMind include?", response: "Mood, anxiety, sleep, functioning, and side-effect tracking tailored to each trimester, with easy export for the perinatal mental health team." },

  { id: 3715, category: 'chapter8', keywords: ['Luna response template Chapter 8'], question: "What template should Luna use for pregnancy psychiatry questions?", response: "1. Clear disclaimer. 2. General educational summary from Chapter 8. 3. Offer CycleMind pregnancy tracking. 4. Strong redirect to perinatal psychiatrist and OB/GYN." },

  { id: 3716, category: 'chapter8', keywords: ['postpartum planning pregnancy'], question: "Does Chapter 8 address postpartum planning?", response: "Yes. Chapter 8 stresses proactive planning for the high-risk postpartum period, including medication adjustments, sleep support, and close monitoring." },

  { id: 3717, category: 'chapter8', keywords: ['Chapter 8 authors'], question: "Who authored Chapter 8?", response: "Elizabeth M. Fitelson, M.D., Lauren M. Osborne, M.D., and Jennifer L. Payne, M.D." },

  { id: 3718, category: 'chapter8', keywords: ['depression pregnancy treatment'], question: "What is the recommended approach to depression in pregnancy?", response: "For moderate-to-severe depression, antidepressants (especially SSRIs with the most safety data) are often continued or initiated after risk-benefit discussion." },

  { id: 3719, category: 'chapter8', keywords: ['bipolar disorder pregnancy'], question: "How is bipolar disorder managed in pregnancy per Chapter 8?", response: "Mood stabilizer selection requires careful balancing of teratogenic risks versus relapse risk; lithium, lamotrigine, and atypical antipsychotics are discussed with monitoring recommendations." },

  { id: 3720, category: 'chapter8', keywords: ['anxiety disorders pregnancy'], question: "What guidance is given for anxiety disorders in pregnancy?", response: "CBT is first-line; SSRIs or benzodiazepines (short-term, low-dose) may be considered when non-pharmacologic approaches are insufficient." },

  { id: 3721, category: 'chapter8', keywords: ['CycleMind data export pregnancy'], question: "How can CycleMind data support prenatal psychiatric care?", response: "Users can export trimester-specific mood and symptom timelines to share with their perinatal mental health team for informed treatment planning." },

  { id: 3722, category: 'chapter8', keywords: ['Luna disclaimer pregnancy treatment'], question: "What disclaimer is mandatory for Chapter 8 topics?", response: "Luna must state she is not a perinatal psychiatrist and cannot recommend medications or treatment plans. This is general information only." },

  { id: 3723, category: 'chapter8', keywords: ['psychosis pregnancy'], question: "How is psychosis addressed in pregnancy?", response: "Acute psychosis in pregnancy is a psychiatric emergency requiring prompt treatment with antipsychotics and close obstetric monitoring." },

  { id: 3724, category: 'chapter8', keywords: ['Luna safety netting pregnancy'], question: "What safety netting should Luna include?", response: "Luna should advise immediate contact with the perinatal psychiatrist or OB/GYN for worsening mood, suicidal thoughts, or any safety concerns during pregnancy." },

  { id: 3725, category: 'chapter8', keywords: ['integrated obstetric psychiatric care'], question: "What is the core message of Chapter 8?", response: "Psychiatric illness in pregnancy requires a thoughtful, individualized, collaborative approach that prioritizes maternal and fetal safety through shared decision-making." },

  { id: 3726, category: 'chapter8', keywords: ['Chapter 8 key takeaway for app'], question: "What is the primary takeaway from Chapter 8 for CycleMind?", response: "Pregnancy is a high-stakes period for mental health; the app should provide optional, respectful tracking tools and education while always directing users to their clinical team." },

  { id: 3727, category: 'chapter8', keywords: ['Luna response boundaries Chapter 8'], question: "What overarching boundaries apply to Luna for Chapter 8 content?", response: "Luna must never interpret symptoms, recommend medications, or alter treatment plans. All responses remain general education and end with a clinician redirect." },

  { id: 3728, category: 'chapter8', keywords: ['SSRIs pregnancy safety'], question: "What does Chapter 8 say about SSRIs in pregnancy?", response: "SSRIs (particularly sertraline) have the most reassuring safety data; risks of specific malformations are small but must be discussed in context of untreated illness risks." },

  { id: 3729, category: 'chapter8', keywords: ['CycleMind pregnancy education'], question: "How should CycleMind incorporate Chapter 8 education?", response: "Create trimester-aware educational cards on psychiatric treatment considerations in pregnancy with clear statements about the need for professional care." },

  { id: 3730, category: 'chapter8', keywords: ['perinatal mental health planning'], question: "Does Chapter 8 address planning for the postpartum period?", response: "Yes. Proactive planning for medication adjustments, sleep support, and close monitoring in the immediate postpartum period is strongly recommended." },

  { id: 3731, category: 'chapter8', keywords: ['Luna educational content Chapter 8'], question: "How should Luna present Chapter 8 content?", response: "Luna should deliver balanced, non-directive education on the risk-benefit framework while offering CycleMind tracking and always emphasizing consultation with the clinical team." },

  { id: 3732, category: 'chapter8', keywords: ['anxiety OCD pregnancy'], question: "What guidance is provided for anxiety and OCD in pregnancy?", response: "CBT is preferred; SSRIs are commonly used when needed, with careful discussion of risks versus benefits of untreated illness." },

  { id: 3733, category: 'chapter8', keywords: ['CycleMind feature ideas Chapter 8'], question: "What CycleMind features are inspired by Chapter 8?", response: "Pregnancy-mode symptom tracker, trimester-specific mood/sleep logs, treatment response tracking, and clinician-export functionality." },

  { id: 3734, category: 'chapter8', keywords: ['Luna safety netting Chapter 8'], question: "What safety netting should Luna include for pregnancy topics?", response: "Luna should direct users with worsening psychiatric symptoms, suicidal ideation, or safety concerns to contact their perinatal mental health team or emergency services immediately." },

  { id: 3735, category: 'chapter8', keywords: ['Chapter 8 key takeaway for app'], question: "What is the primary takeaway from Chapter 8 for CycleMind development?", response: "Pregnancy requires a nuanced, collaborative approach to psychiatric care; the app should support symptom monitoring and education while maintaining strict clinical boundaries." },

  // === Chapter 9: Postpartum Psychiatric Diagnosis and Treatment (IDs 3736–3765) ===
  { id: 3736, category: 'chapter9', keywords: ['postpartum psychiatric diagnosis treatment overview'], question: "What does Chapter 9 of the Textbook of Women's Reproductive Mental Health cover?", response: "Chapter 9 provides a practical clinical framework for diagnosing and treating psychiatric disorders in the postpartum period, emphasizing rapid assessment, safety, breastfeeding considerations, and collaborative care with obstetrics and pediatrics." },

  { id: 3737, category: 'chapter9', keywords: ['postpartum depression diagnosis'], question: "How is postpartum depression diagnosed per Chapter 9?", response: "Postpartum depression is diagnosed using standard DSM-5 criteria for major depressive episode, with onset typically within the first 4 weeks but can occur up to 12 months postpartum. Screening tools and clinical interview are essential." },

  { id: 3738, category: 'chapter9', keywords: ['postpartum psychosis emergency'], question: "How is postpartum psychosis addressed?", response: "Postpartum psychosis is a psychiatric emergency requiring immediate hospitalization, antipsychotics, and often mood stabilizers. It carries high risk of infanticide and suicide and demands urgent intervention." },

  { id: 3739, category: 'chapter9', keywords: ['CycleMind postpartum tracker'], question: "How can CycleMind support postpartum users per Chapter 9?", response: "CycleMind can include a dedicated postpartum mode with daily mood, sleep, anxiety, bonding, and functioning trackers to help users monitor the high-risk postpartum period and generate reports for their clinician." },

  { id: 3740, category: 'chapter9', keywords: ['Luna boundaries postpartum psychiatry'], question: "What boundaries should Luna observe for postpartum mental health?", response: "Luna must state she is not a perinatal psychiatrist and cannot diagnose or treat postpartum disorders. She can share general education from Chapter 9 and support symptom tracking but must always redirect to the user's psychiatrist and OB/GYN." },

  { id: 3741, category: 'chapter9', keywords: ['breastfeeding psychotropic medications'], question: "What does Chapter 9 say about breastfeeding and medications?", response: "Chapter 9 reviews lactation safety data for antidepressants, antipsychotics, and mood stabilizers, emphasizing shared decision-making that balances maternal mental health needs with infant exposure risks." },

  { id: 3742, category: 'chapter9', keywords: ['postpartum anxiety OCD'], question: "How are postpartum anxiety and OCD managed?", response: "CBT is first-line; SSRIs are commonly used when symptoms are moderate to severe. Scrupulosity and harm obsessions are common presentations in postpartum OCD." },

  { id: 3743, category: 'chapter9', keywords: ['postpartum sleep deprivation'], question: "What role does sleep play in postpartum mental health?", response: "Severe sleep disruption is both a symptom and a major risk factor for postpartum depression and psychosis. Chapter 9 stresses sleep protection strategies and early intervention." },

  { id: 3744, category: 'chapter9', keywords: ['CycleMind postpartum mood tracking'], question: "What postpartum-specific tracking should CycleMind include?", response: "Daily mood, anxiety, sleep, infant bonding, and intrusive thought logs with gentle prompts and easy clinician export to support early detection and treatment." },

  { id: 3745, category: 'chapter9', keywords: ['Luna response template Chapter 9'], question: "What template should Luna use for postpartum questions?", response: "1. Clear disclaimer. 2. General educational summary from Chapter 9. 3. Offer CycleMind postpartum tracking. 4. Strong redirect to perinatal psychiatrist or emergency services if safety concerns exist." },

  { id: 3746, category: 'chapter9', keywords: ['infant safety postpartum psychosis'], question: "What infant safety considerations are emphasized?", response: "Chapter 9 stresses assessment of maternal capacity to care for the infant, especially in cases of postpartum psychosis or severe depression, and the need for family/support involvement." },

  { id: 3747, category: 'chapter9', keywords: ['Chapter 9 authors'], question: "Who authored Chapter 9?", response: "Alyson Gorun, M.D., Mira Zein, M.D., Melisa Olgun, B.A., and Lisa A. Catapano, M.D., Ph.D." },

  { id: 3748, category: 'chapter9', keywords: ['postpartum bipolar relapse'], question: "What is the risk of bipolar relapse postpartum?", response: "Women with bipolar disorder have a markedly elevated risk of postpartum mood episodes; prophylactic medication adjustment and close monitoring are recommended." },

  { id: 3749, category: 'chapter9', keywords: ['CycleMind data export postpartum'], question: "How can CycleMind data support postpartum psychiatric care?", response: "Users can export daily mood, sleep, and functioning logs to share with their perinatal mental health team for rapid treatment adjustment." },

  { id: 3750, category: 'chapter9', keywords: ['Luna disclaimer postpartum'], question: "What disclaimer is required for Chapter 9 topics?", response: "Luna must state she is not a clinician and cannot diagnose or treat postpartum psychiatric conditions. This is general information only." },

  { id: 3751, category: 'chapter9', keywords: ['postpartum PTSD'], question: "Is PTSD discussed in the postpartum period?", response: "Yes. Traumatic birth experiences, emergency cesarean, or perinatal loss can trigger postpartum PTSD that requires specific trauma-focused treatment." },

  { id: 3752, category: 'chapter9', keywords: ['integrated care postpartum'], question: "What model of care is advocated?", response: "Close collaboration between reproductive psychiatrists, obstetricians, pediatricians, and lactation consultants is essential for optimal postpartum mental health outcomes." },

  { id: 3753, category: 'chapter9', keywords: ['CycleMind postpartum education'], question: "How should CycleMind incorporate Chapter 9 education?", response: "Create postpartum-specific education cards on common disorders, warning signs, sleep hygiene, and the importance of prompt professional evaluation." },

  { id: 3754, category: 'chapter9', keywords: ['Luna safety netting postpartum'], question: "What safety netting should Luna include?", response: "Luna should direct users with thoughts of harming themselves or the infant, severe mood changes, or inability to care for the baby to seek immediate emergency care or contact their provider." },

  { id: 3755, category: 'chapter9', keywords: ['postpartum psychosis treatment'], question: "How is postpartum psychosis treated per Chapter 9?", response: "Immediate hospitalization, antipsychotics, mood stabilizers, and often ECT are used. Breastfeeding decisions must be made with safety as the priority." },

  { id: 3756, category: 'chapter9', keywords: ['Luna response boundaries Chapter 9'], question: "What overarching boundaries apply to Luna for Chapter 9 content?", response: "Luna must never diagnose postpartum depression, psychosis, or anxiety, or recommend medications. All responses remain general education and end with a clinician redirect." },

  { id: 3757, category: 'chapter9', keywords: ['Chapter 9 key takeaway for app'], question: "What is the primary takeaway from Chapter 9 for CycleMind?", response: "The postpartum period is a high-risk time for psychiatric illness; the app should provide sensitive tracking tools and education while ensuring users connect with professional care." },

  { id: 3758, category: 'chapter9', keywords: ['postpartum anxiety screening'], question: "What screening is recommended postpartum?", response: "Routine screening for depression (Edinburgh Postnatal Depression Scale) and anxiety is recommended, with clinical interview for full assessment." },

  { id: 3759, category: 'chapter9', keywords: ['CycleMind bonding tracker'], question: "Should CycleMind include infant bonding tracking?", response: "Optional, sensitive bonding and attachment questions can be included to help users monitor their experience and discuss with their clinician if concerns arise." },

  { id: 3760, category: 'chapter9', keywords: ['Luna educational content Chapter 9'], question: "How should Luna present Chapter 9 content?", response: "Luna should deliver compassionate, non-stigmatizing education on postpartum psychiatric disorders while offering CycleMind tracking and always emphasizing professional support." },

  { id: 3761, category: 'chapter9', keywords: ['partner postpartum mental health'], question: "Does Chapter 9 address partners?", response: "Yes. Partners can also experience depression and anxiety postpartum; family-wide support is important for optimal maternal and infant outcomes." },

  { id: 3762, category: 'chapter9', keywords: ['CycleMind feature ideas Chapter 9'], question: "What CycleMind features are inspired by Chapter 9?", response: "Postpartum dashboard, daily mood/sleep/bonding logs, warning sign alerts, and clinician-export reports tailored to the postpartum period." },

  { id: 3763, category: 'chapter9', keywords: ['postpartum relapse prevention'], question: "What relapse prevention strategies are discussed?", response: "Proactive medication planning, sleep protection, social support, and early symptom monitoring are key to preventing postpartum psychiatric relapse." },

  { id: 3764, category: 'chapter9', keywords: ['Luna safety netting Chapter 9'], question: "What safety netting should Luna include for postpartum topics?", response: "Luna should advise immediate help for thoughts of harm to self or infant, severe insomnia, or inability to care for the baby." },

  { id: 3765, category: 'chapter9', keywords: ['Chapter 9 key takeaway for app'], question: "What is the primary takeaway from Chapter 9 for CycleMind development?", response: "The postpartum period requires vigilant monitoring; CycleMind should provide practical, compassionate tracking tools while ensuring users remain connected to their clinical team." },

  // === Chapter 10: Perinatal Psychiatric Emergencies (IDs 3766–3795) ===
  { id: 3766, category: 'chapter10', keywords: ['perinatal psychiatric emergencies overview'], question: "What does Chapter 10 of the Textbook of Women's Reproductive Mental Health cover?", response: "Chapter 10 outlines a practical, safety-first approach to psychiatric emergencies during pregnancy and the postpartum period, including agitation, suicidality, psychosis, severe depression, and mania." },

  { id: 3767, category: 'chapter10', keywords: ['postpartum psychosis emergency'], question: "How is postpartum psychosis managed as an emergency?", response: "Postpartum psychosis is a psychiatric emergency requiring immediate hospitalization, antipsychotics/mood stabilizers, and close safety monitoring due to high risks of infanticide and suicide." },

  { id: 3768, category: 'chapter10', keywords: ['suicidality perinatal period'], question: "What is the approach to suicidality in pregnancy and postpartum?", response: "Chapter 10 emphasizes rapid risk assessment, safety planning, hospitalization when indicated, and balancing maternal and fetal safety in treatment decisions." },

  { id: 3769, category: 'chapter10', keywords: ['CycleMind emergency alerts'], question: "How can CycleMind support emergency detection?", response: "CycleMind can include optional safety check-ins, severe symptom alerts (suicidal thoughts, agitation, psychosis indicators), and one-tap clinician or crisis resource connections." },

  { id: 3770, category: 'chapter10', keywords: ['Luna boundaries perinatal emergencies'], question: "What boundaries should Luna observe for psychiatric emergencies?", response: "Luna must immediately direct users experiencing suicidal thoughts, agitation, psychosis, or inability to ensure safety to emergency services or their perinatal psychiatrist. Luna cannot provide crisis intervention." },

  { id: 3771, category: 'chapter10', keywords: ['agitation perinatal treatment'], question: "How is acute agitation managed in the perinatal period?", response: "Chapter 10 reviews pharmacologic (antipsychotics, benzodiazepines) and non-pharmacologic de-escalation strategies while considering pregnancy and breastfeeding safety." },

  { id: 3772, category: 'chapter10', keywords: ['severe depression pregnancy postpartum'], question: "What is the approach to severe depression in the perinatal period?", response: "Severe depression may require hospitalization, electroconvulsive therapy (ECT), or urgent medication initiation after risk-benefit discussion." },

  { id: 3773, category: 'chapter10', keywords: ['CycleMind safety features'], question: "What safety features should CycleMind include based on Chapter 10?", response: "Crisis resource buttons, daily safety screeners, severe symptom flagging, and easy export of recent logs for emergency clinicians." },

  { id: 3774, category: 'chapter10', keywords: ['Luna response template emergencies'], question: "What template should Luna use for emergency topics?", response: "1. Immediate safety redirect. 2. Crisis resources. 3. Encourage contact with perinatal psychiatrist or emergency services. 4. Offer to help log symptoms once safety is addressed." },

  { id: 3775, category: 'chapter10', keywords: ['Chapter 10 authors'], question: "Who authored Chapter 10?", response: "Jovana Martinovic, M.D., Pooja Lakshmin, M.D., Mira Zein, M.D., Melisa Olgun, B.A., and Lucy A. Hutner, M.D." },

  { id: 3776, category: 'chapter10', keywords: ['mania perinatal emergency'], question: "How is manic or mixed episodes managed perinatally?", response: "Acute mania in pregnancy or postpartum is a psychiatric emergency requiring prompt mood stabilization and safety assessment." },

  { id: 3777, category: 'chapter10', keywords: ['Luna disclaimer emergencies'], question: "What disclaimer is required for Chapter 10 topics?", response: "Luna must state she is not a clinician and cannot manage psychiatric emergencies. Users in crisis must contact emergency services or their perinatal mental health team immediately." },

  { id: 3778, category: 'chapter10', keywords: ['ECT electroconvulsive therapy perinatal'], question: "Is ECT discussed for perinatal emergencies?", response: "Yes. ECT is a safe and effective option for severe, treatment-resistant depression, psychosis, or catatonia in pregnancy and postpartum." },

  { id: 3779, category: 'chapter10', keywords: ['CycleMind crisis resources'], question: "How should CycleMind integrate crisis resources from Chapter 10?", response: "Include one-tap access to national perinatal mental health crisis lines, suicide prevention hotlines, and local emergency psychiatric services." },

  { id: 3780, category: 'chapter10', keywords: ['infant safety perinatal emergencies'], question: "What infant safety considerations are emphasized?", response: "Chapter 10 stresses assessment of maternal capacity to care for the infant during acute psychiatric emergencies and the need for family/support involvement." },

  { id: 3781, category: 'chapter10', keywords: ['Luna safety netting Chapter 10'], question: "What safety netting should Luna include?", response: "Luna should immediately provide crisis numbers, urge contact with emergency services or the perinatal team, and offer to stay with the user until help arrives if appropriate." },

  { id: 3782, category: 'chapter10', keywords: ['collaborative care emergencies'], question: "What model of care is advocated for perinatal emergencies?", response: "Rapid, coordinated care between reproductive psychiatrists, obstetricians, emergency departments, and pediatricians is essential." },

  { id: 3783, category: 'chapter10', keywords: ['CycleMind feature ideas Chapter 10'], question: "What CycleMind features are inspired by Chapter 10?", response: "Emergency symptom flagging, crisis resource buttons, safety check-in prompts, and one-tap export of recent logs for emergency clinicians." },

  { id: 3784, category: 'chapter10', keywords: ['Luna educational content Chapter 10'], question: "How should Luna present Chapter 10 content?", response: "Luna should deliver clear, action-oriented education on recognizing emergencies while always prioritizing immediate safety and professional intervention." },

  { id: 3785, category: 'chapter10', keywords: ['postpartum psychosis risk factors'], question: "What risk factors for postpartum psychosis are noted?", response: "History of bipolar disorder, previous postpartum psychosis, family history, and sleep deprivation are major risk factors." },

  { id: 3786, category: 'chapter10', keywords: ['Luna response boundaries Chapter 10'], question: "What overarching boundaries apply to Luna for Chapter 10 content?", response: "Luna must never attempt to manage, assess, or treat psychiatric emergencies. Every response must redirect immediately to professional emergency care." },

  { id: 3787, category: 'chapter10', keywords: ['Chapter 10 key takeaway for app'], question: "What is the primary takeaway from Chapter 10 for CycleMind?", response: "Psychiatric emergencies in the perinatal period require immediate action; the app should provide fast safety tools and education while ensuring users reach professional help." },

  { id: 3788, category: 'chapter10', keywords: ['agitation de-escalation perinatal'], question: "What de-escalation strategies are recommended?", response: "Non-pharmacologic techniques (quiet environment, verbal de-escalation) are preferred initially, with judicious use of medications when safety is at risk." },

  { id: 3789, category: 'chapter10', keywords: ['CycleMind safety check-in'], question: "Should CycleMind include safety check-ins?", response: "Yes — optional daily or triggered safety screeners with immediate crisis resources if high-risk responses are detected." },

  { id: 3790, category: 'chapter10', keywords: ['perinatal emergency planning'], question: "Does Chapter 10 discuss advance planning?", response: "Yes. Proactive safety planning for women at high risk (bipolar, prior psychosis) is strongly recommended before delivery." },

  { id: 3791, category: 'chapter10', keywords: ['Luna crisis redirect language'], question: "What language should Luna use in crisis situations?", response: "Luna should use direct, compassionate language such as: 'This sounds like an emergency. Please call 911 or your perinatal psychiatrist right now. I'm here to help you reach support.'" },

  { id: 3792, category: 'chapter10', keywords: ['integrated emergency care'], question: "What is the core message of Chapter 10?", response: "Perinatal psychiatric emergencies require rapid, coordinated, multidisciplinary intervention prioritizing safety of mother and infant." },

  { id: 3793, category: 'chapter10', keywords: ['CycleMind emergency export'], question: "How can CycleMind assist in emergencies?", response: "Users can instantly export the last 7–14 days of symptom logs to share with emergency providers or their perinatal team." },

  { id: 3794, category: 'chapter10', keywords: ['Luna educational content emergencies'], question: "How should Luna present emergency education?", response: "Luna should focus on recognition of warning signs and immediate action steps while always deferring treatment to professionals." },

  { id: 3795, category: 'chapter10', keywords: ['Chapter 10 key takeaway for app'], question: "What is the primary takeaway from Chapter 10 for CycleMind development?", response: "The app must include robust safety features and crisis pathways while maintaining strict boundaries and never attempting to replace professional emergency care." },

  // === Chapter 11: Prenatal Stress — Effects on Mother and Child (IDs 3796–3825) ===
  { id: 3796, category: 'chapter11', keywords: ['stress pregnancy impacts mother child overview'], question: "What does Chapter 11 of the Textbook of Women's Reproductive Mental Health cover?", response: "Chapter 11 examines the effects of prenatal stress on maternal mental health and fetal/child neurodevelopment, including physiologic mechanisms, risk factors, and clinical implications for perinatal psychiatry." },
  { id: 3797, category: 'chapter11', keywords: ['prenatal stress maternal mental health'], question: "How does prenatal stress affect the mother?", response: "High levels of stress during pregnancy are associated with increased risk of depression, anxiety, and PTSD, which can further amplify stress responses and impact pregnancy outcomes." },
  { id: 3798, category: 'chapter11', keywords: ['fetal programming prenatal stress'], question: "What is fetal programming in the context of prenatal stress?", response: "Prenatal stress can program the fetal HPA axis and brain development, leading to long-term effects on child emotional regulation, cognitive function, and stress reactivity." },
  { id: 3799, category: 'chapter11', keywords: ['CycleMind prenatal stress tracking'], question: "How can CycleMind support users experiencing prenatal stress?", response: "CycleMind can include pregnancy-specific stress, mood, and anxiety trackers with optional fetal movement or pregnancy milestone correlations to help users monitor and share patterns with their perinatal team." },
  { id: 3800, category: 'chapter11', keywords: ['Luna boundaries prenatal stress'], question: "What boundaries should Luna observe for prenatal stress topics?", response: "Luna must state she is not a clinician and cannot provide therapy or interpret fetal/child outcomes. She can share general education from Chapter 11 and support symptom tracking but must always redirect to the user's perinatal psychiatrist or OB/GYN." },
  { id: 3801, category: 'chapter11', keywords: ['HPA axis prenatal stress'], question: "What role does the HPA axis play in prenatal stress effects?", response: "Maternal stress activates the HPA axis, releasing cortisol that can cross the placenta and influence fetal brain development and programming." },
  { id: 3802, category: 'chapter11', keywords: ['child outcomes prenatal stress'], question: "What child outcomes are linked to prenatal stress?", response: "Increased risk of emotional/behavioral problems, cognitive delays, and altered stress reactivity in offspring are associated with high maternal prenatal stress." },
  { id: 3803, category: 'chapter11', keywords: ['CycleMind stress management pregnancy'], question: "What stress management features should CycleMind include?", response: "Optional guided breathing, mindfulness prompts, and stress symptom logging tied to pregnancy stage to support users while encouraging professional care." },
  { id: 3804, category: 'chapter11', keywords: ['Luna response template Chapter 11'], question: "What template should Luna use for Chapter 11 topics?", response: "1. Clear disclaimer. 2. General educational summary. 3. Offer CycleMind pregnancy stress tracking. 4. Strong redirect to perinatal mental health provider." },
  { id: 3805, category: 'chapter11', keywords: ['Chapter 11 authors'], question: "Who authored Chapter 11?", response: "Lea Takács, Ph.D., Vanessa Babineau, Ph.D., and Catherine Monk, Ph.D." },
  { id: 3806, category: 'chapter11', keywords: ['psychosocial stress pregnancy'], question: "What psychosocial stressors are highlighted?", response: "Poverty, intimate partner violence, discrimination, and lack of social support are major sources of prenatal stress with documented effects on maternal and child outcomes." },
  { id: 3807, category: 'chapter11', keywords: ['CycleMind data export prenatal stress'], question: "How can CycleMind data support prenatal care?", response: "Users can export stress, mood, and symptom timelines to share with their obstetrician or perinatal psychiatrist for holistic care planning." },
  { id: 3808, category: 'chapter11', keywords: ['Luna disclaimer prenatal stress'], question: "What disclaimer is required for Chapter 11 topics?", response: "Luna must state she is not a clinician and cannot assess fetal risk or provide therapy. This is general educational information only." },
  { id: 3809, category: 'chapter11', keywords: ['intergenerational transmission stress'], question: "Does Chapter 11 discuss intergenerational effects?", response: "Yes. Prenatal stress can influence offspring stress reactivity, which may perpetuate intergenerational transmission of vulnerability to psychiatric disorders." },
  { id: 3810, category: 'chapter11', keywords: ['non-pharmacologic stress reduction pregnancy'], question: "What non-pharmacologic interventions are recommended?", response: "Mindfulness-based interventions, yoga, exercise, social support enhancement, and psychotherapy are effective for reducing prenatal stress." },
  { id: 3811, category: 'chapter11', keywords: ['CycleMind feature ideas Chapter 11'], question: "What CycleMind features are inspired by Chapter 11?", response: "Pregnancy stress tracker, mindfulness/breathing tools, psychosocial stressor logging, and correlation with mood/sleep outcomes." },
  { id: 3812, category: 'chapter11', keywords: ['Luna safety netting Chapter 11'], question: "What safety netting should Luna include?", response: "Luna should advise users with high stress plus worsening mood, suicidal thoughts, or safety concerns to contact their perinatal team or emergency services immediately." },
  { id: 3813, category: 'chapter11', keywords: ['maternal fetal stress physiology'], question: "What physiologic pathways are reviewed?", response: "Maternal stress hormones (cortisol, CRH) cross the placenta, affecting fetal brain development and programming the offspring's stress response system." },
  { id: 3814, category: 'chapter11', keywords: ['Luna educational content Chapter 11'], question: "How should Luna present Chapter 11 content?", response: "Luna should deliver clear, non-alarmist education on prenatal stress effects while offering CycleMind tracking tools and always emphasizing professional support." },
  { id: 3815, category: 'chapter11', keywords: ['resilience factors prenatal stress'], question: "What resilience factors are discussed?", response: "Social support, mindfulness, physical activity, and positive coping strategies can buffer the effects of prenatal stress on mother and child." },
  { id: 3816, category: 'chapter11', keywords: ['CycleMind stress education'], question: "How should CycleMind incorporate Chapter 11 education?", response: "Create accessible cards on prenatal stress physiology, impacts, and protective factors with links to tracking tools and professional resources." },
  { id: 3817, category: 'chapter11', keywords: ['Luna response boundaries Chapter 11'], question: "What overarching boundaries apply to Luna for Chapter 11 content?", response: "Luna must never provide therapy, assess fetal risk, or interpret individual stress effects. All responses remain general education and end with a clinician redirect." },
  { id: 3818, category: 'chapter11', keywords: ['Chapter 11 key takeaway for app'], question: "What is the primary takeaway from Chapter 11 for CycleMind?", response: "Prenatal stress affects both mother and child; the app should offer supportive tracking and education while ensuring users connect with their perinatal care team." },
  { id: 3819, category: 'chapter11', keywords: ['traumatic stress pregnancy'], question: "Does Chapter 11 address traumatic stress?", response: "Yes. Exposure to trauma or intimate partner violence during pregnancy amplifies stress effects and requires trauma-informed perinatal mental health care." },
  { id: 3820, category: 'chapter11', keywords: ['CycleMind mindfulness tools'], question: "Should CycleMind include mindfulness tools for pregnancy stress?", response: "Optional guided mindfulness or breathing exercises can be included as adjunctive supports, clearly labeled as general wellness tools." },
  { id: 3821, category: 'chapter11', keywords: ['intergenerational mental health'], question: "What intergenerational implications are noted?", response: "Prenatal stress can influence offspring mental health vulnerability, highlighting the importance of early intervention for pregnant individuals." },
  { id: 3822, category: 'chapter11', keywords: ['Luna crisis redirect Chapter 11'], question: "What language should Luna use if stress escalates to crisis?", response: "Luna should use direct, compassionate language: 'High stress plus mood changes can be serious. Please reach out to your perinatal psychiatrist or call your provider right away.'" },
  { id: 3823, category: 'chapter11', keywords: ['integrated care prenatal stress'], question: "What model of care is emphasized?", response: "Integrated obstetric and psychiatric care is essential for addressing prenatal stress and its effects on mother and child." },
  { id: 3824, category: 'chapter11', keywords: ['CycleMind data export Chapter 11'], question: "How can CycleMind data support prenatal stress care?", response: "Users can export stress and mood logs to share with their OB/GYN or perinatal psychiatrist for holistic treatment planning." },
  { id: 3825, category: 'chapter11', keywords: ['Chapter 11 key takeaway for app'], question: "What is the primary takeaway from Chapter 11 for CycleMind development?", response: "Prenatal stress is modifiable; CycleMind should provide practical tracking and education tools while always directing users to professional care." },

  // === Chapter 12: Infant Mental Health and Parent–Infant Relationship (IDs 3826–3855) ===
  { id: 3826, category: 'chapter12', keywords: ['infant mental health parent infant relationship overview'], question: "What does Chapter 12 of the Textbook of Women's Reproductive Mental Health cover?", response: "Chapter 12 reviews the essentials of infant mental health, the parent–infant relationship, attachment theory, assessment tools, and evidence-based treatments in the context of perinatal psychiatry." },
  { id: 3827, category: 'chapter12', keywords: ['attachment theory perinatal psychiatry'], question: "What is the role of attachment theory in Chapter 12?", response: "Secure parent–infant attachment is foundational for infant emotional regulation and long-term mental health. Perinatal psychiatric illness can disrupt attachment, making early intervention critical." },
  { id: 3828, category: 'chapter12', keywords: ['parent infant relationship assessment'], question: "What assessment tools are discussed for the parent–infant relationship?", response: "Chapter 12 reviews observational tools, the Strange Situation Procedure, and clinical interviews to evaluate attachment security and relational quality." },
  { id: 3829, category: 'chapter12', keywords: ['CycleMind bonding tracker'], question: "How can CycleMind support parent–infant bonding?", response: "CycleMind can include optional, gentle bonding and attachment questions in the postpartum mode to help users monitor their relationship with their infant and share insights with their clinician." },
  { id: 3830, category: 'chapter12', keywords: ['Luna boundaries infant mental health'], question: "What boundaries should Luna observe for infant mental health topics?", response: "Luna must state she is not a child psychologist or infant mental health specialist and cannot assess or treat infant or parent–infant relational issues. She can share general education and support tracking but must redirect to qualified perinatal or infant mental health professionals." },
  { id: 3831, category: 'chapter12', keywords: ['postpartum depression infant attachment'], question: "How does postpartum depression affect the parent–infant relationship?", response: "Maternal depression can impair sensitive responsiveness, leading to insecure attachment and potential long-term effects on child emotional development." },
  { id: 3832, category: 'chapter12', keywords: ['evidence based treatments infant mental health'], question: "What treatments are recommended for parent–infant relational problems?", response: "Chapter 12 highlights dyadic therapies such as Child–Parent Psychotherapy, Circle of Security, and video feedback interventions as effective approaches." },
  { id: 3833, category: 'chapter12', keywords: ['CycleMind postpartum relational tracking'], question: "What relational tracking should CycleMind include?", response: "Optional postpartum bonding logs, reflective questions about infant cues, and gentle prompts to notice positive interactions, with clear disclaimers and clinician export." },
  { id: 3834, category: 'chapter12', keywords: ['Luna response template Chapter 12'], question: "What template should Luna use for Chapter 12 topics?", response: "1. Clear disclaimer. 2. General educational summary. 3. Offer CycleMind bonding tracking (optional). 4. Strong redirect to perinatal or infant mental health specialist." },
  { id: 3835, category: 'chapter12', keywords: ['Chapter 12 authors'], question: "Who authored Chapter 12?", response: "Soudabeh Givrad, M.D., Jennifer J. Paul, Ph.D., Christine Wittmann, M.D., Mireya Nadal-Vicens, M.D., Ph.D., and Celeste St. John-Larkin, M.D." },
  { id: 3836, category: 'chapter12', keywords: ['infant mental health essentials'], question: "What are the essentials of infant mental health per Chapter 12?", response: "Infant mental health focuses on the infant's emotional, social, and relational development within the caregiving relationship from birth to age 3." },
  { id: 3837, category: 'chapter12', keywords: ['dyadic therapy parent infant'], question: "What is dyadic therapy?", response: "Dyadic therapies treat the parent–infant relationship as the patient, improving parental sensitivity and infant emotional regulation through joint sessions." },
  { id: 3838, category: 'chapter12', keywords: ['CycleMind feature ideas Chapter 12'], question: "What CycleMind features are inspired by Chapter 12?", response: "Gentle postpartum bonding tracker, reflective prompts, attachment education cards, and optional export for infant mental health clinicians." },
  { id: 3839, category: 'chapter12', keywords: ['Luna disclaimer infant relationship'], question: "What disclaimer is required for Chapter 12 topics?", response: "Luna must state she is not an infant mental health specialist and cannot evaluate or treat parent–infant relationships. This is general educational information only." },
  { id: 3840, category: 'chapter12', keywords: ['trauma parent infant relationship'], question: "How does parental trauma affect the parent–infant relationship?", response: "Maternal trauma history can impair reflective functioning and sensitive caregiving, increasing risk of disrupted attachment that benefits from targeted intervention." },
  { id: 3841, category: 'chapter12', keywords: ['Luna safety netting Chapter 12'], question: "What safety netting should Luna include?", response: "Luna should advise users concerned about bonding difficulties, infant safety, or their own mental health to contact their perinatal psychiatrist or pediatrician promptly." },
  { id: 3842, category: 'chapter12', keywords: ['reflective functioning parent infant'], question: "What is reflective functioning in the parent–infant context?", response: "Reflective functioning is the parent's capacity to understand their own and their infant's mental states; it is a key predictor of secure attachment." },
  { id: 3843, category: 'chapter12', keywords: ['CycleMind bonding education'], question: "How should CycleMind incorporate Chapter 12 education?", response: "Create compassionate, evidence-based cards on attachment, bonding, and early relational health with links to professional resources." },
  { id: 3844, category: 'chapter12', keywords: ['Luna response boundaries Chapter 12'], question: "What overarching boundaries apply to Luna for Chapter 12 content?", response: "Luna must never assess bonding, diagnose relational problems, or provide therapy. All responses remain general education and end with a clinician redirect." },
  { id: 3845, category: 'chapter12', keywords: ['Chapter 12 key takeaway for app'], question: "What is the primary takeaway from Chapter 12 for CycleMind?", response: "The parent–infant relationship is foundational for lifelong mental health; CycleMind should offer respectful, optional tracking and education while directing users to specialists." },
  { id: 3846, category: 'chapter12', keywords: ['video feedback interventions'], question: "Are video feedback interventions discussed?", response: "Yes. Video feedback is an effective dyadic intervention that helps parents observe and improve their interactions with their infant." },
  { id: 3847, category: 'chapter12', keywords: ['Circle of Security'], question: "Is Circle of Security mentioned?", response: "Yes. Circle of Security is a widely used attachment-based intervention that helps parents understand and respond to their infant's emotional needs." },
  { id: 3848, category: 'chapter12', keywords: ['CycleMind reflective prompts'], question: "Should CycleMind include reflective prompts?", response: "Optional gentle prompts (e.g., 'What do you notice about your baby's cues today?') can support reflective functioning without replacing professional guidance." },
  { id: 3849, category: 'chapter12', keywords: ['Luna educational content Chapter 12'], question: "How should Luna present Chapter 12 content?", response: "Luna should deliver hopeful, non-stigmatizing education on infant mental health and the parent–infant relationship while always encouraging professional support." },
  { id: 3850, category: 'chapter12', keywords: ['perinatal psychiatry infant mental health'], question: "What is the connection between perinatal psychiatry and infant mental health?", response: "Maternal perinatal mental health directly influences the parent–infant relationship and infant development, making integrated care essential." },
  { id: 3851, category: 'chapter12', keywords: ['Luna crisis redirect Chapter 12'], question: "What language should Luna use if bonding concerns escalate?", response: "Luna should use direct, compassionate language: 'If you're worried about your bond with your baby or your own mental health, please reach out to your perinatal psychiatrist or pediatrician right away.'" },
  { id: 3852, category: 'chapter12', keywords: ['integrated dyadic care'], question: "What model of care is emphasized?", response: "Chapter 12 advocates for integrated perinatal psychiatric and infant mental health services to support the parent–infant dyad." },
  { id: 3853, category: 'chapter12', keywords: ['CycleMind data export Chapter 12'], question: "How can CycleMind data support infant mental health care?", response: "Users can export bonding and relational observations to share with their infant mental health clinician or pediatrician." },
  { id: 3854, category: 'chapter12', keywords: ['Luna safety netting Chapter 12 b'], question: "What safety netting should Luna include?", response: "Luna should direct users concerned about infant safety, bonding difficulties, or their own mental health to contact their perinatal team or pediatrician immediately." },
  { id: 3855, category: 'chapter12', keywords: ['Chapter 12 key takeaway for app'], question: "What is the primary takeaway from Chapter 12 for CycleMind development?", response: "Supporting the parent–infant relationship is central to perinatal mental health; CycleMind should provide optional, respectful tools while ensuring users seek professional guidance." },

  // === Chapter 13: Depressive Disorders Across the Reproductive Lifespan (IDs 3856–3885) ===
  { id: 3856, category: 'chapter13', keywords: ['depressive disorders perinatal overview'], question: "What does Chapter 13 of the Textbook of Women's Reproductive Mental Health cover?", response: "Chapter 13 provides a detailed clinical approach to depressive disorders across the reproductive lifespan, with emphasis on perinatal depression, epidemiology, pathophysiology, screening, diagnosis, and evidence-based treatments." },
  { id: 3857, category: 'chapter13', keywords: ['perinatal depression prevalence'], question: "What is the prevalence of perinatal depression?", response: "Perinatal depression affects approximately 10–15% of women during pregnancy and up to 20% in the postpartum period, making it one of the most common complications of childbirth." },
  { id: 3858, category: 'chapter13', keywords: ['Edinburgh Postnatal Depression Scale EPDS'], question: "What screening tool is recommended for perinatal depression?", response: "The Edinburgh Postnatal Depression Scale (EPDS) is the most widely used and validated tool for screening depression in pregnancy and postpartum." },
  { id: 3859, category: 'chapter13', keywords: ['CycleMind depression tracking'], question: "How can CycleMind support depression tracking across reproductive stages?", response: "CycleMind can include integrated mood trackers with EPDS-style questions, phase-specific prompts (menstrual, pregnancy, postpartum, perimenopause), and clinician-export reports." },
  { id: 3860, category: 'chapter13', keywords: ['Luna boundaries depressive disorders'], question: "What boundaries should Luna observe for depressive disorders?", response: "Luna must state she is not a psychiatrist and cannot diagnose or treat depression. She can share general education from Chapter 13 and support symptom tracking but must always redirect to a qualified perinatal psychiatrist." },
  { id: 3861, category: 'chapter13', keywords: ['untreated perinatal depression risks'], question: "What risks are associated with untreated perinatal depression?", response: "Untreated depression increases risks of preterm birth, low birth weight, impaired maternal–infant bonding, and long-term child developmental issues." },
  { id: 3862, category: 'chapter13', keywords: ['SSRIs perinatal depression'], question: "What is the role of SSRIs in perinatal depression?", response: "SSRIs (especially sertraline) are first-line pharmacologic treatment for moderate-to-severe perinatal depression after risk-benefit discussion." },
  { id: 3863, category: 'chapter13', keywords: ['CBT IPT perinatal depression'], question: "What psychotherapy is recommended for perinatal depression?", response: "Cognitive-behavioral therapy (CBT) and interpersonal psychotherapy (IPT) are first-line non-pharmacologic treatments with strong evidence in the perinatal period." },
  { id: 3864, category: 'chapter13', keywords: ['CycleMind EPDS integration'], question: "Should CycleMind integrate the EPDS?", response: "Yes — optional, validated EPDS screening at key reproductive stages with clear disclaimers and immediate clinician referral pathways for elevated scores." },
  { id: 3865, category: 'chapter13', keywords: ['Luna response template Chapter 13'], question: "What template should Luna use for depressive disorder questions?", response: "1. Clear disclaimer. 2. General educational summary from Chapter 13. 3. Offer CycleMind mood tracking. 4. Strong redirect to perinatal psychiatrist." },
  { id: 3866, category: 'chapter13', keywords: ['Chapter 13 authors'], question: "Who authored Chapter 13?", response: "Lauren M. Osborne, M.D. and Catherine Birndorf, M.D." },
  { id: 3867, category: 'chapter13', keywords: ['perinatal depression pathophysiology'], question: "What pathophysiology is discussed for perinatal depression?", response: "Hormonal fluctuations, HPA-axis dysregulation, inflammation, and serotonin system changes contribute to vulnerability for depressive episodes during reproductive transitions." },
  { id: 3868, category: 'chapter13', keywords: ['postpartum depression vs baby blues'], question: "How does Chapter 13 differentiate baby blues from postpartum depression?", response: "Baby blues are transient, mild, and self-limited (resolving within 2 weeks). Postpartum depression is more severe, persistent, and meets full diagnostic criteria." },
  { id: 3869, category: 'chapter13', keywords: ['CycleMind mood correlation'], question: "How should CycleMind handle mood tracking for depressive disorders?", response: "CycleMind can correlate daily mood logs with reproductive phase (luteal, pregnancy trimester, postpartum weeks) to help users and clinicians identify patterns." },
  { id: 3870, category: 'chapter13', keywords: ['Luna disclaimer depression'], question: "What disclaimer is required for Chapter 13 topics?", response: "Luna must state she is not a psychiatrist and cannot diagnose or treat depressive disorders. This is general educational information only." },
  { id: 3871, category: 'chapter13', keywords: ['integrative approaches perinatal depression'], question: "Does Chapter 13 reference integrative treatments?", response: "Yes — Chapter 14 expands on integrative approaches, but Chapter 13 notes the role of exercise, omega-3s, and bright light therapy as adjuncts." },
  { id: 3872, category: 'chapter13', keywords: ['CycleMind feature ideas Chapter 13'], question: "What CycleMind features are inspired by Chapter 13?", response: "Comprehensive mood tracker with EPDS integration, reproductive-phase correlation charts, and depression education library with treatment overviews." },
  { id: 3873, category: 'chapter13', keywords: ['perinatal depression screening timing'], question: "When should screening occur per Chapter 13?", response: "Screening for depression is recommended at least once in pregnancy and at the postpartum visit, with additional screening as clinically indicated." },
  { id: 3874, category: 'chapter13', keywords: ['Luna safety netting depression'], question: "What safety netting should Luna include for depressive symptoms?", response: "Luna should advise users with passive or active suicidal thoughts, severe functional impairment, or inability to care for themselves or their infant to seek immediate professional help." },
  { id: 3875, category: 'chapter13', keywords: ['collaborative care depressive disorders'], question: "What model of care is emphasized?", response: "Collaborative care between reproductive psychiatrists, obstetricians, and primary providers optimizes outcomes for perinatal depressive disorders." },
  { id: 3876, category: 'chapter13', keywords: ['Luna educational content Chapter 13'], question: "How should Luna present Chapter 13 content?", response: "Luna should deliver hopeful, evidence-based education on perinatal depression while emphasizing effective treatments and the importance of professional care." },
  { id: 3877, category: 'chapter13', keywords: ['Chapter 13 key takeaway for app'], question: "What is the primary takeaway from Chapter 13 for CycleMind?", response: "Depressive disorders are common and treatable across reproductive stages; CycleMind should support accurate symptom tracking and facilitate connection to care." },
  { id: 3878, category: 'chapter13', keywords: ['Luna response boundaries Chapter 13'], question: "What overarching boundaries apply to Luna for Chapter 13 content?", response: "Luna must never diagnose depression, interpret screening scores, or recommend treatments. All responses remain general education and end with a clinician redirect." },
  { id: 3879, category: 'chapter13', keywords: ['pregnancy depression treatment'], question: "What is the approach to depression during pregnancy?", response: "Treatment decisions balance risks of medication exposure against risks of untreated illness, with SSRIs often used when benefits outweigh risks." },
  { id: 3880, category: 'chapter13', keywords: ['postpartum depression treatment'], question: "What is the approach to postpartum depression?", response: "SSRIs are first-line; psychotherapy (CBT/IPT) is highly effective. Breastfeeding compatibility and infant safety are key considerations in medication choice." },
  { id: 3881, category: 'chapter13', keywords: ['CycleMind EPDS scoring'], question: "Should CycleMind score the EPDS?", response: "Optional automated EPDS scoring with clear disclaimers and immediate clinician referral recommendations for elevated scores." },
  { id: 3882, category: 'chapter13', keywords: ['perinatal depression comorbidities'], question: "What comorbidities are common with perinatal depression?", response: "Anxiety disorders, OCD, PTSD, and substance use frequently co-occur and require comprehensive assessment and treatment." },
  { id: 3883, category: 'chapter13', keywords: ['CycleMind data export Chapter 13'], question: "How can CycleMind data support depressive disorder care?", response: "Users can export mood logs, EPDS results, and phase correlations to share with their psychiatrist for treatment planning." },
  { id: 3884, category: 'chapter13', keywords: ['Luna crisis redirect depression'], question: "What language should Luna use for depressive crisis?", response: "Luna should use direct, compassionate language: 'If you're having thoughts of harming yourself or your baby, please call your psychiatrist or emergency services right now.'" },
  { id: 3885, category: 'chapter13', keywords: ['Chapter 13 key takeaway for app'], question: "What is the primary takeaway from Chapter 13 for CycleMind development?", response: "Perinatal depression is common, under-recognized, and highly treatable; CycleMind should provide practical tracking and education while ensuring users reach professional care." },

  // === Chapter 14: Integrative Approaches to Perinatal Depression (IDs 3886–3915) ===
  { id: 3886, category: 'chapter14', keywords: ['integrative approaches perinatal depression overview'], question: "What does Chapter 14 of the Textbook of Women's Reproductive Mental Health cover?", response: "Chapter 14 reviews evidence-based integrative, complementary, and alternative medicine (CAM) approaches to perinatal depression, including nutrition, omega-3 fatty acids, exercise, yoga, acupuncture, mindfulness, SAM-e, St. John's wort, and light therapy." },
  { id: 3887, category: 'chapter14', keywords: ['omega-3 fatty acids perinatal depression'], question: "What is the evidence for omega-3s in perinatal depression?", response: "Omega-3 fatty acids (EPA/DHA) show promise as adjunctive treatment for perinatal depression with a favorable safety profile during pregnancy and lactation." },
  { id: 3888, category: 'chapter14', keywords: ['exercise perinatal depression'], question: "What role does exercise play in treating perinatal depression?", response: "Regular moderate exercise (150 minutes/week) is an effective non-pharmacologic intervention for mild-to-moderate perinatal depression and improves overall maternal well-being." },
  { id: 3889, category: 'chapter14', keywords: ['CycleMind integrative tracking'], question: "How can CycleMind support integrative approaches from Chapter 14?", response: "CycleMind can include optional logs for exercise, nutrition (omega-3 intake), mindfulness practice, and sleep hygiene to help users track integrative strategies alongside mood symptoms." },
  { id: 3890, category: 'chapter14', keywords: ['Luna boundaries integrative treatments'], question: "What boundaries should Luna observe for integrative approaches?", response: "Luna must state she is not a physician and cannot recommend supplements, herbs, or therapies. She can share general evidence summaries from Chapter 14 and support tracking but must always redirect to the user's perinatal psychiatrist or OB/GYN for personalized advice." },
  { id: 3891, category: 'chapter14', keywords: ['yoga mindfulness perinatal depression'], question: "What is the evidence for yoga and mindfulness?", response: "Mindfulness-based interventions and prenatal yoga reduce depressive symptoms, anxiety, and stress in pregnant and postpartum women with good safety profiles." },
  { id: 3892, category: 'chapter14', keywords: ['acupuncture perinatal depression'], question: "Is acupuncture discussed for perinatal depression?", response: "Acupuncture shows preliminary evidence of benefit for perinatal depression and is generally considered safe when performed by trained practitioners." },
  { id: 3893, category: 'chapter14', keywords: ['SAM-e perinatal depression'], question: "What is the role of SAM-e?", response: "S-adenosylmethionine (SAM-e) has antidepressant effects and may be a safe adjunctive option, though more perinatal safety data are needed." },
  { id: 3894, category: 'chapter14', keywords: ['CycleMind nutrition exercise logs'], question: "What integrative logging features should CycleMind include?", response: "Optional pregnancy-safe nutrition (omega-3 rich foods), exercise minutes, and mindfulness minutes trackers with correlation to mood outcomes." },
  { id: 3895, category: 'chapter14', keywords: ['Luna response template Chapter 14'], question: "What template should Luna use for integrative approaches?", response: "1. Clear disclaimer. 2. General evidence summary from Chapter 14. 3. Offer CycleMind integrative tracking. 4. Strong redirect to perinatal psychiatrist or OB/GYN." },
  { id: 3896, category: 'chapter14', keywords: ['St John wort perinatal depression'], question: "Is St. John's wort recommended?", response: "St. John's wort has drug interactions (including with many psychotropics) and limited perinatal safety data; it is generally not recommended during pregnancy or lactation." },
  { id: 3897, category: 'chapter14', keywords: ['bright light therapy perinatal depression'], question: "What is the evidence for bright light therapy?", response: "Morning bright light therapy is a safe, non-pharmacologic option with emerging evidence for perinatal depression, particularly when seasonal factors are present." },
  { id: 3898, category: 'chapter14', keywords: ['Chapter 14 authors'], question: "Who authored Chapter 14?", response: "Madeleine A. Becker, M.D., M.A., M. Camille Hoffman, M.D., M.Sc., Nina T. Ballone, M.D., and Ripal Shah, M.D., M.P.H." },
  { id: 3899, category: 'chapter14', keywords: ['integrative vs conventional treatment'], question: "How do integrative approaches fit with conventional care?", response: "Integrative approaches are best used as adjuncts to evidence-based psychotherapy and/or medication after thorough risk-benefit discussion with the perinatal team." },
  { id: 3900, category: 'chapter14', keywords: ['CycleMind feature ideas Chapter 14'], question: "What CycleMind features are inspired by Chapter 14?", response: "Integrative wellness tracker (exercise, nutrition, mindfulness, light exposure) with mood correlation and safety disclaimers." },
  { id: 3901, category: 'chapter14', keywords: ['Luna disclaimer supplements'], question: "What disclaimer is required for supplements and herbs?", response: "Luna must state she is not a clinician and cannot recommend any supplement, herb, or CAM therapy. Users should discuss all integrative approaches with their perinatal psychiatrist or OB/GYN." },
  { id: 3902, category: 'chapter14', keywords: ['nutrition perinatal depression'], question: "What nutritional factors are discussed?", response: "Adequate intake of omega-3 fatty acids, folate, vitamin D, and overall Mediterranean-style diet may support mood during the perinatal period." },
  { id: 3903, category: 'chapter14', keywords: ['Luna educational content Chapter 14'], question: "How should Luna present Chapter 14 content?", response: "Luna should deliver balanced, evidence-based summaries of integrative options while emphasizing that they are adjunctive and require professional oversight." },
  { id: 3904, category: 'chapter14', keywords: ['safety integrative treatments pregnancy'], question: "What safety considerations are emphasized?", response: "All integrative treatments must be evaluated for pregnancy and lactation safety; some herbs and high-dose supplements carry risks and require medical supervision." },
  { id: 3905, category: 'chapter14', keywords: ['CycleMind data export integrative'], question: "How can CycleMind data support integrative care discussions?", response: "Users can export exercise, nutrition, and mindfulness logs alongside mood data to facilitate informed conversations with their perinatal team." },
  { id: 3906, category: 'chapter14', keywords: ['Luna safety netting Chapter 14'], question: "What safety netting should Luna include?", response: "Luna should advise users to consult their provider before starting any supplement, herb, or new exercise regimen during pregnancy or lactation." },
  { id: 3907, category: 'chapter14', keywords: ['mindfulness based interventions'], question: "What mindfulness interventions are reviewed?", response: "Mindfulness-Based Cognitive Therapy (MBCT) and Mindfulness-Based Stress Reduction (MBSR) adapted for pregnancy show benefit for preventing and treating perinatal depression." },
  { id: 3908, category: 'chapter14', keywords: ['Luna response boundaries Chapter 14'], question: "What overarching boundaries apply to Luna for Chapter 14 content?", response: "Luna must never recommend specific integrative treatments or interpret their suitability for an individual user. All responses remain general education and end with a clinician redirect." },
  { id: 3909, category: 'chapter14', keywords: ['Chapter 14 key takeaway for app'], question: "What is the primary takeaway from Chapter 14 for CycleMind?", response: "Integrative approaches are valuable adjuncts for perinatal depression; CycleMind should support tracking of safe, evidence-based lifestyle strategies while maintaining strict clinical boundaries." },
  { id: 3910, category: 'chapter14', keywords: ['yoga perinatal depression evidence'], question: "What is the evidence level for yoga?", response: "Prenatal yoga has moderate evidence for reducing depressive and anxiety symptoms and improving overall well-being during pregnancy." },
  { id: 3911, category: 'chapter14', keywords: ['CycleMind wellness dashboard'], question: "Should CycleMind include a wellness dashboard?", response: "Yes — an optional integrative wellness dashboard combining mood tracking with exercise, nutrition, mindfulness, and sleep metrics for a holistic view." },
  { id: 3912, category: 'chapter14', keywords: ['integrative care collaboration'], question: "What is emphasized about integrative care?", response: "Integrative approaches work best within a collaborative model involving the perinatal psychiatrist, OB/GYN, and other specialists." },
  { id: 3913, category: 'chapter14', keywords: ['Luna crisis redirect Chapter 14'], question: "What language should Luna use if depressive symptoms worsen?", response: "Luna should use direct, compassionate language: 'If your mood is worsening, please contact your perinatal psychiatrist or OB/GYN right away for support.'" },
  { id: 3914, category: 'chapter14', keywords: ['perinatal depression adjunctive therapies'], question: "Are integrative therapies considered first-line?", response: "No. Psychotherapy and/or medication remain first-line; integrative therapies are valuable adjuncts for mild-to-moderate symptoms or as augmentation." },
  { id: 3915, category: 'chapter14', keywords: ['Chapter 14 key takeaway for app'], question: "What is the primary takeaway from Chapter 14 for CycleMind development?", response: "Evidence-based integrative strategies can complement conventional care; CycleMind should offer practical tracking tools with clear disclaimers and professional referral pathways." },

  // === Chapter 15: Bipolar Disorder in Reproductive Context (IDs 3916–3945) ===
  { id: 3916, category: 'chapter15', keywords: ['bipolar disorder reproductive context overview'], question: "What does Chapter 15 of the Textbook of Women's Reproductive Mental Health cover?", response: "Chapter 15 reviews bipolar disorder and related disorders across reproductive transitions, with emphasis on pregnancy and postpartum risks, medication management, and clinical decision-making." },
  { id: 3917, category: 'chapter15', keywords: ['bipolar relapse pregnancy postpartum'], question: "What is the risk of bipolar relapse in the perinatal period?", response: "Women with bipolar disorder have a markedly elevated risk of mood episode recurrence during pregnancy and especially postpartum; proactive planning is essential." },
  { id: 3918, category: 'chapter15', keywords: ['lithium pregnancy'], question: "What are the considerations for lithium in pregnancy?", response: "Lithium requires careful monitoring due to teratogenic risks (Ebstein's anomaly) and changes in renal clearance during pregnancy; benefits often outweigh risks in stable patients with close monitoring." },
  { id: 3919, category: 'chapter15', keywords: ['CycleMind bipolar tracking'], question: "How can CycleMind support users with bipolar disorder?", response: "CycleMind can include mood polarity tracking (mania/hypomania/depression) tied to reproductive phases, medication logs, and sleep monitoring to help users and clinicians detect early warning signs." },
  { id: 3920, category: 'chapter15', keywords: ['Luna boundaries bipolar disorder'], question: "What boundaries should Luna observe for bipolar disorder?", response: "Luna must state she is not a psychiatrist and cannot diagnose, manage, or adjust medications for bipolar disorder. She can share general education from Chapter 15 and support symptom tracking but must always redirect to the user's perinatal psychiatrist." },
  { id: 3921, category: 'chapter15', keywords: ['atypical antipsychotics pregnancy'], question: "What is the evidence for atypical antipsychotics in pregnancy?", response: "Atypical antipsychotics are increasingly used for bipolar disorder in pregnancy; individual agents have varying safety profiles that must be discussed in risk-benefit analysis." },
  { id: 3922, category: 'chapter15', keywords: ['lamotrigine pregnancy'], question: "What are the considerations for lamotrigine in pregnancy?", response: "Lamotrigine is often preferred for bipolar depression in pregnancy due to a relatively favorable safety profile, though dose adjustments are required due to increased clearance." },
  { id: 3923, category: 'chapter15', keywords: ['CycleMind mood polarity tracker'], question: "What bipolar-specific tracking should CycleMind include?", response: "Optional mood polarity (depression, mania/hypomania, mixed) logging with sleep, energy, and reproductive-phase correlations to support early detection of episodes." },
  { id: 3924, category: 'chapter15', keywords: ['Luna response template Chapter 15'], question: "What template should Luna use for bipolar questions?", response: "1. Clear disclaimer. 2. General educational summary from Chapter 15. 3. Offer CycleMind mood tracking. 4. Strong redirect to perinatal psychiatrist." },
  { id: 3925, category: 'chapter15', keywords: ['Chapter 15 authors'], question: "Who authored Chapter 15?", response: "Sarah M. Nagle-Yang, M.D., Sarah A. DeBrunner, M.D., Andrea Favini, M.D., Andrew M. Novick, M.D., Ph.D., Caitlin Hasser, M.D., Chandni Prakash, M.D., and Margo Nathan, M.D." },
  { id: 3926, category: 'chapter15', keywords: ['postpartum bipolar relapse risk'], question: "What is the postpartum relapse risk for bipolar disorder?", response: "The postpartum period carries the highest risk of relapse for women with bipolar disorder; prophylactic medication adjustment and sleep protection are critical." },
  { id: 3927, category: 'chapter15', keywords: ['valproate pregnancy contraindication'], question: "Why is valproate generally avoided in pregnancy?", response: "Valproate has high teratogenic risk (neural tube defects, cognitive teratogenicity) and is typically avoided or used only when no safer alternatives exist." },
  { id: 3928, category: 'chapter15', keywords: ['CycleMind medication mood log'], question: "Should CycleMind include medication-mood logging for bipolar users?", response: "Yes — optional, private logs of mood stabilizer or antipsychotic use with symptom correlation to help users prepare for clinical appointments." },
  { id: 3929, category: 'chapter15', keywords: ['Luna disclaimer bipolar medications'], question: "What disclaimer is required for bipolar medication topics?", response: "Luna must state she is not a prescribing clinician and cannot recommend or adjust any psychiatric medications. All decisions require discussion with a perinatal psychiatrist." },
  { id: 3930, category: 'chapter15', keywords: ['rapid cycling bipolar perinatal'], question: "Does Chapter 15 address rapid cycling?", response: "Yes. Pregnancy and postpartum hormonal changes can trigger or exacerbate rapid cycling in women with bipolar disorder." },
  { id: 3931, category: 'chapter15', keywords: ['CycleMind feature ideas Chapter 15'], question: "What CycleMind features are inspired by Chapter 15?", response: "Bipolar mood polarity tracker, sleep monitoring (key trigger), medication-mood correlations, and reproductive-phase alerts for high-risk periods." },
  { id: 3932, category: 'chapter15', keywords: ['Luna safety netting bipolar'], question: "What safety netting should Luna include?", response: "Luna should advise immediate contact with the perinatal psychiatrist for signs of mania, mixed episodes, severe depression, or suicidal thoughts." },
  { id: 3933, category: 'chapter15', keywords: ['integrated care bipolar perinatal'], question: "What model of care is emphasized?", response: "Close collaboration between reproductive psychiatrists, obstetricians, and neonatologists is essential for women with bipolar disorder during pregnancy and postpartum." },
  { id: 3934, category: 'chapter15', keywords: ['Luna educational content Chapter 15'], question: "How should Luna present Chapter 15 content?", response: "Luna should deliver balanced education on perinatal risks and management strategies while always emphasizing individualized care with a qualified psychiatrist." },
  { id: 3935, category: 'chapter15', keywords: ['Chapter 15 key takeaway for app'], question: "What is the primary takeaway from Chapter 15 for CycleMind?", response: "Bipolar disorder requires vigilant monitoring during reproductive transitions; CycleMind should provide mood and sleep tracking tools while maintaining strict clinical boundaries." },
  { id: 3936, category: 'chapter15', keywords: ['Luna response boundaries Chapter 15'], question: "What overarching boundaries apply to Luna for Chapter 15 content?", response: "Luna must never diagnose bipolar disorder, interpret mood charts clinically, or recommend medication changes. All responses remain general education and end with a clinician redirect." },
  { id: 3937, category: 'chapter15', keywords: ['postpartum prophylaxis bipolar'], question: "What postpartum prophylaxis is discussed?", response: "Prophylactic medication adjustment (often increasing mood stabilizer dose) and close monitoring are recommended immediately after delivery for women with bipolar disorder." },
  { id: 3938, category: 'chapter15', keywords: ['CycleMind sleep bipolar trigger'], question: "Why is sleep tracking important for bipolar users?", response: "Sleep disruption is a major trigger for manic episodes; CycleMind's sleep tracker can help users and clinicians identify early warning signs in the perinatal period." },
  { id: 3939, category: 'chapter15', keywords: ['lamotrigine clearance pregnancy'], question: "What happens to lamotrigine levels in pregnancy?", response: "Lamotrigine clearance increases significantly during pregnancy, often requiring dose increases and close level monitoring." },
  { id: 3940, category: 'chapter15', keywords: ['CycleMind data export bipolar'], question: "How can CycleMind data support bipolar care?", response: "Users can export mood polarity, sleep, and medication logs to share with their reproductive psychiatrist for treatment optimization." },
  { id: 3941, category: 'chapter15', keywords: ['Luna crisis redirect bipolar'], question: "What language should Luna use for bipolar crisis?", response: "Luna should use direct, compassionate language: 'Signs of mania or severe depression require immediate help. Please contact your perinatal psychiatrist or emergency services right away.'" },
  { id: 3942, category: 'chapter15', keywords: ['integrated obstetric psychiatric care bipolar'], question: "What is emphasized about care for bipolar disorder?", response: "Seamless integration of psychiatric and obstetric care is critical for women with bipolar disorder throughout pregnancy and the postpartum period." },
  { id: 3943, category: 'chapter15', keywords: ['perimenopause bipolar'], question: "Does Chapter 15 address perimenopause?", response: "Yes. Hormonal changes in perimenopause can destabilize bipolar disorder, increasing depressive or mixed episode risk." },
  { id: 3944, category: 'chapter15', keywords: ['CycleMind bipolar education'], question: "How should CycleMind incorporate Chapter 15 education?", response: "Create clear cards on perinatal risks, medication considerations, and the importance of close monitoring for women with bipolar disorder." },
  { id: 3945, category: 'chapter15', keywords: ['Chapter 15 key takeaway for app'], question: "What is the primary takeaway from Chapter 15 for CycleMind development?", response: "Bipolar disorder in the reproductive context requires specialized, proactive management; CycleMind should support mood and sleep tracking while ensuring users remain connected to expert clinical care." },

  // === Chapter 16: Postpartum Psychosis (IDs 3946–3975) ===
  { id: 3946, category: 'chapter16', keywords: ['postpartum psychosis overview'], question: "What does Chapter 16 of the Textbook of Women's Reproductive Mental Health cover?", response: "Chapter 16 provides a comprehensive clinical guide to postpartum psychosis, including epidemiology, risk factors, presentation, differential diagnosis, urgent treatment, safety planning, and long-term management." },
  { id: 3947, category: 'chapter16', keywords: ['postpartum psychosis prevalence'], question: "What is the prevalence and timing of postpartum psychosis?", response: "Postpartum psychosis occurs in 1–2 per 1,000 births, most commonly in the first 2–4 weeks postpartum, with peak onset in the first 10 days." },
  { id: 3948, category: 'chapter16', keywords: ['risk factors postpartum psychosis'], question: "What are the major risk factors for postpartum psychosis?", response: "Personal or family history of bipolar disorder, prior postpartum psychosis, first pregnancy, and sleep deprivation are the strongest risk factors." },
  { id: 3949, category: 'chapter16', keywords: ['CycleMind psychosis alerts'], question: "How can CycleMind support early detection of postpartum psychosis?", response: "CycleMind can include optional postpartum psychosis warning sign screeners (mood lability, confusion, paranoia, sleep loss) with immediate crisis resource buttons and clinician alerts." },
  { id: 3950, category: 'chapter16', keywords: ['Luna boundaries postpartum psychosis'], question: "What boundaries should Luna observe for postpartum psychosis?", response: "Luna must state she is not a clinician and cannot diagnose or treat psychosis. She can share general education from Chapter 16 and support symptom tracking but must immediately redirect any user reporting possible psychotic symptoms to emergency services or their perinatal psychiatrist." },
  { id: 3951, category: 'chapter16', keywords: ['postpartum psychosis presentation'], question: "What are the classic symptoms of postpartum psychosis?", response: "Rapid onset of mood lability, insomnia, confusion, delusions (often infant-related), hallucinations, and disorganized thinking in the early postpartum period." },
  { id: 3952, category: 'chapter16', keywords: ['treatment postpartum psychosis'], question: "What is the first-line treatment for postpartum psychosis?", response: "Immediate hospitalization, antipsychotics (often atypical), mood stabilizers (lithium or valproate when appropriate), and benzodiazepines for agitation/sleep are standard; ECT may be used for severe or refractory cases." },
  { id: 3953, category: 'chapter16', keywords: ['infant safety postpartum psychosis'], question: "What infant safety measures are emphasized?", response: "Chapter 16 stresses assessment of maternal capacity to care for the infant, supervised visits when indicated, and family/support involvement until stability is achieved." },
  { id: 3954, category: 'chapter16', keywords: ['CycleMind safety features psychosis'], question: "What safety features should CycleMind include for postpartum psychosis risk?", response: "One-tap crisis resources, psychosis warning sign checklists, sleep disruption alerts, and automatic log export for emergency providers." },
  { id: 3955, category: 'chapter16', keywords: ['Luna response template Chapter 16'], question: "What template should Luna use for postpartum psychosis questions?", response: "1. Immediate safety redirect and crisis resources. 2. General educational summary. 3. Offer CycleMind tracking once safety is addressed. 4. Strong emphasis on professional emergency care." },
  { id: 3956, category: 'chapter16', keywords: ['Chapter 16 authors'], question: "Who authored Chapter 16?", response: "Caitlin Hasser, M.D., Jovana Martinovic, M.D., Pooja Lakshmin, M.D., Mira Zein, M.D., Melisa Olgun, B.A., Lucy A. Hutner, M.D., Sarah M. Nagle-Yang, M.D., and Lauren M. Osborne, M.D." },
  { id: 3957, category: 'chapter16', keywords: ['postpartum psychosis differential diagnosis'], question: "What is the differential diagnosis for postpartum psychosis?", response: "Includes bipolar mania with psychotic features, severe major depression with psychotic features, delirium, substance-induced psychosis, and autoimmune encephalitis." },
  { id: 3958, category: 'chapter16', keywords: ['lithium postpartum psychosis'], question: "What is the role of lithium in postpartum psychosis?", response: "Lithium is often a first-line mood stabilizer for postpartum psychosis in women with known bipolar disorder, with careful monitoring of levels and infant safety if breastfeeding." },
  { id: 3959, category: 'chapter16', keywords: ['CycleMind psychosis education'], question: "How should CycleMind incorporate Chapter 16 education?", response: "Create clear, non-alarmist warning sign cards for postpartum psychosis with one-tap access to crisis resources and clinician referral pathways." },
  { id: 3960, category: 'chapter16', keywords: ['Luna disclaimer postpartum psychosis'], question: "What disclaimer is required for Chapter 16 topics?", response: "Luna must state she is not a clinician and cannot diagnose or treat postpartum psychosis. Any possible psychotic symptoms require immediate professional evaluation." },
  { id: 3961, category: 'chapter16', keywords: ['breastfeeding postpartum psychosis'], question: "How is breastfeeding addressed in postpartum psychosis?", response: "Breastfeeding decisions must balance maternal stability, medication safety, and infant well-being; temporary interruption may be necessary during acute treatment." },
  { id: 3962, category: 'chapter16', keywords: ['CycleMind data export psychosis'], question: "How can CycleMind data assist in postpartum psychosis care?", response: "Users (or family members with consent) can export recent sleep, mood, and symptom logs to share with emergency or inpatient psychiatric teams." },
  { id: 3963, category: 'chapter16', keywords: ['Luna crisis redirect psychosis'], question: "What language should Luna use for possible postpartum psychosis?", response: "Luna should use direct, compassionate language: 'Symptoms like confusion, unusual thoughts about your baby, or severe sleep loss can indicate a medical emergency. Please call 911 or your perinatal psychiatrist right now.'" },
  { id: 3964, category: 'chapter16', keywords: ['postpartum psychosis prophylaxis'], question: "What prophylaxis is recommended for high-risk women?", response: "For women with prior postpartum psychosis or bipolar disorder, prophylactic mood stabilizer or antipsychotic treatment immediately after delivery is often recommended." },
  { id: 3965, category: 'chapter16', keywords: ['Luna response boundaries Chapter 16'], question: "What overarching boundaries apply to Luna for Chapter 16 content?", response: "Luna must never assess, diagnose, or manage postpartum psychosis. Every response must prioritize immediate professional emergency care." },
  { id: 3966, category: 'chapter16', keywords: ['Chapter 16 key takeaway for app'], question: "What is the primary takeaway from Chapter 16 for CycleMind?", response: "Postpartum psychosis is a treatable but life-threatening emergency; CycleMind must include rapid safety tools, warning sign education, and crisis pathways while maintaining strict boundaries." },
  { id: 3967, category: 'chapter16', keywords: ['antipsychotics postpartum psychosis'], question: "What antipsychotics are commonly used?", response: "Second-generation antipsychotics (olanzapine, quetiapine, risperidone) are frequently used due to efficacy and relatively favorable perinatal safety profiles." },
  { id: 3968, category: 'chapter16', keywords: ['CycleMind sleep psychosis alert'], question: "Why is sleep disruption a key alert in CycleMind?", response: "Severe insomnia is often the earliest and most reliable prodromal sign of postpartum psychosis; CycleMind can flag significant sleep loss for user and clinician attention." },
  { id: 3969, category: 'chapter16', keywords: ['family involvement postpartum psychosis'], question: "What role does family play?", response: "Family members are often the first to notice early signs; Chapter 16 encourages education of partners and family about warning signs and safety planning." },
  { id: 3970, category: 'chapter16', keywords: ['Luna educational content Chapter 16'], question: "How should Luna present Chapter 16 content?", response: "Luna should deliver clear, action-oriented education on recognition and urgency of postpartum psychosis while always directing users to immediate professional help." },
  { id: 3971, category: 'chapter16', keywords: ['ECT postpartum psychosis'], question: "Is ECT used for postpartum psychosis?", response: "Yes. Electroconvulsive therapy is a safe and rapidly effective treatment for severe postpartum psychosis, particularly when medication response is inadequate." },
  { id: 3972, category: 'chapter16', keywords: ['CycleMind family sharing psychosis'], question: "Should CycleMind support family sharing of psychosis warning signs?", response: "Optional, consent-based family sharing of recent symptom logs or warning sign alerts can be included to support early detection." },
  { id: 3973, category: 'chapter16', keywords: ['Luna safety netting Chapter 16'], question: "What safety netting should Luna include?", response: "Luna should provide immediate crisis numbers, urge contact with emergency services or the perinatal psychiatrist, and remain available to help the user reach support." },
  { id: 3974, category: 'chapter16', keywords: ['postpartum psychosis recurrence risk'], question: "What is the recurrence risk?", response: "Women with a history of postpartum psychosis have a 50–80% risk of recurrence in subsequent pregnancies/postpartum periods; prophylaxis is often indicated." },
  { id: 3975, category: 'chapter16', keywords: ['Chapter 16 key takeaway for app'], question: "What is the primary takeaway from Chapter 16 for CycleMind development?", response: "Postpartum psychosis demands rapid recognition and intervention; CycleMind must prioritize safety features, warning sign education, and crisis pathways while never replacing professional care." },

  // === Chapter 17: Schizophrenia and Related Disorders in Reproductive Context (IDs 3976–4005) ===
  { id: 3976, category: 'chapter17', keywords: ['schizophrenia reproductive context overview'], question: "What does Chapter 17 of the Textbook of Women's Reproductive Mental Health cover?", response: "Chapter 17 reviews schizophrenia and related psychotic disorders in women across reproductive transitions, with focus on pregnancy and postpartum management, medication safety, relapse prevention, and parenting considerations." },
  { id: 3977, category: 'chapter17', keywords: ['schizophrenia pregnancy relapse risk'], question: "What is the risk of relapse in pregnancy for women with schizophrenia?", response: "Pregnancy is a period of relative stability for many women with schizophrenia, but medication discontinuation or dose reduction can lead to relapse; careful monitoring is required." },
  { id: 3978, category: 'chapter17', keywords: ['antipsychotics pregnancy safety'], question: "What is the evidence for antipsychotics in pregnancy?", response: "Most second-generation antipsychotics have reassuring safety data; first-generation agents are also used. Risks must be weighed against the high morbidity of untreated psychosis." },
  { id: 3979, category: 'chapter17', keywords: ['CycleMind schizophrenia tracking'], question: "How can CycleMind support women with schizophrenia?", response: "CycleMind can include optional symptom trackers for positive/negative symptoms, medication adherence, sleep, and functioning tied to reproductive phases to facilitate early detection of relapse." },
  { id: 3980, category: 'chapter17', keywords: ['Luna boundaries schizophrenia'], question: "What boundaries should Luna observe for schizophrenia and related disorders?", response: "Luna must state she is not a psychiatrist and cannot diagnose, manage, or adjust medications for schizophrenia. She can share general education from Chapter 17 and support symptom tracking but must always redirect to the user's perinatal psychiatrist." },
  { id: 3981, category: 'chapter17', keywords: ['postpartum psychosis schizophrenia'], question: "What is the relationship between schizophrenia and postpartum psychosis?", response: "Women with schizophrenia have elevated risk of postpartum psychotic relapse; prophylactic antipsychotic continuation and close monitoring are recommended." },
  { id: 3982, category: 'chapter17', keywords: ['breastfeeding antipsychotics'], question: "What breastfeeding considerations are discussed?", response: "Most antipsychotics are compatible with breastfeeding at low infant exposure levels; individual agent selection and monitoring are essential." },
  { id: 3983, category: 'chapter17', keywords: ['CycleMind medication adherence schizophrenia'], question: "Should CycleMind include medication adherence tracking for schizophrenia?", response: "Optional, private medication logs with mood/symptom correlation can help users and clinicians monitor adherence during reproductive transitions." },
  { id: 3984, category: 'chapter17', keywords: ['Luna response template Chapter 17'], question: "What template should Luna use for schizophrenia questions?", response: "1. Clear disclaimer. 2. General educational summary from Chapter 17. 3. Offer CycleMind symptom/medication tracking. 4. Strong redirect to perinatal psychiatrist." },
  { id: 3985, category: 'chapter17', keywords: ['Chapter 17 authors'], question: "Who authored Chapter 17?", response: "Sarah M. Nagle-Yang, M.D., Susan Hatters Friedman, M.D., Caitlin Hasser, M.D., Ashley Mulvihill, M.D., Andrew M. Novick, M.D., Ph.D., Allyce K. Jones, DNP, MSN, PMHNP-BC, APRN, Eric Reed, M.D., and Surya Sabhapathy, M.D., M.P.H." },
  { id: 3986, category: 'chapter17', keywords: ['parenting schizophrenia'], question: "What parenting considerations are addressed?", response: "Chapter 17 discusses the challenges and supports needed for mothers with schizophrenia to safely parent, including custody concerns, family involvement, and community resources." },
  { id: 3987, category: 'chapter17', keywords: ['first generation vs second generation antipsychotics pregnancy'], question: "How do first- and second-generation antipsychotics compare in pregnancy?", response: "Second-generation agents are generally preferred due to lower extrapyramidal side effect risk; both classes have extensive safety data but require individualized selection." },
  { id: 3988, category: 'chapter17', keywords: ['CycleMind psychosis symptom tracker'], question: "What psychosis-specific tracking should CycleMind include?", response: "Optional, private tracking of hallucinations, delusions, disorganized thinking, and negative symptoms with reproductive-phase correlation and clinician export." },
  { id: 3989, category: 'chapter17', keywords: ['Luna disclaimer schizophrenia medications'], question: "What disclaimer is required for schizophrenia medication topics?", response: "Luna must state she is not a prescribing clinician and cannot recommend or adjust any antipsychotic or other psychiatric medication. All decisions require consultation with a perinatal psychiatrist." },
  { id: 3990, category: 'chapter17', keywords: ['schizophrenia perimenopause'], question: "Does Chapter 17 address perimenopause?", response: "Yes. Hormonal changes in perimenopause can exacerbate psychotic symptoms in women with schizophrenia; dose adjustments and monitoring may be needed." },
  { id: 3991, category: 'chapter17', keywords: ['CycleMind feature ideas Chapter 17'], question: "What CycleMind features are inspired by Chapter 17?", response: "Schizophrenia symptom tracker, medication adherence log, reproductive-phase alerts, and parenting support resource links." },
  { id: 3992, category: 'chapter17', keywords: ['Luna safety netting schizophrenia'], question: "What safety netting should Luna include?", response: "Luna should direct users with worsening psychotic symptoms, suicidal thoughts, or concerns about infant safety to contact their perinatal psychiatrist or emergency services immediately." },
  { id: 3993, category: 'chapter17', keywords: ['integrated care schizophrenia perinatal'], question: "What model of care is emphasized?", response: "Multidisciplinary collaboration between reproductive psychiatrists, obstetricians, pediatricians, and social support services is critical for women with schizophrenia." },
  { id: 3994, category: 'chapter17', keywords: ['Luna educational content Chapter 17'], question: "How should Luna present Chapter 17 content?", response: "Luna should deliver hopeful, destigmatizing education on schizophrenia management during reproductive transitions while always emphasizing professional care." },
  { id: 3995, category: 'chapter17', keywords: ['Chapter 17 key takeaway for app'], question: "What is the primary takeaway from Chapter 17 for CycleMind?", response: "Schizophrenia requires ongoing, specialized management across reproductive stages; CycleMind should provide practical tracking tools while maintaining strict clinical boundaries." },
  { id: 3996, category: 'chapter17', keywords: ['Luna response boundaries Chapter 17'], question: "What overarching boundaries apply to Luna for Chapter 17 content?", response: "Luna must never diagnose schizophrenia, assess psychotic symptoms, or recommend medication changes. All responses remain general education and end with a clinician redirect." },
  { id: 3997, category: 'chapter17', keywords: ['postpartum relapse schizophrenia'], question: "What is the postpartum relapse risk for schizophrenia?", response: "Women with schizophrenia have a significantly increased risk of psychotic relapse in the postpartum period; prophylactic antipsychotic continuation is often indicated." },
  { id: 3998, category: 'chapter17', keywords: ['CycleMind sleep schizophrenia'], question: "Why is sleep tracking important for schizophrenia users?", response: "Sleep disruption is a common prodrome of psychotic decompensation; CycleMind's sleep tracker can help users and clinicians identify early warning signs." },
  { id: 3999, category: 'chapter17', keywords: ['parenting support schizophrenia'], question: "What parenting support is discussed?", response: "Chapter 17 highlights the need for practical supports (home visiting, parenting programs, custody planning) to help mothers with schizophrenia safely parent." },
  { id: 4000, category: 'chapter17', keywords: ['CycleMind data export schizophrenia'], question: "How can CycleMind data support schizophrenia care?", response: "Users can export symptom logs, medication adherence, and sleep data to share with their reproductive psychiatrist for treatment optimization." },
  { id: 4001, category: 'chapter17', keywords: ['Luna crisis redirect schizophrenia'], question: "What language should Luna use for schizophrenia crisis?", response: "Luna should use direct, compassionate language: 'Worsening psychotic symptoms or safety concerns require immediate help. Please contact your perinatal psychiatrist or emergency services right away.'" },
  { id: 4002, category: 'chapter17', keywords: ['antipsychotic monitoring pregnancy'], question: "What monitoring is recommended for antipsychotics in pregnancy?", response: "Fetal ultrasound for major malformations, maternal metabolic monitoring, and neonatal observation for withdrawal or extrapyramidal signs are standard." },
  { id: 4003, category: 'chapter17', keywords: ['CycleMind schizophrenia education'], question: "How should CycleMind incorporate Chapter 17 education?", response: "Create clear, non-stigmatizing cards on schizophrenia management during reproductive transitions with links to professional resources." },
  { id: 4004, category: 'chapter17', keywords: ['Luna safety netting Chapter 17'], question: "What safety netting should Luna include?", response: "Luna should advise users with worsening psychotic symptoms, thoughts of harm, or concerns about infant safety to seek immediate professional help." },
  { id: 4005, category: 'chapter17', keywords: ['Chapter 17 key takeaway for app'], question: "What is the primary takeaway from Chapter 17 for CycleMind development?", response: "Women with schizophrenia can have successful reproductive experiences with specialized, proactive care; CycleMind should support symptom and medication tracking while ensuring users remain connected to expert clinical teams." },

  // === Chapter 18: Trauma and Reproductive Health (IDs 4006–4035) ===
  { id: 4006, category: 'chapter18', keywords: ['trauma reproductive health overview'], question: "What does Chapter 18 of the Textbook of Women's Reproductive Mental Health cover?", response: "Chapter 18 explores the intersection of trauma (including childhood abuse, sexual trauma, intimate partner violence) with reproductive health, pregnancy, childbirth, and mental health outcomes." },
  { id: 4007, category: 'chapter18', keywords: ['trauma informed care reproductive psychiatry'], question: "What is trauma-informed care in reproductive psychiatry?", response: "Trauma-informed care emphasizes safety, trustworthiness, choice, collaboration, and empowerment when providing reproductive and mental health services to trauma survivors." },
  { id: 4008, category: 'chapter18', keywords: ['intimate partner violence IPV pregnancy'], question: "What are the effects of intimate partner violence during pregnancy?", response: "IPV during pregnancy increases risks of depression, PTSD, substance use, preterm birth, low birth weight, and poor prenatal care." },
  { id: 4009, category: 'chapter18', keywords: ['CycleMind trauma informed tracking'], question: "How can CycleMind support trauma survivors?", response: "CycleMind can implement trauma-informed design: optional sensitive questions, clear consent for tracking, trigger warnings, and easy opt-out for any reproductive or mental health logs." },
  { id: 4010, category: 'chapter18', keywords: ['Luna boundaries trauma reproductive health'], question: "What boundaries should Luna observe for trauma topics?", response: "Luna must state she is not a trauma therapist and cannot provide therapy or interpret trauma history. She can share general education from Chapter 18 and support safe tracking but must always redirect to qualified trauma-informed mental health professionals." },
  { id: 4011, category: 'chapter18', keywords: ['sexual trauma reproductive health'], question: "How does sexual trauma affect reproductive health?", response: "History of sexual trauma is associated with higher rates of gynecologic pain, sexual dysfunction, avoidance of prenatal care, and PTSD symptoms during pregnancy and delivery." },
  { id: 4012, category: 'chapter18', keywords: ['PTSD pregnancy childbirth'], question: "What is the impact of PTSD on pregnancy and childbirth?", response: "PTSD can lead to hypervigilance, avoidance of medical care, traumatic birth experiences, and increased risk of postpartum depression and bonding difficulties." },
  { id: 4013, category: 'chapter18', keywords: ['CycleMind trauma sensitive features'], question: "What trauma-sensitive features should CycleMind include?", response: "Trigger warnings before sensitive questions, easy skip/opt-out, clear privacy controls, and links to trauma-informed resources." },
  { id: 4014, category: 'chapter18', keywords: ['Luna response template Chapter 18'], question: "What template should Luna use for trauma questions?", response: "1. Clear disclaimer and trauma-informed language. 2. General educational summary. 3. Offer safe CycleMind tracking. 4. Strong redirect to trauma-informed clinician." },
  { id: 4015, category: 'chapter18', keywords: ['Chapter 18 authors'], question: "Who authored Chapter 18?", response: "Priya Gopalan, M.D., Elizabeth Albertini, M.D., Priyanka Amin, M.D., Maureen Curley, Ph.D., Jody Glance, M.D., Saira Kalia, M.D., and Neeta Shenai, M.D." },
  { id: 4016, category: 'chapter18', keywords: ['childhood adversity reproductive outcomes'], question: "What are the effects of childhood adversity on reproductive health?", response: "Adverse childhood experiences (ACEs) are linked to higher rates of unintended pregnancy, pregnancy complications, and perinatal mental health disorders." },
  { id: 4017, category: 'chapter18', keywords: ['CycleMind ACEs screening'], question: "Should CycleMind include ACEs screening?", response: "Optional, voluntary ACEs questions with clear trauma-informed language and immediate resource links if scores indicate high risk." },
  { id: 4018, category: 'chapter18', keywords: ['Luna disclaimer trauma'], question: "What disclaimer is required for Chapter 18 topics?", response: "Luna must state she is not a trauma specialist and cannot provide therapy. This is general educational information only." },
  { id: 4019, category: 'chapter18', keywords: ['birth trauma PTSD'], question: "What is birth trauma and its consequences?", response: "Traumatic birth experiences (emergency cesarean, loss of control, perceived threat) can lead to PTSD symptoms that affect future pregnancies and bonding." },
  { id: 4020, category: 'chapter18', keywords: ['CycleMind trauma informed language'], question: "How should CycleMind apply trauma-informed principles?", response: "Use empowering language, offer choice and control in all tracking features, provide content warnings, and prioritize user safety and privacy." },
  { id: 4021, category: 'chapter18', keywords: ['Luna safety netting trauma'], question: "What safety netting should Luna include?", response: "Luna should direct users experiencing distress from trauma reminders or safety concerns to trauma-informed mental health resources or their perinatal team." },
  { id: 4022, category: 'chapter18', keywords: ['integrated trauma reproductive care'], question: "What model of care is emphasized?", response: "Trauma-informed, integrated reproductive and mental health care is essential for survivors of abuse and violence." },
  { id: 4023, category: 'chapter18', keywords: ['CycleMind feature ideas Chapter 18'], question: "What CycleMind features are inspired by Chapter 18?", response: "Trauma-informed symptom tracker, optional ACEs screening, birth trauma log, and direct links to survivor support resources." },
  { id: 4024, category: 'chapter18', keywords: ['Luna educational content Chapter 18'], question: "How should Luna present Chapter 18 content?", response: "Luna should use validating, non-stigmatizing language that acknowledges the prevalence and impact of trauma while offering safe tracking options and professional referrals." },
  { id: 4025, category: 'chapter18', keywords: ['IPV screening reproductive psychiatry'], question: "Is IPV screening recommended?", response: "Yes. Routine, trauma-informed screening for intimate partner violence is recommended in reproductive psychiatry settings." },
  { id: 4026, category: 'chapter18', keywords: ['Luna response boundaries Chapter 18'], question: "What overarching boundaries apply to Luna for Chapter 18 content?", response: "Luna must never explore personal trauma history, provide counseling, or interpret symptoms as trauma-related. All responses remain general education and end with a clinician redirect." },
  { id: 4027, category: 'chapter18', keywords: ['Chapter 18 key takeaway for app'], question: "What is the primary takeaway from Chapter 18 for CycleMind?", response: "Trauma profoundly affects reproductive and mental health; CycleMind must be built with trauma-informed principles and clear pathways to professional support." },
  { id: 4028, category: 'chapter18', keywords: ['reproductive health trauma survivors'], question: "What unique needs do trauma survivors have in reproductive health?", response: "Trauma survivors may experience heightened anxiety during pelvic exams, labor, or breastfeeding and benefit from trauma-informed communication and control over procedures." },
  { id: 4029, category: 'chapter18', keywords: ['CycleMind privacy trauma'], question: "How does CycleMind protect privacy for trauma-related tracking?", response: "All sensitive logs are fully optional, encrypted, and user-controlled; no data is shared without explicit consent." },
  { id: 4030, category: 'chapter18', keywords: ['Luna crisis redirect trauma'], question: "What language should Luna use for trauma-related distress?", response: "Luna should use direct, compassionate language: 'If trauma reminders are causing significant distress or safety concerns, please reach out to a trauma-informed therapist or your perinatal team right away.'" },
  { id: 4031, category: 'chapter18', keywords: ['sexual trauma pregnancy'], question: "How does sexual trauma affect pregnancy?", response: "Sexual trauma history is associated with higher rates of hyperemesis, pelvic pain, dissociation during labor, and avoidance of prenatal care." },
  { id: 4032, category: 'chapter18', keywords: ['CycleMind trauma informed onboarding'], question: "Should CycleMind have trauma-informed onboarding?", response: "Yes — gentle onboarding that explains optional sensitive questions, offers opt-out, and provides resource links." },
  { id: 4033, category: 'chapter18', keywords: ['integrated trauma informed reproductive care'], question: "What is the core message of Chapter 18?", response: "Trauma-informed care should be standard in all reproductive health and psychiatric settings to improve outcomes for survivors." },
  { id: 4034, category: 'chapter18', keywords: ['Luna educational content trauma'], question: "How should Luna present trauma-related education?", response: "Luna should use validating language that normalizes the impact of trauma while offering general information and directing users to professional trauma-informed care." },
  { id: 4035, category: 'chapter18', keywords: ['Chapter 18 key takeaway for app'], question: "What is the primary takeaway from Chapter 18 for CycleMind development?", response: "CycleMind must be designed as a trauma-informed app with user choice, safety, and clear pathways to professional support at its core." },

  // === Chapter 19: Anxiety Disorders and Insomnia in the Perinatal Period (IDs 4036–4065) ===
  { id: 4036, category: 'chapter19', keywords: ['anxiety disorders insomnia perinatal overview'], question: "What does Chapter 19 of the Textbook of Women's Reproductive Mental Health cover?", response: "Chapter 19 reviews the epidemiology, diagnosis, and treatment of anxiety disorders (GAD, panic, social anxiety, PTSD, OCD) and insomnia in pregnancy and the postpartum period, with emphasis on safety of interventions and integrated care." },
  { id: 4037, category: 'chapter19', keywords: ['perinatal anxiety prevalence'], question: "What is the prevalence of perinatal anxiety?", response: "Anxiety disorders affect up to 15–20% of pregnant and postpartum women and are often comorbid with depression." },
  { id: 4038, category: 'chapter19', keywords: ['insomnia perinatal period'], question: "How common is insomnia in the perinatal period?", response: "Insomnia affects up to 75% of pregnant women and is a major risk factor for perinatal depression and anxiety; Chapter 19 links it to hormonal changes and physical discomfort." },
  { id: 4039, category: 'chapter19', keywords: ['CycleMind anxiety insomnia tracker'], question: "How can CycleMind support anxiety and insomnia tracking?", response: "CycleMind can include pregnancy/postpartum-specific anxiety screeners, insomnia logs, and sleep–mood correlation charts to help users monitor these common issues." },
  { id: 4040, category: 'chapter19', keywords: ['Luna boundaries anxiety insomnia'], question: "What boundaries should Luna observe for anxiety and insomnia topics?", response: "Luna must state she is not a clinician and cannot diagnose or treat anxiety disorders or insomnia. She can share general education from Chapter 19 and support symptom tracking but must always redirect to the user's perinatal psychiatrist or OB/GYN." },
  { id: 4041, category: 'chapter19', keywords: ['CBT-I perinatal insomnia'], question: "What is the first-line treatment for perinatal insomnia?", response: "Cognitive Behavioral Therapy for Insomnia (CBT-I) is the first-line treatment and is safe and effective during pregnancy and postpartum." },
  { id: 4042, category: 'chapter19', keywords: ['SSRIs perinatal anxiety'], question: "What is the role of SSRIs for perinatal anxiety?", response: "SSRIs are first-line pharmacologic treatment for moderate-to-severe perinatal anxiety disorders after risk-benefit discussion." },
  { id: 4043, category: 'chapter19', keywords: ['CycleMind sleep hygiene pregnancy'], question: "What sleep hygiene features should CycleMind include?", response: "Pregnancy-tailored sleep hygiene tips, CBT-I-based prompts, and sleep diary integration with mood tracking." },
  { id: 4044, category: 'chapter19', keywords: ['Luna response template Chapter 19'], question: "What template should Luna use for anxiety and insomnia questions?", response: "1. Clear disclaimer. 2. General educational summary from Chapter 19. 3. Offer CycleMind anxiety/insomnia tracking. 4. Strong redirect to perinatal mental health provider." },
  { id: 4045, category: 'chapter19', keywords: ['Chapter 19 authors'], question: "Who authored Chapter 19?", response: "Lucy A. Hutner, M.D., Joanna V. MacLean, M.D., Gioia M. Guerrieri, D.O., Melisa Olgun, B.A., and Julia Frew, M.D." },
  { id: 4046, category: 'chapter19', keywords: ['GAD generalized anxiety disorder perinatal'], question: "How is generalized anxiety disorder managed perinatally?", response: "CBT is first-line; SSRIs are used for moderate-to-severe GAD when non-pharmacologic approaches are insufficient." },
  { id: 4047, category: 'chapter19', keywords: ['panic disorder pregnancy'], question: "What considerations apply to panic disorder in pregnancy?", response: "Panic attacks can mimic serious medical conditions; CBT and SSRIs are effective, with careful monitoring for safety." },
  { id: 4048, category: 'chapter19', keywords: ['CycleMind anxiety screening'], question: "Should CycleMind include anxiety screening?", response: "Yes — optional validated anxiety screeners (e.g., GAD-7) at key perinatal timepoints with clear clinician referral for elevated scores." },
  { id: 4049, category: 'chapter19', keywords: ['Luna disclaimer anxiety insomnia'], question: "What disclaimer is required for Chapter 19 topics?", response: "Luna must state she is not a clinician and cannot diagnose or treat anxiety disorders or insomnia. This is general educational information only." },
  { id: 4050, category: 'chapter19', keywords: ['OCD perinatal period'], question: "How is OCD addressed in the perinatal period?", response: "Perinatal OCD often involves harm obsessions related to the infant; CBT with exposure/response prevention is first-line, with SSRIs as needed." },
  { id: 4051, category: 'chapter19', keywords: ['CycleMind feature ideas Chapter 19'], question: "What CycleMind features are inspired by Chapter 19?", response: "Anxiety and insomnia trackers, CBT-I–based sleep hygiene prompts, perinatal-specific anxiety screeners, and mood–sleep correlation charts." },
  { id: 4052, category: 'chapter19', keywords: ['PTSD perinatal anxiety'], question: "How does PTSD intersect with perinatal anxiety?", response: "PTSD symptoms often worsen or emerge in the perinatal period; trauma-focused CBT and SSRIs are effective treatments." },
  { id: 4053, category: 'chapter19', keywords: ['Luna safety netting anxiety insomnia'], question: "What safety netting should Luna include?", response: "Luna should advise users with severe anxiety, panic attacks, insomnia causing functional impairment, or suicidal thoughts to contact their perinatal psychiatrist or OB/GYN promptly." },
  { id: 4054, category: 'chapter19', keywords: ['integrated care anxiety insomnia'], question: "What model of care is emphasized?", response: "Collaborative care between reproductive psychiatrists, obstetricians, and sleep specialists optimizes outcomes for perinatal anxiety and insomnia." },
  { id: 4055, category: 'chapter19', keywords: ['Luna educational content Chapter 19'], question: "How should Luna present Chapter 19 content?", response: "Luna should deliver practical, destigmatizing education on perinatal anxiety and insomnia while offering CycleMind tracking tools and professional referrals." },
  { id: 4056, category: 'chapter19', keywords: ['Chapter 19 key takeaway for app'], question: "What is the primary takeaway from Chapter 19 for CycleMind?", response: "Anxiety disorders and insomnia are highly prevalent and treatable in the perinatal period; CycleMind should support early detection and tracking while ensuring users access professional care." },
  { id: 4057, category: 'chapter19', keywords: ['Luna response boundaries Chapter 19'], question: "What overarching boundaries apply to Luna for Chapter 19 content?", response: "Luna must never diagnose anxiety disorders or insomnia, interpret screening scores, or recommend treatments. All responses remain general education and end with a clinician redirect." },
  { id: 4058, category: 'chapter19', keywords: ['sleep hygiene perinatal'], question: "What sleep hygiene recommendations are given?", response: "Consistent sleep schedule, dark/cool environment, limit caffeine, and avoid screens before bed are emphasized, with pregnancy-specific adaptations." },
  { id: 4059, category: 'chapter19', keywords: ['CycleMind CBT-I elements'], question: "Should CycleMind include CBT-I elements?", response: "Optional guided CBT-I prompts (stimulus control, sleep restriction education) can be included as adjunctive wellness tools with clear disclaimers." },
  { id: 4060, category: 'chapter19', keywords: ['perinatal anxiety comorbidities'], question: "What comorbidities are common with perinatal anxiety?", response: "Depression, OCD, PTSD, and insomnia frequently co-occur and require comprehensive assessment." },
  { id: 4061, category: 'chapter19', keywords: ['CycleMind data export anxiety insomnia'], question: "How can CycleMind data support perinatal anxiety/insomnia care?", response: "Users can export anxiety scores, sleep logs, and symptom timelines to share with their perinatal mental health team." },
  { id: 4062, category: 'chapter19', keywords: ['Luna crisis redirect anxiety'], question: "What language should Luna use for severe anxiety or insomnia?", response: "Luna should use direct, compassionate language: 'Severe anxiety or insomnia can worsen quickly. Please contact your perinatal psychiatrist or OB/GYN right away.'" },
  { id: 4063, category: 'chapter19', keywords: ['non-pharmacologic insomnia pregnancy'], question: "What non-pharmacologic options are recommended for insomnia?", response: "CBT-I, sleep hygiene, and relaxation techniques are first-line and safe throughout pregnancy and postpartum." },
  { id: 4064, category: 'chapter19', keywords: ['Luna educational content Chapter 19'], question: "How should Luna present Chapter 19 content?", response: "Luna should deliver practical, empowering education on managing perinatal anxiety and insomnia while always encouraging professional evaluation." },
  { id: 4065, category: 'chapter19', keywords: ['Chapter 19 key takeaway for app'], question: "What is the primary takeaway from Chapter 19 for CycleMind development?", response: "Anxiety and insomnia are common, interconnected, and treatable in the perinatal period; CycleMind should provide practical tracking and education tools while maintaining strict clinical boundaries." },

  // === Chapter 20: Obsessive-Compulsive Disorder in the Perinatal Period (IDs 4066–4095) ===
  { id: 4066, category: 'chapter20', keywords: ['OCD perinatal overview'], question: "What does Chapter 20 of the Textbook of Women's Reproductive Mental Health cover?", response: "Chapter 20 reviews obsessive-compulsive disorder in the perinatal period, including epidemiology, unique presentations (harm obsessions, contamination fears), pathophysiology, screening, diagnosis, and evidence-based treatments." },
  { id: 4067, category: 'chapter20', keywords: ['perinatal OCD prevalence'], question: "What is the prevalence of perinatal OCD?", response: "OCD affects up to 4% of pregnant and postpartum women, with new-onset or worsening symptoms frequently occurring in the perinatal period." },
  { id: 4068, category: 'chapter20', keywords: ['harm obsessions perinatal OCD'], question: "What are harm obsessions in perinatal OCD?", response: "Harm obsessions (fear of harming the infant intentionally or accidentally) are common in perinatal OCD and are ego-dystonic; they do not indicate true risk but cause significant distress." },
  { id: 4069, category: 'chapter20', keywords: ['CycleMind OCD tracking'], question: "How can CycleMind support users with perinatal OCD?", response: "CycleMind can include optional, private OCD symptom trackers (obsessions, compulsions, harm thoughts) with reproductive-phase correlation and clinician export." },
  { id: 4070, category: 'chapter20', keywords: ['Luna boundaries OCD'], question: "What boundaries should Luna observe for OCD topics?", response: "Luna must state she is not a psychiatrist and cannot diagnose or treat OCD. She can share general education from Chapter 20 and support symptom tracking but must always redirect to a qualified perinatal psychiatrist." },
  { id: 4071, category: 'chapter20', keywords: ['CBT ERP perinatal OCD'], question: "What is the first-line treatment for perinatal OCD?", response: "Cognitive-behavioral therapy with exposure and response prevention (CBT/ERP) is first-line and highly effective for perinatal OCD." },
  { id: 4072, category: 'chapter20', keywords: ['SSRIs perinatal OCD'], question: "What is the role of SSRIs in perinatal OCD?", response: "SSRIs (especially sertraline or fluoxetine) are first-line pharmacologic treatment when CBT/ERP is insufficient or symptoms are severe." },
  { id: 4073, category: 'chapter20', keywords: ['CycleMind harm obsession log'], question: "Should CycleMind include harm obsession tracking?", response: "Optional, private, non-judgmental logging of intrusive thoughts with clear disclaimers and immediate clinician referral for high distress or functional impairment." },
  { id: 4074, category: 'chapter20', keywords: ['Luna response template Chapter 20'], question: "What template should Luna use for OCD questions?", response: "1. Clear disclaimer. 2. General educational summary from Chapter 20. 3. Offer CycleMind OCD tracking. 4. Strong redirect to perinatal psychiatrist." },
  { id: 4075, category: 'chapter20', keywords: ['Chapter 20 authors'], question: "Who authored Chapter 20?", response: "Neha S. Hudepohl, M.D., Nicole Leistikow, M.D., Mimi Levine, M.D., and Lauren M. Osborne, M.D." },
  { id: 4076, category: 'chapter20', keywords: ['contamination obsessions perinatal'], question: "What contamination obsessions are common in perinatal OCD?", response: "Fears of contaminating the infant through cleaning rituals or avoidance of medical care are frequent and can interfere with bonding and infant care." },
  { id: 4077, category: 'chapter20', keywords: ['CycleMind OCD education'], question: "How should CycleMind incorporate Chapter 20 education?", response: "Create destigmatizing cards explaining that intrusive thoughts are common in perinatal OCD, are not predictive of action, and are treatable." },
  { id: 4078, category: 'chapter20', keywords: ['Luna disclaimer OCD'], question: "What disclaimer is required for Chapter 20 topics?", response: "Luna must state she is not a clinician and cannot diagnose or treat OCD. This is general educational information only." },
  { id: 4079, category: 'chapter20', keywords: ['postpartum OCD vs postpartum psychosis'], question: "How does Chapter 20 differentiate OCD from postpartum psychosis?", response: "Perinatal OCD involves ego-dystonic obsessions without loss of reality testing; postpartum psychosis involves delusions and hallucinations with impaired insight." },
  { id: 4080, category: 'chapter20', keywords: ['CycleMind feature ideas Chapter 20'], question: "What CycleMind features are inspired by Chapter 20?", response: "Perinatal OCD symptom tracker, harm-thought log (private), CBT/ERP education cards, and clinician-export functionality." },
  { id: 4081, category: 'chapter20', keywords: ['Luna safety netting OCD'], question: "What safety netting should Luna include?", response: "Luna should advise users with high distress from obsessions, compulsive behaviors interfering with infant care, or suicidal thoughts to contact their perinatal psychiatrist immediately." },
  { id: 4082, category: 'chapter20', keywords: ['integrated care perinatal OCD'], question: "What model of care is emphasized?", response: "Collaborative care between reproductive psychiatrists and obstetricians optimizes outcomes for perinatal OCD." },
  { id: 4083, category: 'chapter20', keywords: ['Luna educational content Chapter 20'], question: "How should Luna present Chapter 20 content?", response: "Luna should use validating, normalizing language to reduce shame around intrusive thoughts while directing users to professional treatment." },
  { id: 4084, category: 'chapter20', keywords: ['Chapter 20 key takeaway for app'], question: "What is the primary takeaway from Chapter 20 for CycleMind?", response: "Perinatal OCD is common, treatable, and often involves harm obsessions that are ego-dystonic; CycleMind should offer respectful tracking while ensuring users seek expert care." },
  { id: 4085, category: 'chapter20', keywords: ['Luna response boundaries Chapter 20'], question: "What overarching boundaries apply to Luna for Chapter 20 content?", response: "Luna must never diagnose OCD, normalize or interpret intrusive thoughts as safe, or recommend exposure therapy. All responses remain general education and end with a clinician redirect." },
  { id: 4086, category: 'chapter20', keywords: ['perinatal OCD screening'], question: "What screening is recommended for perinatal OCD?", response: "The Yale-Brown Obsessive Compulsive Scale (Y-BOCS) or perinatal-specific questions can be used alongside routine depression/anxiety screening." },
  { id: 4087, category: 'chapter20', keywords: ['CycleMind harm thought education'], question: "How should CycleMind educate about harm obsessions?", response: "Include clear, reassuring cards explaining that intrusive harm thoughts are common in perinatal OCD, are not predictive of action, and respond well to treatment." },
  { id: 4088, category: 'chapter20', keywords: ['CBT ERP perinatal OCD evidence'], question: "What is the evidence for CBT/ERP in perinatal OCD?", response: "CBT with exposure and response prevention is the most effective treatment for perinatal OCD and is safe throughout pregnancy and postpartum." },
  { id: 4089, category: 'chapter20', keywords: ['CycleMind data export OCD'], question: "How can CycleMind data support OCD care?", response: "Users can export obsession/compulsion logs and Y-BOCS-style ratings to share with their perinatal psychiatrist for treatment planning." },
  { id: 4090, category: 'chapter20', keywords: ['Luna crisis redirect OCD'], question: "What language should Luna use for severe OCD distress?", response: "Luna should use direct, compassionate language: 'If obsessions are causing severe distress or interfering with caring for yourself or your baby, please contact your perinatal psychiatrist right away.'" },
  { id: 4091, category: 'chapter20', keywords: ['postpartum OCD onset'], question: "When does perinatal OCD commonly onset?", response: "New-onset or worsening OCD frequently occurs in the third trimester or early postpartum period." },
  { id: 4092, category: 'chapter20', keywords: ['Luna educational content Chapter 20'], question: "How should Luna present Chapter 20 content?", response: "Luna should emphasize that intrusive thoughts are common, ego-dystonic, and treatable while directing users to professional care." },
  { id: 4093, category: 'chapter20', keywords: ['integrated perinatal OCD care'], question: "What is the core message of Chapter 20?", response: "Perinatal OCD requires prompt recognition and integrated psychiatric-obstetric care using CBT/ERP and SSRIs when needed." },
  { id: 4094, category: 'chapter20', keywords: ['CycleMind OCD module'], question: "What should the CycleMind OCD module include?", response: "Private symptom logging, education on common perinatal presentations, and easy clinician export with strong disclaimers." },
  { id: 4095, category: 'chapter20', keywords: ['Chapter 20 key takeaway for app'], question: "What is the primary takeaway from Chapter 20 for CycleMind development?", response: "Perinatal OCD is highly treatable; CycleMind should provide respectful, private tracking tools and education while ensuring users connect with expert clinical care." },
];